  console.log("Building @deus/cli...\n");

  // Step 1: Bundle CLI TypeScript
  console.log("1. Bundling CLI...");
  await build({
    entryPoints: [join(cliDir, "src/cli.ts")],
    bundle: true,
    platform: "node",
    target: "node20",
    format: "esm",
