/**
 * Headless serve mode — starts agent-server, backend, and serves the web UI.
 *
 * Process orchestration mirrors scripts/dev.sh but in production mode:
 * 1. Start agent-server → capture LISTEN_URL from stdout
 * 2. Start backend with AGENT_SERVER_URL → capture [BACKEND_PORT] from stdout
 * 3. Serve static frontend files, proxying /api and /ws to backend
 *
 * In "bundled" mode (npm install), pre-built bundles are loaded from ./bundles/.
 * In "dev" mode (running from monorepo), builds are found in their source locations.
 */

import { spawn, type ChildProcess } from "node:child_process";
import { createServer } from "node:http";
import { readFileSync, existsSync, statSync } from "node:fs";
import { join, resolve, extname, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { platform, homedir, arch } from "node:os";
import { mkdirSync } from "node:fs";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// MIME types for static file serving
const MIME_TYPES: Record<string, string> = {
  ".html": "text/html",
  ".js": "application/javascript",
  ".mjs": "application/javascript",
  ".css": "text/css",
  ".json": "application/json",
  ".png": "image/png",
  ".jpg": "image/jpeg",
  ".jpeg": "image/jpeg",
  ".gif": "image/gif",
  ".svg": "image/svg+xml",
  ".ico": "image/x-icon",
  ".woff": "font/woff",
  ".woff2": "font/woff2",
  ".ttf": "font/ttf",
  ".map": "application/json",
};

export interface ServeOptions {
  port: number;
  host: string;
  open: boolean;
  dataDir?: string;
}

interface ProcessInfo {
  process: ChildProcess;
  name: string;
}

export async function serve(options: ServeOptions): Promise<void> {
  const { port, host, open, dataDir } = options;

  console.log("");
  console.log("  Deus IDE — Starting headless server");
  console.log("  ====================================");
  console.log("");

  // Resolve paths to bundles
  const paths = resolveBundlePaths();
  if (!paths) {
    console.error("  Error: Could not find Deus bundles.");
    console.error("  Run 'bun run build:cli' from the monorepo root first.");
    process.exit(1);
  }

  // Resolve data directory for database
  const dbPath = resolveDataDir(dataDir);
  console.log(`  Database: ${dbPath}`);

  // Track child processes for cleanup
  const children: ProcessInfo[] = [];

  // Graceful shutdown handler
  function shutdown() {
    console.log("\n  Shutting down...");
    for (const child of children) {
      if (!child.process.killed) {
        child.process.kill("SIGTERM");
      }
    }
    process.exit(0);
  }
  process.on("SIGINT", shutdown);
  process.on("SIGTERM", shutdown);

  // Step 1: Start agent-server
  console.log("  Starting agent-server...");
  const agentServerUrl = await startProcess({
    name: "agent-server",
    command: process.execPath,
    args: [paths.agentServer],
    env: { DATABASE_PATH: dbPath },
    waitFor: /LISTEN_URL=(.+)/,
    children,
  });

  if (!agentServerUrl) {
    console.error("  Error: Agent-server failed to start");
    shutdown();
    return;
  }
  console.log(`  Agent-server: ${agentServerUrl}`);

  // Step 2: Start backend
  console.log("  Starting backend...");
  const backendPort = await startProcess({
    name: "backend",
    command: process.execPath,
    args: [paths.backend],
    env: {
      AGENT_SERVER_URL: agentServerUrl,
      DATABASE_PATH: dbPath,
      PORT: "0", // Dynamic port
    },
    waitFor: /\[BACKEND_PORT\](\d+)/,
    children,
  });

  if (!backendPort) {
    console.error("  Error: Backend failed to start");
    shutdown();
    return;
  }
  console.log(`  Backend API: http://localhost:${backendPort}`);

  // Step 3: Start web server (static files + reverse proxy to backend)
  const webServer = createWebServer(
    parseInt(backendPort, 10),
    paths.frontend
  );

  webServer.listen(port, host, () => {
    console.log("");
    console.log(`  Deus is running at http://${host}:${port}`);
    console.log("");
    console.log("  Press Ctrl+C to stop");
    console.log("");

    if (open) {
      openBrowser(`http://${host}:${port}`);
    }
  });

  // Keep the process alive
  await new Promise(() => {});
}

/**
 * Resolve paths to the pre-built bundles.
 * Checks two locations:
 * 1. Bundled mode (npm package): ./bundles/
 * 2. Dev mode (monorepo): relative paths to build outputs
 */
function resolveBundlePaths(): {
  agentServer: string;
  backend: string;
  frontend: string;
} | null {
  // CLI package root (packages/cli/)
  const cliRoot = resolve(__dirname, "..");

  // Option 1: Bundled mode — bundles/ directory in the CLI package
  const bundledDir = join(cliRoot, "bundles");
  if (existsSync(join(bundledDir, "agent-server.bundled.cjs"))) {
    return {
      agentServer: join(bundledDir, "agent-server.bundled.cjs"),
      backend: join(bundledDir, "server.bundled.cjs"),
      frontend: join(bundledDir, "web"),
    };
  }

  // Option 2: Dev mode — find bundles in monorepo build outputs
  const monorepoRoot = resolve(cliRoot, "../..");
  const agentServer = join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs");
  const backend = join(monorepoRoot, "apps/backend/dist/server.bundled.cjs");
  const frontend = join(monorepoRoot, "dist/web");

  if (existsSync(agentServer) && existsSync(backend)) {
    // Frontend might not be built yet, but backend + agent-server are required
    return { agentServer, backend, frontend };
  }

  return null;
}

/**
 * Resolve the database file path, creating the directory if needed.
 */
function resolveDataDir(customDir?: string): string {
  if (customDir) {
    mkdirSync(customDir, { recursive: true });
    return join(customDir, "deus.db");
  }

  // Platform-appropriate default data directory
  const os = platform();
  let dir: string;

  if (os === "darwin") {
    dir = join(homedir(), "Library/Application Support/com.deus.app");
  } else if (os === "win32") {
    dir = join(process.env.APPDATA || join(homedir(), "AppData/Roaming"), "com.deus.app");
  } else {
    // Linux / other: XDG_DATA_HOME or ~/.local/share
    dir = join(process.env.XDG_DATA_HOME || join(homedir(), ".local/share"), "deus");
  }

  mkdirSync(dir, { recursive: true });
  return join(dir, "deus.db");
}

/**
 * Start a child process and wait for a pattern in stdout.
 * Returns the first capture group from the pattern match.
 */
async function startProcess(opts: {
  name: string;
  command: string;
  args: string[];
  env: Record<string, string>;
  waitFor: RegExp;
  children: ProcessInfo[];
  timeoutMs?: number;
}): Promise<string | null> {
  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;

  return new Promise((resolve) => {
    const child = spawn(command, args, {
      stdio: ["ignore", "pipe", "pipe"],
      env: { ...process.env, ...env },
    });

    children.push({ process: child, name });

    let buffer = "";
    let resolved = false;

    const timeout = setTimeout(() => {
      if (!resolved) {
        resolved = true;
        console.error(`  Warning: ${name} did not produce expected output within ${timeoutMs}ms`);
        resolve(null);
      }
    }, timeoutMs);

    child.stdout?.on("data", (data: Buffer) => {
      const text = data.toString();
      buffer += text;

      // Log output with prefix
      for (const line of text.split("\n")) {
        const trimmed = line.trim();
        if (trimmed && !resolved) {
          // Don't spam — only log important lines
        }
      }

      // Check for the pattern
      const match = buffer.match(waitFor);
      if (match && !resolved) {
        resolved = true;
        clearTimeout(timeout);
        resolve(match[1]);
      }
    });

    child.stderr?.on("data", (data: Buffer) => {
      for (const line of data.toString().split("\n")) {
        if (line.trim()) {
          console.error(`  [${name}:err] ${line.trim()}`);
        }
      }
    });

    child.on("exit", (code, signal) => {
      if (!resolved) {
        resolved = true;
        clearTimeout(timeout);
        console.error(`  ${name} exited unexpectedly (code=${code}, signal=${signal})`);
        resolve(null);
      }
    });
  });
}

/**
 * Create an HTTP server that:
 * - Proxies /api/* and /ws to the backend
 * - Serves static frontend files for everything else
 * - Injects the backend port into the frontend config
 */
function createWebServer(backendPort: number, frontendDir: string) {
  const hasFrontend = existsSync(frontendDir) && existsSync(join(frontendDir, "index.html"));

  const server = createServer(async (req, res) => {
    const url = req.url || "/";

    // Proxy API requests to backend
    if (url.startsWith("/api/") || url.startsWith("/api")) {
      return proxyRequest(req, res, backendPort);
    }

    // Serve __backend_port for frontend config discovery
    if (url === "/__backend_port") {
      res.writeHead(200, {
        "Content-Type": "application/json",
        "Access-Control-Allow-Origin": "*",
      });
      res.end(JSON.stringify({ port: backendPort }));
      return;
    }

    // Serve static frontend files
    if (hasFrontend) {
      serveStaticFile(req, res, frontendDir);
    } else {
      // No frontend build — show a simple status page
      res.writeHead(200, { "Content-Type": "text/html" });
      res.end(`
        <!DOCTYPE html>
        <html>
        <head><title>Deus IDE</title></head>
        <body style="font-family: system-ui; padding: 2rem; background: #0a0a0a; color: #e5e5e5;">
          <h1>Deus IDE Server</h1>
          <p>Backend API running on port ${backendPort}</p>
          <p>WebSocket: ws://localhost:${backendPort}/ws</p>
          <p style="color: #a3a3a3;">Frontend not built. Run <code>bun run build:web</code> to build the UI.</p>
        </body>
        </html>
      `);
    }
  });

  // Handle WebSocket upgrade — proxy to backend
  server.on("upgrade", (req, socket, head) => {
    const { request } = require("node:http");
    const proxyReq = request({
      hostname: "localhost",
      port: backendPort,
      path: req.url,
      method: req.method,
      headers: req.headers,
    });

    proxyReq.on("upgrade", (_proxyRes: any, proxySocket: any, proxyHead: any) => {
      socket.write(
        "HTTP/1.1 101 Switching Protocols\r\n" +
          Object.entries(_proxyRes.headers)
            .map(([k, v]: [string, any]) => `${k}: ${v}`)
            .join("\r\n") +
          "\r\n\r\n"
      );
      if (proxyHead.length > 0) socket.write(proxyHead);

      proxySocket.pipe(socket);
      socket.pipe(proxySocket);
    });

    proxyReq.on("error", () => {
      socket.end();
    });

    proxyReq.end();
  });

  return server;
}

/**
 * Proxy an HTTP request to the backend.
 */
function proxyRequest(
  req: import("node:http").IncomingMessage,
  res: import("node:http").ServerResponse,
  backendPort: number
) {
  const { request } = require("node:http") as typeof import("node:http");

  const proxyReq = request(
    {
      hostname: "localhost",
      port: backendPort,
      path: req.url,
      method: req.method,
      headers: {
        ...req.headers,
        host: `localhost:${backendPort}`,
      },
    },
    (proxyRes) => {
      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
      proxyRes.pipe(res);
    }
  );

  proxyReq.on("error", () => {
    res.writeHead(502, { "Content-Type": "application/json" });
    res.end(JSON.stringify({ error: "Backend unavailable" }));
  });

  req.pipe(proxyReq);
}

/**
 * Serve a static file from the frontend build directory.
 * Falls back to index.html for SPA client-side routing.
 */
function serveStaticFile(
  req: import("node:http").IncomingMessage,
  res: import("node:http").ServerResponse,
  frontendDir: string
) {
  let pathname = (req.url || "/").split("?")[0];
  if (pathname === "/") pathname = "/index.html";

  let filePath = join(frontendDir, pathname);

  // SPA fallback: if file doesn't exist, serve index.html
  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
    filePath = join(frontendDir, "index.html");
  }

  if (!existsSync(filePath)) {
    res.writeHead(404);
    res.end("Not found");
    return;
  }

  const ext = extname(filePath);
  const contentType = MIME_TYPES[ext] || "application/octet-stream";

  try {
    const content = readFileSync(filePath);
    res.writeHead(200, {
      "Content-Type": contentType,
      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
    });
    res.end(content);
  } catch {
    res.writeHead(500);
    res.end("Internal server error");
  }
}

/**
 * Open a URL in the default browser.
 */
function openBrowser(url: string) {
  const os = platform();
  const cmd = os === "darwin" ? "open" : os === "win32" ? "start" : "xdg-open";
  spawn(cmd, [url], { detached: true, stdio: "ignore" }).unref();
}

