/**
 * Resolve the Node.js binary for spawning child processes.
 *
 * In monorepo dev mode, native modules are compiled against Electron's Node ABI
 * (via `electron-builder install-app-deps` in postinstall). Using system Node
 * causes ERR_DLOPEN_FAILED. Detect and use Electron's embedded Node binary.
 *
 * When installed as an npm package, native modules are compiled for system Node.
 */
function resolveNodeBinary(): string {
  // If ELECTRON_RUN_AS_NODE is already set, we're being run via Electron's node
  if (process.env.ELECTRON_RUN_AS_NODE === "1") {
    return process.execPath;
  }

  // Check if we're in a monorepo with electron installed
  try {
    const electronPath = execSync(
      'node -e "try { console.log(require(\'electron\')) } catch { process.exit(1) }"',
      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
    ).trim();

    if (electronPath && existsSync(electronPath)) {
      // Test if system Node can load better-sqlite3
      try {
        execSync('node -e "require(\'better-sqlite3\')"', {
          timeout: 5000,
          stdio: ["pipe", "pipe", "pipe"],
        });
        // System Node works fine — no need for Electron's node
        return process.execPath;
      } catch {
        // System Node can't load native modules — use Electron's node
        return electronPath;
      }
    }
  } catch {
    // Electron not available — use system node
  }

  return process.execPath;
}

