        "HTTP/1.1 101 Switching Protocols\r\n" +
          Object.entries(_proxyRes.headers)
            .map(([k, v]: [string, any]) => `${k}: ${v}`)
            .join("\r\n") +
          "\r\n\r\n"
      );
      if (proxyHead.length > 0) socket.write(proxyHead);

      proxySocket.pipe(socket);
      socket.pipe(proxySocket);
    });

    proxyReq.on("error", () => {
      socket.end();
    });

    proxyReq.end();
  });

  return server;
}

/**
 * Proxy an HTTP request to the backend.
 */
function proxyRequest(
  req: import("node:http").IncomingMessage,
  res: import("node:http").ServerResponse,
  backendPort: number
) {
  const { request } = require("node:http") as typeof import("node:http");

  const proxyReq = request(
    {
      hostname: "localhost",
      port: backendPort,
      path: req.url,
      method: req.method,
      headers: {
        ...req.headers,
        host: `localhost:${backendPort}`,
      },
    },
    (proxyRes) => {
      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
      proxyRes.pipe(res);
    }
  );

  proxyReq.on("error", () => {
    res.writeHead(502, { "Content-Type": "application/json" });
    res.end(JSON.stringify({ error: "Backend unavailable" }));
  });

  req.pipe(proxyReq);
}

/**
 * Serve a static file from the frontend build directory.
 * Falls back to index.html for SPA client-side routing.
 */
function serveStaticFile(
  req: import("node:http").IncomingMessage,
  res: import("node:http").ServerResponse,
  frontendDir: string
) {
  let pathname = (req.url || "/").split("?")[0];
  if (pathname === "/") pathname = "/index.html";

  let filePath = join(frontendDir, pathname);

  // SPA fallback: if file doesn't exist, serve index.html
  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
    filePath = join(frontendDir, "index.html");
  }

  if (!existsSync(filePath)) {
    res.writeHead(404);
    res.end("Not found");
    return;
  }

  const ext = extname(filePath);
  const contentType = MIME_TYPES[ext] || "application/octet-stream";

  try {
    const content = readFileSync(filePath);
    res.writeHead(200, {
      "Content-Type": contentType,
      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
    });
    res.end(content);
  } catch {
    res.writeHead(500);
    res.end("Internal server error");
  }
}

/**
 * Open a URL in the default browser.
 */
function openBrowser(url: string) {
  const os = platform();
  const cmd = os === "darwin" ? "open" : os === "win32" ? "start" : "xdg-open";
  spawn(cmd, [url], { detached: true, stdio: "ignore" }).unref();
}

