 30→              res.setHeader("Access-Control-Allow-Origin", "*");
 31→              res.end(JSON.stringify({ port: parseInt(port, 10) }));
 32→              return;
 33→            }
 34→          } catch {
 35→            // Port file not readable — fall through to 503
 36→          }
 37→          res.statusCode = 503;
 38→          res.end(JSON.stringify({ error: "Backend not started yet" }));
 39→          return;
 40→        }
 41→        next();
 42→      });
 43→    },
 44→  };
 45→}
