  1→/**
  2→ * Electron Main Process — Thin Shell
  3→ *
  4→ * Responsibilities:
  5→ * - Window lifecycle (create, show, close)
  6→ * - Backend child process management
  7→ * - IPC handler registration
  8→ * - Auto-updater setup
  9→ * - Shell environment sync (macOS PATH fix)
 10→ *
 11→ * Business logic stays in the Node.js backend and agent-server — the main process
 12→ * is purely a desktop shell that spawns them and bridges native OS features.
 13→ */
 14→
 15→import { app, BrowserWindow, ipcMain, shell } from "electron";
 16→import { join } from "path";
 17→import { is } from "@electron-toolkit/utils";
 18→import { spawnBackend, stopBackend, CDP_PORT } from "./backend-process";
 19→// Agent-server is spawned by the backend process (via AGENT_SERVER_BUNDLE_PATH env var)
 20→import { registerNativeHandlers } from "./native-handlers";
 21→import { registerBrowserViewHandlers, destroyAllBrowserViews } from "./browser-views";
 22→// PTY, file watching, and browser server are now handled by the backend
 23→// via WebSocket commands — no Electron IPC needed for these.
 24→import { setupAutoUpdater } from "./auto-updater";
 25→import { syncShellEnvironment } from "./shell-env";
 26→import { setupAppMenu } from "./app-menu";
 27→import { setupTray, destroyTray } from "./tray";
 28→
 29→// ---------------------------------------------------------------------------
 30→// Single Instance Lock
 31→// ---------------------------------------------------------------------------
 32→
 33→if (!app.requestSingleInstanceLock()) {
 34→  app.quit();
 35→  process.exit(0);
 36→}
 37→
 38→// Enable Chrome DevTools Protocol so agent-browser can connect to IDE browser views
 39→// via CDP instead of spawning a separate Chrome process. Listens on 127.0.0.1 only.
 40→// Agent tools use `agent-browser --cdp <port>` to interact with the same browser
 41→// the user sees — shared cookies, real-time visibility of agent actions.
 42→app.commandLine.appendSwitch("remote-debugging-port", CDP_PORT);
 43→app.commandLine.appendSwitch("remote-debugging-address", "127.0.0.1");
 44→
 45→let mainWindow: BrowserWindow | null = null;
 46→
 47→// ---------------------------------------------------------------------------
 48→// Window Creation
 49→// ---------------------------------------------------------------------------
 50→
 51→async function createWindow(): Promise<void> {
 52→  mainWindow = new BrowserWindow({
 53→    width: 1400,
 54→    height: 900,
 55→    minWidth: 800,
 56→    minHeight: 600,
 57→    show: false,
 58→    titleBarStyle: process.platform === "darwin" ? "hiddenInset" : "default",
 59→    trafficLightPosition: { x: 16, y: 18 },
 60→    backgroundColor: "#0e0e10",
 61→    // Vibrancy is set dynamically via IPC after onboarding completes.
 62→    // No transparent:true — the CSS overlay handles the dark onboarding canvas,
 63→    // and vibrancy works without native transparency.
 64→    ...(process.platform === "linux"
 65→      ? { icon: join(__dirname, "../../resources/icons/icon.png") }
 66→      : {}),
 67→    webPreferences: {
 68→      preload: join(__dirname, "../preload/index.mjs"),
 69→      contextIsolation: true,
 70→      nodeIntegration: false,
 71→      sandbox: false, // ESM preload requires sandbox: false (package.json "type": "module")
 72→    },
 73→  });
 74→
 75→  // Show window once renderer is ready (avoids white flash)
 76→  mainWindow.on("ready-to-show", () => {
 77→    // Window starts hidden — the renderer calls show_main_window after
 78→    // settings/onboarding state is determined.
 79→    // Safety net: force-show after 3s if the renderer hasn't called show_main_window.
 80→    setTimeout(() => {
 81→      if (mainWindow && !mainWindow.isDestroyed() && !mainWindow.isVisible()) {
 82→        console.log("[main] Safety net: force-showing window after 3s timeout");
 83→        mainWindow.show();
 84→      }
 85→    }, 3000);
 86→  });
 87→
 88→  // Open DevTools in development
 89→  if (is.dev) {
 90→    mainWindow.webContents.openDevTools({ mode: "detach" });
 91→  }
 92→
 93→  // Forward renderer console to main process stdout (dev only — avoid leaking PII in prod logs)
 94→  if (!app.isPackaged) {
 95→    mainWindow.webContents.on("console-message", (_event, level, message, line, sourceId) => {
 96→      const prefix =
 97→        level === 2 ? "[renderer:warn]" : level === 3 ? "[renderer:error]" : "[renderer]";
 98→      const source = sourceId ? ` (${sourceId.split("/").pop()}:${line})` : "";
 99→      console.log(`${prefix} ${message}${source}`);
100→    });
101→  }
102→
103→  // External links open in system browser (only allow http/https)
104→  mainWindow.webContents.setWindowOpenHandler(({ url }) => {
105→    try {
106→      const parsed = new URL(url);
107→      if (parsed.protocol === "http:" || parsed.protocol === "https:") {
108→        shell.openExternal(url);
109→      }
110→    } catch {
111→      // Ignore malformed URLs
112→    }
113→    return { action: "deny" };
114→  });
115→
116→  // Block top-level navigation to external URLs (security: prevent redirect hijacks)
117→  mainWindow.webContents.on("will-navigate", (event, url) => {
118→    const appUrl = is.dev
119→      ? process.env.ELECTRON_RENDERER_URL
120→      : `file://${join(__dirname, "../renderer")}`;
121→    if (appUrl && url.startsWith(appUrl)) return; // allow app navigation
122→    event.preventDefault();
123→    try {
124→      const parsed = new URL(url);
125→      if (parsed.protocol === "http:" || parsed.protocol === "https:") {
126→        shell.openExternal(url);
127→      }
128→    } catch {
129→      /* ignore malformed */
130→    }
131→  });
132→
133→  // Track fullscreen state for CSS selectors (.fullscreen)
134→  mainWindow.on("enter-full-screen", () => {
135→    mainWindow?.webContents.send("fullscreen-change", { isFullscreen: true });
136→  });
137→  mainWindow.on("leave-full-screen", () => {
138→    mainWindow?.webContents.send("fullscreen-change", { isFullscreen: false });
139→  });
140→
141→  // Dev: load Vite dev server. Prod: load built files.
142→  if (is.dev && process.env.ELECTRON_RENDERER_URL) {
143→    mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL);
144→  } else {
145→    mainWindow.loadFile(join(__dirname, "../renderer/index.html"));
146→  }
147→}
148→
149→// ---------------------------------------------------------------------------
150→// App Lifecycle
151→// ---------------------------------------------------------------------------
152→
153→app.whenReady().then(async () => {
154→  // Debug logging to file (Electron swallows stdout/stderr in dev mode)
155→  const fs = await import("fs");
156→  const debugLogPath = join(app.getPath("temp"), "deus-debug.log");
157→  const debugLog = (msg: string) => {
158→    try {
159→      fs.appendFileSync(debugLogPath, `${new Date().toISOString()} ${msg}\n`);
160→    } catch {
161→      // Never block boot on diagnostics
162→    }
163→    console.error(msg);
164→  };
165→  debugLog("[main] App ready, starting initialization...");
166→  debugLog("[main] __dirname: " + __dirname);
167→
168→  // Set up the native app menu (File, Edit, View, Window, Help)
169→  setupAppMenu();
170→  // Fix PATH when launched from macOS Finder (login shell doesn't run)
171→  if (process.platform === "darwin") {
172→    try {
173→      await syncShellEnvironment();
174→    } catch (err) {
175→      debugLog(
176→        "[main] syncShellEnvironment failed: " + (err instanceof Error ? err.message : String(err))
177→      );
178→    }
179→  }
180→
181→  // Spawn backend as child process
182→  debugLog("[main] Spawning backend...");
183→  try {
184→    const { port: backendPort, authToken } = await spawnBackend();
185→    debugLog("[main] Backend started on port: " + backendPort);
186→
187→    // Expose backend connection info so IPC handlers can return it to renderer
188→    process.env.DEUS_BACKEND_PORT = String(backendPort);
189→    process.env.DEUS_AUTH_TOKEN = authToken;
190→
191→    // System tray icon with backend health status
192→    setupTray(backendPort);
193→  } catch (err) {
194→    debugLog("[main] Backend spawn FAILED: " + (err instanceof Error ? err.message : String(err)));
195→    const { dialog } = await import("electron");
196→    dialog.showErrorBox(
197→      "Failed to Start",
198→      `The application backend failed to start.\n\n${err instanceof Error ? err.message : String(err)}`
199→    );
200→    app.quit();
201→    return;
202→  }
203→
204→  // Agent-server is spawned by the backend process (via AGENT_SERVER_BUNDLE_PATH env var)
205→  // when AGENT_SERVER_BUNDLE_PATH env var is present.
206→
207→  // Register IPC handlers before window creation so they're ready immediately
208→  registerNativeHandlers();
209→  registerBrowserViewHandlers();
210→
211→  // Cross-window event relay — when one renderer sends an event via ipcRenderer.send(),
212→  // forward it to all OTHER windows. This enables the detached browser window to
213→  // communicate with the main window (e.g., CHAT_INSERT events).
214→  const RELAY_EVENTS = new Set([
215→    "chat-insert", // Detached browser -> main window
216→    "browser-window:workspace-change", // Main window → detached browser window
217→  ]);
218→
219→  for (const channel of RELAY_EVENTS) {
220→    ipcMain.on(channel, (event, ...args) => {
221→      for (const win of BrowserWindow.getAllWindows()) {
222→        if (win.webContents.id !== event.sender.id && !win.isDestroyed()) {
223→          win.webContents.send(channel, ...args);
224→        }
225→      }
226→    });
227→  }
228→
229→  debugLog("[main] Creating window...");
230→  // PTY, FS watching, browser server — all handled by backend now
231→
232→  await createWindow();
233→  debugLog("[main] Window created");
234→
235→  // Dev mode: swap dock icon so it's visually distinct from the production app
236→  if (is.dev && process.platform === "darwin") {
237→    try {
238→      const { nativeImage } = await import("electron");
239→      const devIconPath = join(__dirname, "../../resources/icons/icon-dev.png");
240→      const devIcon = nativeImage.createFromPath(devIconPath);
241→      if (!devIcon.isEmpty()) {
242→        app.dock?.setIcon(devIcon);
243→        debugLog("[main] Dev dock icon set (orange dot)");
244→      }
245→    } catch (err) {
246→      debugLog(
247→        "[main] Failed to set dev dock icon: " + (err instanceof Error ? err.message : String(err))
248→      );
249→    }
250→  }
251→
252→  // Auto-updater (delayed start — let the app boot first)
253→  if (!is.dev) {
254→    setTimeout(() => {
255→      if (mainWindow && !mainWindow.isDestroyed()) setupAutoUpdater(mainWindow);
256→    }, 15_000);
257→  }
258→});
259→
260→// Second instance: focus existing window
261→app.on("second-instance", () => {
262→  if (mainWindow) {
263→    if (mainWindow.isMinimized()) mainWindow.restore();
264→    mainWindow.focus();
265→  }
266→});
267→
268→// Quit when all windows are closed (all platforms including macOS)
269→app.on("window-all-closed", () => {
270→  app.quit();
271→});
272→
273→app.on("before-quit", () => {
274→  destroyTray();
275→  destroyAllBrowserViews();
276→  stopBackend();
277→});
278→
279→// Export for IPC handlers that need window reference
280→export function getMainWindow(): BrowserWindow | null {
281→  return mainWindow;
282→}
