 93→function getAssetPattern(
 94→  os: string,
 95→  cpuArch: string
 96→): { matcher: (name: string) => boolean; description: string } | null {
 97→  switch (os) {
 98→    case "darwin": {
 99→      const archSuffix = cpuArch === "arm64" ? "arm64" : "x64";
100→      return {
101→        matcher: (name) => name.endsWith(".dmg") && name.includes(archSuffix),
102→        description: `macOS DMG (${archSuffix})`,
103→      };
104→    }
105→    case "win32":
106→      return {
107→        matcher: (name) => name.endsWith(".exe") && !name.includes("blockmap"),
108→        description: "Windows installer (exe)",
109→      };
110→    case "linux":
111→      return {
112→        matcher: (name) => name.endsWith(".AppImage"),
113→        description: "Linux AppImage",
114→      };
115→    default:
116→      return null;
117→  }
