120→async function fetchRelease(version: string): Promise<GithubRelease | null> {
121→  const endpoint =
122→    version === "latest"
123→      ? `https://api.github.com/repos/${GITHUB_REPO}/releases/latest`
124→      : `https://api.github.com/repos/${GITHUB_REPO}/releases/tags/${version}`;
125→
126→  return new Promise((resolve) => {
127→    get(
128→      endpoint,
129→      {
130→        headers: {
131→          "User-Agent": "deus-cli",
132→          Accept: "application/vnd.github.v3+json",
133→        },
134→      },
135→      (res) => {
136→        // Follow redirects
137→        if (res.statusCode === 302 || res.statusCode === 301) {
138→          const redirectUrl = res.headers.location;
139→          if (redirectUrl) {
140→            get(
141→              redirectUrl,
142→              { headers: { "User-Agent": "deus-cli" } },
143→              (redirectRes) => {
144→                collectBody(redirectRes).then((body) => {
145→                  try {
146→                    resolve(JSON.parse(body));
147→                  } catch {
148→                    resolve(null);
149→                  }
150→                });
151→              }
152→            ).on("error", () => resolve(null));
153→            return;
154→          }
155→        }
156→
157→        if (res.statusCode !== 200) {
158→          resolve(null);
159→          return;
160→        }
161→
162→        collectBody(res).then((body) => {
163→          try {
164→            resolve(JSON.parse(body));
165→          } catch {
166→            resolve(null);
167→          }
168→        });
169→      }
170→    ).on("error", () => resolve(null));
171→  });
172→}
173→
174→function collectBody(res: IncomingMessage): Promise<string> {
175→  return new Promise((resolve) => {
176→    let body = "";
177→    res.on("data", (chunk: Buffer) => (body += chunk.toString()));
178→    res.on("end", () => resolve(body));
179→    res.on("error", () => resolve(""));
180→  });
181→}
