183→async function downloadFile(url: string, dest: string): Promise<void> {
184→  return new Promise((resolve, reject) => {
185→    const download = (downloadUrl: string) => {
186→      get(downloadUrl, { headers: { "User-Agent": "deus-cli" } }, (res) => {
187→        // Follow redirects (GitHub releases redirect to S3)
188→        if (res.statusCode === 302 || res.statusCode === 301) {
189→          const redirectUrl = res.headers.location;
190→          if (redirectUrl) {
191→            download(redirectUrl);
192→            return;
193→          }
194→        }
195→
196→        if (res.statusCode !== 200) {
