  cross: isUnicode ? "✗" : "×",
  dot: isUnicode ? "●" : "*",
  dash: isUnicode ? "─" : "-",
  arrow: isUnicode ? "→" : "->",
  diamond: isUnicode ? "◆" : "*",
  pointer: isUnicode ? "❯" : ">",
  info: isUnicode ? "ℹ" : "i",
  warning: isUnicode ? "⚠" : "!",
  bullet: isUnicode ? "•" : "-",

  // Box drawing
  tl: isUnicode ? "╭" : "+",
  tr: isUnicode ? "╮" : "+",
  bl: isUnicode ? "╰" : "+",
  br: isUnicode ? "╯" : "+",
