#!/usr/bin/env node

/**
 * Deus CLI — run Deus IDE from the command line.
 *
 * Smart default:
 *   deus              On a desktop → launch app (install if needed)
 *                     On a server  → start headless with web UI
 *
 * Explicit commands:
 *   deus serve        Start headless server with web UI
 *   deus desktop      Download and install the desktop app
 */

import { parseArgs } from "node:util";
import { serve } from "./serve.js";
import { installDesktop, hasDisplay, findInstalledApp, launchDesktop } from "./desktop.js";

const HELP = `
  Deus IDE — AI-powered IDE for managing multiple parallel coding agents

  Usage:
    deus [command] [options]

  Commands:
    (default)   Auto-detect: launch desktop app or start headless server
    serve       Start headless server with web UI
    desktop     Download and install the desktop app

  Options (serve):
    --port, -p <port>     Port for the web UI (default: 3000)
    --host <host>         Host to bind to (default: localhost)
    --open                Open browser after starting
    --data-dir <path>     Directory for database and data files

  Options (desktop):
    --version <version>   Specific version to install (default: latest)

  Examples:
    deus                  Auto-detect mode
    deus serve -p 8080    Start server on port 8080
    deus desktop          Install the desktop app
`;

async function main() {
  const args = process.argv.slice(2);
  const command = args[0] && !args[0].startsWith("-") ? args[0] : null;
  const commandArgs = command ? args.slice(1) : args;

  if (command === "help" || args.includes("--help") || args.includes("-h")) {
    console.log(HELP);
    process.exit(0);
  }

  if (args.includes("--version") && command !== "desktop") {
    const pkg = await import("../package.json", { with: { type: "json" } });
    console.log(pkg.default.version);
    process.exit(0);
  }

  // Resolve the actual command
  const resolvedCommand = command ?? autoDetect();

  switch (resolvedCommand) {
    case "serve": {
      const { values } = parseArgs({
        args: commandArgs,
        options: {
          port: { type: "string", short: "p", default: "3000" },
          host: { type: "string", default: "localhost" },
          open: { type: "boolean", default: false },
          "data-dir": { type: "string" },
        },
        strict: false,
      });

      await serve({
        port: parseInt(values.port as string, 10),
        host: values.host as string,
        open: values.open as boolean,
        dataDir: values["data-dir"] as string | undefined,
      });
      break;
    }

    case "desktop": {
      const { values } = parseArgs({
        args: commandArgs,
        options: {
          version: { type: "string", default: "latest" },
        },
        strict: false,
      });

      // Check if already installed — just launch
      const installedPath = findInstalledApp();
      if (installedPath) {
        console.log("");
        console.log(`  Deus is already installed at ${installedPath}`);
        launchDesktop(installedPath);
        console.log("");
        return;
      }

      await installDesktop({ version: values.version as string });
      break;
    }

    default:
      console.error(`Unknown command: ${resolvedCommand}`);
      console.log(HELP);
      process.exit(1);
  }
}

/**
 * Auto-detect the best mode based on environment:
 * - Desktop with display → "desktop" (launch or install the app)
 * - Server / headless → "serve" (run headless with web UI)
 */
function autoDetect(): "serve" | "desktop" {
  if (!hasDisplay()) {
    console.log("  No display detected — starting in server mode\n");
    return "serve";
  }

  // Desktop environment — check if app is installed
  const installedPath = findInstalledApp();
  if (installedPath) {
    console.log(`  Found Deus at ${installedPath}\n`);
    return "desktop";
  }

  // Desktop but not installed — install it
  console.log("  Desktop environment detected — installing Deus app\n");
  return "desktop";
}

main().catch((err) => {
  console.error("Fatal error:", err);
  process.exit(1);
});

