  1→/**
  2→ * Headless serve mode — starts agent-server, backend, and serves the web UI.
  3→ *
  4→ * Process orchestration mirrors scripts/dev.sh but in production mode:
  5→ * 1. Start agent-server → capture LISTEN_URL from stdout
  6→ * 2. Start backend with AGENT_SERVER_URL → capture [BACKEND_PORT] from stdout
  7→ * 3. Serve static frontend files, proxying /api and /ws to backend
  8→ *
  9→ * In "bundled" mode (npm install), pre-built bundles are loaded from ./bundles/.
 10→ * In "dev" mode (running from monorepo), builds are found in their source locations.
 11→ */
 12→
 13→import { spawn, execSync, type ChildProcess } from "node:child_process";
 14→import { createServer, request as httpRequest } from "node:http";
 15→import { readFileSync, existsSync, statSync } from "node:fs";
 16→import { join, resolve, extname, dirname } from "node:path";
 17→import { fileURLToPath } from "node:url";
 18→import { platform, homedir, arch } from "node:os";
 19→import { mkdirSync } from "node:fs";
 20→
 21→const __filename = fileURLToPath(import.meta.url);
 22→const __dirname = dirname(__filename);
 23→
 24→// MIME types for static file serving
 25→const MIME_TYPES: Record<string, string> = {
 26→  ".html": "text/html",
 27→  ".js": "application/javascript",
 28→  ".mjs": "application/javascript",
 29→  ".css": "text/css",
 30→  ".json": "application/json",
 31→  ".png": "image/png",
 32→  ".jpg": "image/jpeg",
 33→  ".jpeg": "image/jpeg",
 34→  ".gif": "image/gif",
 35→  ".svg": "image/svg+xml",
 36→  ".ico": "image/x-icon",
 37→  ".woff": "font/woff",
 38→  ".woff2": "font/woff2",
 39→  ".ttf": "font/ttf",
 40→  ".map": "application/json",
 41→};
 42→
 43→export interface ServeOptions {
 44→  port: number;
 45→  host: string;
 46→  open: boolean;
 47→  dataDir?: string;
 48→}
 49→
 50→interface ProcessInfo {
 51→  process: ChildProcess;
 52→  name: string;
 53→}
 54→
 55→export async function serve(options: ServeOptions): Promise<void> {
 56→  const { port, host, open, dataDir } = options;
 57→
 58→  console.log("");
 59→  console.log("  Deus IDE — Starting headless server");
 60→  console.log("  ====================================");
 61→  console.log("");
 62→
 63→  // Resolve paths to bundles
 64→  const paths = resolveBundlePaths();
 65→  if (!paths) {
 66→    console.error("  Error: Could not find Deus bundles.");
 67→    console.error("  Run 'bun run build:cli' from the monorepo root first.");
 68→    process.exit(1);
 69→  }
 70→
 71→  // Resolve the Node binary for child processes.
 72→  // In monorepo dev mode, native modules (better-sqlite3, node-pty) are compiled
 73→  // against Electron's Node ABI. Use Electron's node binary to avoid ABI mismatch.
 74→  // When installed via npm, native modules are compiled for the user's Node.
 75→  const nodeCmd = resolveNodeBinary();
 76→  console.log(`  Node: ${nodeCmd === process.execPath ? "system" : "electron"} (${nodeCmd})`);
 77→
 78→  // Resolve data directory for database
 79→  const dbPath = resolveDataDir(dataDir);
 80→  console.log(`  Database: ${dbPath}`);
 81→
 82→  // Track child processes for cleanup
 83→  const children: ProcessInfo[] = [];
 84→
 85→  // Graceful shutdown handler
 86→  function shutdown() {
 87→    console.log("\n  Shutting down...");
 88→    for (const child of children) {
 89→      if (!child.process.killed) {
 90→        child.process.kill("SIGTERM");
 91→      }
 92→    }
 93→    process.exit(0);
 94→  }
 95→  process.on("SIGINT", shutdown);
 96→  process.on("SIGTERM", shutdown);
 97→
 98→  // Step 1: Start agent-server
 99→  console.log("  Starting agent-server...");
100→  const agentServerUrl = await startProcess({
101→    name: "agent-server",
102→    command: nodeCmd,
103→    args: [paths.agentServer],
104→    env: { DATABASE_PATH: dbPath },
105→    waitFor: /LISTEN_URL=(.+)/,
106→    children,
107→  });
108→
109→  if (!agentServerUrl) {
110→    console.error("  Error: Agent-server failed to start");
111→    shutdown();
112→    return;
113→  }
114→  console.log(`  Agent-server: ${agentServerUrl}`);
115→
116→  // Step 2: Start backend
117→  console.log("  Starting backend...");
118→  const backendPort = await startProcess({
119→    name: "backend",
120→    command: nodeCmd,
121→    args: [paths.backend],
122→    env: {
123→      AGENT_SERVER_URL: agentServerUrl,
124→      DATABASE_PATH: dbPath,
125→      PORT: "0", // Dynamic port
126→    },
127→    waitFor: /\[BACKEND_PORT\](\d+)/,
128→    children,
129→  });
130→
131→  if (!backendPort) {
132→    console.error("  Error: Backend failed to start");
133→    shutdown();
134→    return;
135→  }
136→  console.log(`  Backend API: http://localhost:${backendPort}`);
137→
138→  // Step 3: Start web server (static files + reverse proxy to backend)
139→  const webServer = createWebServer(
140→    parseInt(backendPort, 10),
141→    paths.frontend
142→  );
143→
144→  webServer.listen(port, host, () => {
145→    console.log("");
146→    console.log(`  Deus is running at http://${host}:${port}`);
147→    console.log("");
148→    console.log("  Press Ctrl+C to stop");
149→    console.log("");
150→
151→    if (open) {
152→      openBrowser(`http://${host}:${port}`);
153→    }
154→  });
155→
156→  // Keep the process alive
157→  await new Promise(() => {});
158→}
159→
160→/**
161→ * Resolve paths to the pre-built bundles.
162→ * Checks two locations:
163→ * 1. Bundled mode (npm package): ./bundles/
164→ * 2. Dev mode (monorepo): relative paths to build outputs
165→ */
166→function resolveBundlePaths(): {
167→  agentServer: string;
168→  backend: string;
169→  frontend: string;
170→} | null {
171→  // CLI package root (packages/cli/)
172→  const cliRoot = resolve(__dirname, "..");
173→
174→  // Option 1: Bundled mode — bundles/ directory in the CLI package
175→  const bundledDir = join(cliRoot, "bundles");
176→  if (existsSync(join(bundledDir, "agent-server.bundled.cjs"))) {
177→    return {
178→      agentServer: join(bundledDir, "agent-server.bundled.cjs"),
179→      backend: join(bundledDir, "server.bundled.cjs"),
180→      frontend: join(bundledDir, "web"),
181→    };
182→  }
183→
184→  // Option 2: Dev mode — find bundles in monorepo build outputs
185→  const monorepoRoot = resolve(cliRoot, "../..");
186→  const agentServer = join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs");
187→  const backend = join(monorepoRoot, "apps/backend/dist/server.bundled.cjs");
188→  const frontend = join(monorepoRoot, "apps/web/dist/web");
189→
190→  if (existsSync(agentServer) && existsSync(backend)) {
191→    // Frontend might not be built yet, but backend + agent-server are required
192→    return { agentServer, backend, frontend };
193→  }
194→
195→  return null;
196→}
197→
198→/**
199→ * Resolve the database file path, creating the directory if needed.
200→ */
201→function resolveDataDir(customDir?: string): string {
202→  if (customDir) {
203→    mkdirSync(customDir, { recursive: true });
204→    return join(customDir, "deus.db");
205→  }
206→
207→  // Platform-appropriate default data directory
208→  const os = platform();
209→  let dir: string;
210→
211→  if (os === "darwin") {
212→    dir = join(homedir(), "Library/Application Support/com.deus.app");
213→  } else if (os === "win32") {
214→    dir = join(process.env.APPDATA || join(homedir(), "AppData/Roaming"), "com.deus.app");
215→  } else {
216→    // Linux / other: XDG_DATA_HOME or ~/.local/share
217→    dir = join(process.env.XDG_DATA_HOME || join(homedir(), ".local/share"), "deus");
218→  }
219→
220→  mkdirSync(dir, { recursive: true });
221→  return join(dir, "deus.db");
222→}
223→
224→/**
225→ * Resolve the Node.js binary for spawning child processes.
226→ *
227→ * In monorepo dev mode, native modules are compiled against Electron's Node ABI
228→ * (via `electron-builder install-app-deps` in postinstall). Using system Node
229→ * causes ERR_DLOPEN_FAILED. Detect and use Electron's embedded Node binary.
230→ *
231→ * When installed as an npm package, native modules are compiled for system Node.
232→ */
233→function resolveNodeBinary(): string {
234→  // If ELECTRON_RUN_AS_NODE is already set, we're being run via Electron's node
235→  if (process.env.ELECTRON_RUN_AS_NODE === "1") {
236→    return process.execPath;
237→  }
238→
239→  // Check if we're in a monorepo with electron installed
240→  try {
241→    const electronPath = execSync(
242→      'node -e "try { console.log(require(\'electron\')) } catch { process.exit(1) }"',
243→      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
244→    ).trim();
245→
246→    if (electronPath && existsSync(electronPath)) {
247→      // Test if system Node can actually use better-sqlite3 (load the .node binary)
248→      try {
249→        execSync(
250→          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
251→          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
252→        );
253→        // System Node works fine — no need for Electron's node
254→        return process.execPath;
255→      } catch {
256→        // System Node can't use native modules — use Electron's node
257→        return electronPath;
258→      }
259→    }
260→  } catch {
261→    // Electron not available — use system node
262→  }
263→
264→  return process.execPath;
265→}
266→
267→/**
268→ * Start a child process and wait for a pattern in stdout.
269→ * Returns the first capture group from the pattern match.
270→ */
271→async function startProcess(opts: {
272→  name: string;
273→  command: string;
274→  args: string[];
275→  env: Record<string, string>;
276→  waitFor: RegExp;
277→  children: ProcessInfo[];
278→  timeoutMs?: number;
279→}): Promise<string | null> {
280→  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
281→
282→  return new Promise((resolve) => {
283→    // If using Electron's node binary, set ELECTRON_RUN_AS_NODE=1
284→    const extraEnv: Record<string, string> = {};
285→    if (command !== process.execPath && command.includes("Electron")) {
286→      extraEnv.ELECTRON_RUN_AS_NODE = "1";
287→    }
288→
289→    const child = spawn(command, args, {
290→      stdio: ["ignore", "pipe", "pipe"],
291→      env: { ...process.env, ...extraEnv, ...env },
292→    });
293→
294→    children.push({ process: child, name });
295→
296→    let buffer = "";
297→    let resolved = false;
298→
299→    const timeout = setTimeout(() => {
300→      if (!resolved) {
301→        resolved = true;
302→        console.error(`  Warning: ${name} did not produce expected output within ${timeoutMs}ms`);
303→        resolve(null);
304→      }
305→    }, timeoutMs);
306→
307→    child.stdout?.on("data", (data: Buffer) => {
308→      const text = data.toString();
309→      buffer += text;
310→
311→      // Log output with prefix
312→      for (const line of text.split("\n")) {
313→        const trimmed = line.trim();
314→        if (trimmed && !resolved) {
315→          // Don't spam — only log important lines
316→        }
317→      }
318→
319→      // Check for the pattern
320→      const match = buffer.match(waitFor);
321→      if (match && !resolved) {
322→        resolved = true;
323→        clearTimeout(timeout);
324→        resolve(match[1]);
325→      }
326→    });
327→
328→    child.stderr?.on("data", (data: Buffer) => {
329→      for (const line of data.toString().split("\n")) {
330→        if (line.trim()) {
331→          console.error(`  [${name}:err] ${line.trim()}`);
332→        }
333→      }
334→    });
335→
336→    child.on("exit", (code, signal) => {
337→      if (!resolved) {
338→        resolved = true;
339→        clearTimeout(timeout);
340→        console.error(`  ${name} exited unexpectedly (code=${code}, signal=${signal})`);
341→        resolve(null);
342→      }
343→    });
344→  });
345→}
346→
347→/**
348→ * Create an HTTP server that:
349→ * - Proxies /api/* and /ws to the backend
350→ * - Serves static frontend files for everything else
351→ * - Injects the backend port into the frontend config
352→ */
353→function createWebServer(backendPort: number, frontendDir: string) {
354→  const hasFrontend = existsSync(frontendDir) && existsSync(join(frontendDir, "index.html"));
355→
356→  const server = createServer(async (req, res) => {
357→    const url = req.url || "/";
358→
359→    // Proxy API requests to backend
360→    if (url.startsWith("/api/") || url.startsWith("/api")) {
361→      return proxyRequest(req, res, backendPort);
362→    }
363→
364→    // Serve __backend_port for frontend config discovery
365→    if (url === "/__backend_port") {
366→      res.writeHead(200, {
367→        "Content-Type": "application/json",
368→        "Access-Control-Allow-Origin": "*",
369→      });
370→      res.end(JSON.stringify({ port: backendPort }));
371→      return;
372→    }
373→
374→    // Serve static frontend files
375→    if (hasFrontend) {
376→      serveStaticFile(req, res, frontendDir);
377→    } else {
378→      // No frontend build — show a simple status page
379→      res.writeHead(200, { "Content-Type": "text/html" });
380→      res.end(`
381→        <!DOCTYPE html>
382→        <html>
383→        <head><title>Deus IDE</title></head>
384→        <body style="font-family: system-ui; padding: 2rem; background: #0a0a0a; color: #e5e5e5;">
385→          <h1>Deus IDE Server</h1>
386→          <p>Backend API running on port ${backendPort}</p>
387→          <p>WebSocket: ws://localhost:${backendPort}/ws</p>
388→          <p style="color: #a3a3a3;">Frontend not built. Run <code>bun run build:web</code> to build the UI.</p>
389→        </body>
390→        </html>
391→      `);
392→    }
393→  });
394→
395→  // Handle WebSocket upgrade — proxy to backend
396→  server.on("upgrade", (req, socket, head) => {
397→    const proxyReq = httpRequest({
398→      hostname: "localhost",
399→      port: backendPort,
400→      path: req.url,
401→      method: req.method,
402→      headers: req.headers,
403→    });
404→
405→    proxyReq.on("upgrade", (_proxyRes: any, proxySocket: any, proxyHead: any) => {
406→      socket.write(
407→        "HTTP/1.1 101 Switching Protocols\r\n" +
408→          Object.entries(_proxyRes.headers)
409→            .map(([k, v]: [string, any]) => `${k}: ${v}`)
410→            .join("\r\n") +
411→          "\r\n\r\n"
412→      );
413→      if (proxyHead.length > 0) socket.write(proxyHead);
414→
415→      proxySocket.pipe(socket);
416→      socket.pipe(proxySocket);
417→    });
418→
419→    proxyReq.on("error", () => {
420→      socket.end();
421→    });
422→
423→    proxyReq.end();
424→  });
425→
426→  return server;
427→}
428→
429→/**
430→ * Proxy an HTTP request to the backend.
431→ */
432→function proxyRequest(
433→  req: import("node:http").IncomingMessage,
434→  res: import("node:http").ServerResponse,
435→  backendPort: number
436→) {
437→  const proxyReq = httpRequest(
438→    {
439→      hostname: "localhost",
440→      port: backendPort,
441→      path: req.url,
442→      method: req.method,
443→      headers: {
444→        ...req.headers,
445→        host: `localhost:${backendPort}`,
446→      },
447→    },
448→    (proxyRes) => {
449→      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
450→      proxyRes.pipe(res);
451→    }
452→  );
453→
454→  proxyReq.on("error", () => {
455→    res.writeHead(502, { "Content-Type": "application/json" });
456→    res.end(JSON.stringify({ error: "Backend unavailable" }));
457→  });
458→
459→  req.pipe(proxyReq);
460→}
461→
462→/**
463→ * Serve a static file from the frontend build directory.
464→ * Falls back to index.html for SPA client-side routing.
465→ */
466→function serveStaticFile(
467→  req: import("node:http").IncomingMessage,
468→  res: import("node:http").ServerResponse,
469→  frontendDir: string
470→) {
471→  let pathname = (req.url || "/").split("?")[0];
472→  if (pathname === "/") pathname = "/index.html";
473→
474→  let filePath = join(frontendDir, pathname);
475→
476→  // SPA fallback: if file doesn't exist, serve index.html
477→  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
478→    filePath = join(frontendDir, "index.html");
479→  }
480→
481→  if (!existsSync(filePath)) {
482→    res.writeHead(404);
483→    res.end("Not found");
484→    return;
485→  }
486→
487→  const ext = extname(filePath);
488→  const contentType = MIME_TYPES[ext] || "application/octet-stream";
489→
490→  try {
491→    const content = readFileSync(filePath);
492→    res.writeHead(200, {
493→      "Content-Type": contentType,
494→      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
495→    });
496→    res.end(content);
497→  } catch {
498→    res.writeHead(500);
499→    res.end("Internal server error");
500→  }
501→}
502→
503→/**
504→ * Open a URL in the default browser.
505→ */
506→function openBrowser(url: string) {
507→  const os = platform();
508→  const cmd = os === "darwin" ? "open" : os === "win32" ? "start" : "xdg-open";
509→  spawn(cmd, [url], { detached: true, stdio: "ignore" }).unref();
510→}
