  switch (os) {
    case "darwin": {
      const archSuffix = cpuArch === "arm64" ? "arm64" : "x64";
      return {
        matcher: (name) => name.endsWith(".dmg") && name.includes(archSuffix),
        description: `macOS DMG (${archSuffix})`,
      };
    }
    case "win32":
      return {
        matcher: (name) => name.endsWith(".exe") && !name.includes("blockmap"),
        description: "Windows installer (exe)",
      };
    case "linux":
      return {
        matcher: (name) => name.endsWith(".AppImage"),
        description: "Linux AppImage",
      };
    default:
      return null;
  }
}

async function fetchRelease(version: string): Promise<GithubRelease | null> {
  const endpoint =
    version === "latest"
      ? `https://api.github.com/repos/${GITHUB_REPO}/releases/latest`
      : `https://api.github.com/repos/${GITHUB_REPO}/releases/tags/${version}`;

  return new Promise((resolve) => {
    get(
      endpoint,
      {
        headers: {
          "User-Agent": "deus-cli",
          Accept: "application/vnd.github.v3+json",
        },
      },
      (res) => {
        // Follow redirects
        if (res.statusCode === 302 || res.statusCode === 301) {
          const redirectUrl = res.headers.location;
          if (redirectUrl) {
            get(
              redirectUrl,
              { headers: { "User-Agent": "deus-cli" } },
              (redirectRes) => {
                collectBody(redirectRes).then((body) => {
                  try {
                    resolve(JSON.parse(body));
                  } catch {
                    resolve(null);
                  }
                });
              }
            ).on("error", () => resolve(null));
            return;
          }
        }

        if (res.statusCode !== 200) {
          resolve(null);
          return;
        }

        collectBody(res).then((body) => {
          try {
            resolve(JSON.parse(body));
          } catch {
            resolve(null);
          }
        });
      }
    ).on("error", () => resolve(null));
  });
}

function collectBody(res: IncomingMessage): Promise<string> {
  return new Promise((resolve) => {
    let body = "";
    res.on("data", (chunk: Buffer) => (body += chunk.toString()));
    res.on("end", () => resolve(body));
    res.on("error", () => resolve(""));
  });
}

async function downloadFile(url: string, dest: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const download = (downloadUrl: string) => {
      get(downloadUrl, { headers: { "User-Agent": "deus-cli" } }, (res) => {
        // Follow redirects (GitHub releases redirect to S3)
        if (res.statusCode === 302 || res.statusCode === 301) {
          const redirectUrl = res.headers.location;
          if (redirectUrl) {
            download(redirectUrl);
            return;
          }
        }

        if (res.statusCode !== 200) {
          reject(new Error(`Download failed with status ${res.statusCode}`));
          return;
        }

        const totalSize = parseInt(res.headers["content-length"] || "0", 10);
        let downloaded = 0;

        const file = createWriteStream(dest);
        res.on("data", (chunk: Buffer) => {
          downloaded += chunk.length;
          if (totalSize > 0) {
            const pct = Math.round((downloaded / totalSize) * 100);
            process.stdout.write(`\r  Progress: ${pct}% (${formatBytes(downloaded)} / ${formatBytes(totalSize)})`);
          }
        });
        res.pipe(file);
        file.on("finish", () => {
          file.close();
          process.stdout.write("\n");
          resolve();
        });
        file.on("error", reject);
      }).on("error", reject);
    };

    download(url);
  });
}

function formatBytes(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

async function installForPlatform(os: string, filePath: string, fileName: string): Promise<void> {
  switch (os) {
    case "darwin": {
      console.log("  Installing DMG...");
      console.log("  Mounting disk image...");

      try {
        // Mount the DMG
        const mountOutput = execSync(`hdiutil attach "${filePath}" -nobrowse`, {
          encoding: "utf-8",
        });

        // Find the mount point
        const mountPoint = mountOutput
          .split("\n")
          .filter((line) => line.includes("/Volumes/"))
          .map((line) => line.trim().split("\t").pop()?.trim())
          .find(Boolean);

        if (!mountPoint) {
          console.error("  Could not find mount point");
          return;
        }

        // Copy .app to /Applications
        const appName = "Deus.app";
        const appPath = `${mountPoint}/${appName}`;
        const destPath = `/Applications/${appName}`;

        if (existsSync(appPath)) {
          console.log(`  Copying ${appName} to /Applications...`);
          execSync(`cp -R "${appPath}" "${destPath}"`, { stdio: "pipe" });
          console.log("  Installed successfully!");

          // Launch the app
          launchDesktop(destPath);
        } else {
          console.log(`  DMG mounted at ${mountPoint}`);
          console.log("  Drag the app to /Applications to complete installation.");
        }

        // Unmount
        execSync(`hdiutil detach "${mountPoint}" -quiet`, { stdio: "pipe" });
      } catch (err) {
        console.error("  Install failed. Opening DMG for manual installation...");
        execSync(`open "${filePath}"`);
      }
      break;
    }

    case "win32": {
      console.log("  Running installer...");
      spawn(filePath, [], { detached: true, stdio: "ignore" }).unref();
      console.log("  Installer launched. Follow the on-screen instructions.");
      break;
    }

    case "linux": {
      console.log("  Making AppImage executable...");
      execSync(`chmod +x "${filePath}"`);

      // Copy to ~/Applications or ~/.local/bin
      const installDir = join(homedir(), ".local", "bin");
      mkdirSync(installDir, { recursive: true });
      const destPath = join(installDir, "Deus.AppImage");
      execSync(`cp "${filePath}" "${destPath}"`);
      console.log(`  Installed to ${destPath}`);

      // Launch the app
      launchDesktop(destPath);
      break;
    }
  }

  console.log("");
}

