228→ * (via `electron-builder install-app-deps` in postinstall). Using system Node
229→ * causes ERR_DLOPEN_FAILED. Detect and use Electron's embedded Node binary.
230→ *
231→ * When installed as an npm package, native modules are compiled for system Node.
232→ */
233→function resolveNodeBinary(): string {
234→  // If ELECTRON_RUN_AS_NODE is already set, we're being run via Electron's node
235→  if (process.env.ELECTRON_RUN_AS_NODE === "1") {
236→    return process.execPath;
237→  }
