503→/**
504→ * Open a URL in the default browser.
505→ */
506→function openBrowser(url: string) {
507→  const os = platform();
508→  const cmd = os === "darwin" ? "open" : os === "win32" ? "start" : "xdg-open";
509→  spawn(cmd, [url], { detached: true, stdio: "ignore" }).unref();
510→}
