 40→/**
 41→ * Check if a display/GUI is available (i.e. not a headless server).
 42→ * Returns false for SSH sessions, Docker containers, CI, etc.
 43→ */
 44→export function hasDisplay(): boolean {
 45→  const os = platform();
 46→
 47→  // Docker / CI detection
 48→  if (process.env.CI || process.env.DOCKER || existsSync("/.dockerenv")) return false;
 49→
 50→  // macOS always has a display (even over SSH, `open` launches GUI apps)
 51→  if (os === "darwin") return true;
 52→
 53→  // Windows: assume display unless explicitly headless
 54→  if (os === "win32") return !process.env.SSH_CONNECTION;
 55→
 56→  // Linux: check for DISPLAY or WAYLAND_DISPLAY
 57→  if (os === "linux") {
 58→    return !!(process.env.DISPLAY || process.env.WAYLAND_DISPLAY);
 59→  }
 60→
 61→  return false;
 62→}
