 64→/**
 65→ * Check if the desktop app is already installed.
 66→ * Returns the path to the installed app, or null.
 67→ */
 68→export function findInstalledApp(): string | null {
 69→  const os = platform();
 70→  const paths = INSTALL_PATHS[os] || [];
 71→
 72→  for (const p of paths) {
 73→    if (p && existsSync(p)) return p;
 74→  }
 75→
 76→  return null;
 77→}
