 79→/**
 80→ * Launch an already-installed desktop app.
 81→ */
 82→export function launchDesktop(appPath: string): void {
 83→  const os = platform();
 84→  console.log(`  Launching Deus...`);
 85→
 86→  switch (os) {
 87→    case "darwin":
 88→      spawn("open", [appPath], { detached: true, stdio: "ignore" }).unref();
 89→      break;
 90→    case "win32":
 91→      spawn(appPath, [], { detached: true, stdio: "ignore" }).unref();
 92→      break;
 93→    case "linux":
 94→      spawn(appPath, [], { detached: true, stdio: "ignore" }).unref();
 95→      break;
 96→  }
 97→}
