 99→export async function installDesktop(options: DesktopOptions): Promise<void> {
100→  const { version } = options;
101→  const os = platform();
102→  const cpuArch = arch();
103→
104→  console.log("");
105→  console.log("  Deus Desktop Installer");
106→  console.log("  ======================");
107→  console.log("");
108→
109→  // Determine which asset to download based on platform
110→  const assetPattern = getAssetPattern(os, cpuArch);
111→  if (!assetPattern) {
112→    console.error(`  Unsupported platform: ${os} ${cpuArch}`);
113→    console.error("  Supported: macOS (arm64/x64), Windows (x64), Linux (x64)");
114→    process.exit(1);
115→  }
116→
117→  console.log(`  Platform: ${os} ${cpuArch}`);
118→  console.log(`  Looking for: ${assetPattern.description}`);
119→  console.log("");
120→
121→  // Fetch release info from GitHub
122→  console.log("  Fetching release info...");
123→  const release = await fetchRelease(version);
124→  if (!release) {
125→    console.error("  Error: Could not find release on GitHub.");
126→    console.error(`  Repo: ${GITHUB_REPO}`);
127→    console.error("  Make sure the repository has published releases.");
128→    process.exit(1);
129→  }
130→
131→  console.log(`  Found release: ${release.tag_name}`);
132→
133→  // Find matching asset
134→  const asset = release.assets.find((a) => assetPattern.matcher(a.name));
135→  if (!asset) {
136→    console.error(`  Error: No matching installer found for ${os} ${cpuArch}`);
137→    console.error("  Available assets:");
138→    for (const a of release.assets) {
139→      console.error(`    - ${a.name}`);
140→    }
141→    process.exit(1);
142→  }
143→
144→  console.log(`  Downloading: ${asset.name}`);
145→
146→  // Download to temp directory
147→  const downloadDir = join(tmpdir(), "deus-installer");
148→  mkdirSync(downloadDir, { recursive: true });
149→  const downloadPath = join(downloadDir, asset.name);
150→
151→  await downloadFile(asset.browser_download_url, downloadPath);
152→  console.log("  Download complete!");
153→  console.log("");
154→
155→  // Install based on platform
156→  await installForPlatform(os, downloadPath, asset.name);
157→
158→  // Cleanup
159→  try {
160→    unlinkSync(downloadPath);
161→  } catch {
162→    // Ignore cleanup errors
163→  }
164→}
165→
166→function getAssetPattern(
167→  os: string,
168→  cpuArch: string
169→): { matcher: (name: string) => boolean; description: string } | null {
170→  switch (os) {
171→    case "darwin": {
172→      const archSuffix = cpuArch === "arm64" ? "arm64" : "x64";
173→      return {
174→        matcher: (name) => name.endsWith(".dmg") && name.includes(archSuffix),
175→        description: `macOS DMG (${archSuffix})`,
176→      };
177→    }
178→    case "win32":
179→      return {
180→        matcher: (name) => name.endsWith(".exe") && !name.includes("blockmap"),
181→        description: "Windows installer (exe)",
182→      };
183→    case "linux":
184→      return {
185→        matcher: (name) => name.endsWith(".AppImage"),
186→        description: "Linux AppImage",
187→      };
188→    default:
189→      return null;
190→  }
191→}
192→
193→async function fetchRelease(version: string): Promise<GithubRelease | null> {
194→  const endpoint =
195→    version === "latest"
196→      ? `https://api.github.com/repos/${GITHUB_REPO}/releases/latest`
197→      : `https://api.github.com/repos/${GITHUB_REPO}/releases/tags/${version}`;
198→
199→  return new Promise((resolve) => {
200→    get(
201→      endpoint,
202→      {
203→        headers: {
204→          "User-Agent": "deus-cli",
205→          Accept: "application/vnd.github.v3+json",
206→        },
207→      },
208→      (res) => {
209→        // Follow redirects
210→        if (res.statusCode === 302 || res.statusCode === 301) {
211→          const redirectUrl = res.headers.location;
212→          if (redirectUrl) {
213→            get(
214→              redirectUrl,
215→              { headers: { "User-Agent": "deus-cli" } },
216→              (redirectRes) => {
217→                collectBody(redirectRes).then((body) => {
218→                  try {
219→                    resolve(JSON.parse(body));
220→                  } catch {
221→                    resolve(null);
222→                  }
223→                });
224→              }
225→            ).on("error", () => resolve(null));
226→            return;
227→          }
228→        }
229→
230→        if (res.statusCode !== 200) {
231→          resolve(null);
232→          return;
233→        }
234→
235→        collectBody(res).then((body) => {
236→          try {
237→            resolve(JSON.parse(body));
238→          } catch {
239→            resolve(null);
240→          }
241→        });
242→      }
243→    ).on("error", () => resolve(null));
244→  });
245→}
246→
247→function collectBody(res: IncomingMessage): Promise<string> {
248→  return new Promise((resolve) => {
249→    let body = "";
250→    res.on("data", (chunk: Buffer) => (body += chunk.toString()));
251→    res.on("end", () => resolve(body));
252→    res.on("error", () => resolve(""));
253→  });
254→}
255→
256→async function downloadFile(url: string, dest: string): Promise<void> {
257→  return new Promise((resolve, reject) => {
258→    const download = (downloadUrl: string) => {
259→      get(downloadUrl, { headers: { "User-Agent": "deus-cli" } }, (res) => {
260→        // Follow redirects (GitHub releases redirect to S3)
261→        if (res.statusCode === 302 || res.statusCode === 301) {
262→          const redirectUrl = res.headers.location;
263→          if (redirectUrl) {
264→            download(redirectUrl);
265→            return;
266→          }
267→        }
268→
269→        if (res.statusCode !== 200) {
270→          reject(new Error(`Download failed with status ${res.statusCode}`));
271→          return;
272→        }
273→
274→        const totalSize = parseInt(res.headers["content-length"] || "0", 10);
275→        let downloaded = 0;
276→
277→        const file = createWriteStream(dest);
278→        res.on("data", (chunk: Buffer) => {
279→          downloaded += chunk.length;
280→          if (totalSize > 0) {
281→            const pct = Math.round((downloaded / totalSize) * 100);
282→            process.stdout.write(`\r  Progress: ${pct}% (${formatBytes(downloaded)} / ${formatBytes(totalSize)})`);
283→          }
284→        });
285→        res.pipe(file);
286→        file.on("finish", () => {
287→          file.close();
288→          process.stdout.write("\n");
289→          resolve();
290→        });
291→        file.on("error", reject);
292→      }).on("error", reject);
293→    };
294→
295→    download(url);
296→  });
297→}
298→
299→function formatBytes(bytes: number): string {
300→  if (bytes < 1024) return `${bytes} B`;
301→  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
302→  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
303→}
304→
305→async function installForPlatform(os: string, filePath: string, fileName: string): Promise<void> {
306→  switch (os) {
307→    case "darwin": {
308→      console.log("  Installing DMG...");
309→      console.log("  Mounting disk image...");
310→
311→      try {
312→        // Mount the DMG
313→        const mountOutput = execSync(`hdiutil attach "${filePath}" -nobrowse`, {
314→          encoding: "utf-8",
315→        });
316→
317→        // Find the mount point
318→        const mountPoint = mountOutput
319→          .split("\n")
320→          .filter((line) => line.includes("/Volumes/"))
321→          .map((line) => line.trim().split("\t").pop()?.trim())
322→          .find(Boolean);
323→
324→        if (!mountPoint) {
325→          console.error("  Could not find mount point");
326→          return;
327→        }
328→
329→        // Copy .app to /Applications
330→        const appName = "Deus.app";
331→        const appPath = `${mountPoint}/${appName}`;
332→        const destPath = `/Applications/${appName}`;
333→
334→        if (existsSync(appPath)) {
335→          console.log(`  Copying ${appName} to /Applications...`);
336→          execSync(`cp -R "${appPath}" "${destPath}"`, { stdio: "pipe" });
337→          console.log("  Installed successfully!");
338→
339→          // Launch the app
340→          launchDesktop(destPath);
341→        } else {
342→          console.log(`  DMG mounted at ${mountPoint}`);
343→          console.log("  Drag the app to /Applications to complete installation.");
344→        }
345→
346→        // Unmount
347→        execSync(`hdiutil detach "${mountPoint}" -quiet`, { stdio: "pipe" });
348→      } catch (err) {
349→        console.error("  Install failed. Opening DMG for manual installation...");
350→        execSync(`open "${filePath}"`);
351→      }
352→      break;
353→    }
354→
355→    case "win32": {
356→      console.log("  Running installer...");
357→      spawn(filePath, [], { detached: true, stdio: "ignore" }).unref();
358→      console.log("  Installer launched. Follow the on-screen instructions.");
359→      break;
360→    }
361→
362→    case "linux": {
363→      console.log("  Making AppImage executable...");
364→      execSync(`chmod +x "${filePath}"`);
365→
366→      // Copy to ~/Applications or ~/.local/bin
367→      const installDir = join(homedir(), ".local", "bin");
368→      mkdirSync(installDir, { recursive: true });
369→      const destPath = join(installDir, "Deus.AppImage");
370→      execSync(`cp "${filePath}" "${destPath}"`);
371→      console.log(`  Installed to ${destPath}`);
372→
373→      // Launch the app
374→      launchDesktop(destPath);
375→      break;
376→    }
377→  }
378→
379→  console.log("");
380→}
