  1→#!/usr/bin/env node
  2→
  3→/**
  4→ * Deus CLI — run Deus IDE from the command line.
  5→ *
  6→ * Smart default:
  7→ *   deus              On a desktop → launch app (install if needed)
  8→ *                     On a server  → start headless with web UI
  9→ *
 10→ * Explicit commands:
 11→ *   deus serve        Start headless server with web UI
 12→ *   deus desktop      Download and install the desktop app
 13→ */
 14→
 15→import { parseArgs } from "node:util";
 16→import { serve } from "./serve.js";
 17→import { installDesktop, hasDisplay, findInstalledApp, launchDesktop } from "./desktop.js";
