 20→function printHelp(version: string) {
 21→  banner(version);
 22→  console.log(`  ${c.bold("Usage:")}   deus ${c.dim("[command] [options]")}`);
 23→  blank();
 24→  console.log(`  ${c.bold("Commands:")}`);
 25→  console.log(`    ${c.dim("(none)")}        Auto-detect: launch desktop app or start server`);
 26→  console.log(`    ${c.cyan("serve")}        Start server with web UI ${c.dim("(headless)")}`);
 27→  console.log(`    ${c.cyan("desktop")}      Download and install the desktop app`);
 28→  blank();
 29→  console.log(`  ${c.bold("Options")} ${c.dim("(serve):")}`);
 30→  console.log(`    ${c.cyan("--port, -p")}   Port for the web UI ${c.dim("(default: 3000)")}`);
 31→  console.log(`    ${c.cyan("--host")}       Host to bind to ${c.dim("(default: localhost)")}`);
 32→  console.log(`    ${c.cyan("--open")}       Open browser after starting`);
 33→  console.log(`    ${c.cyan("--data-dir")}   Directory for database and data files`);
 34→  blank();
 35→  console.log(`  ${c.bold("Examples:")}`);
 36→  console.log(`    ${c.dim("$")} deus                    ${c.dim("# auto-detect mode")}`);
 37→  console.log(`    ${c.dim("$")} deus serve -p 8080      ${c.dim("# server on port 8080")}`);
 38→  console.log(`    ${c.dim("$")} deus serve --open       ${c.dim("# server + open browser")}`);
