 43→async function main() {
 44→  const args = process.argv.slice(2);
 45→  const command = args[0] && !args[0].startsWith("-") ? args[0] : null;
 46→  const commandArgs = command ? args.slice(1) : args;
 47→
 48→  // Load version once
 49→  const pkg = await import("../package.json", { with: { type: "json" } });
 50→  const version = pkg.default.version;
 51→
 52→  // Version (plain output, no banner)
 53→  if (args.includes("--version") || args.includes("-v")) {
 54→    console.log(version);
 55→    process.exit(0);
 56→  }
 57→
 58→  // Help
 59→  if (command === "help" || args.includes("--help") || args.includes("-h")) {
 60→    printHelp(version);
 61→    process.exit(0);
 62→  }
 63→
 64→  // Show banner
 65→  banner(version);
 66→
 67→  // Resolve command
 68→  const resolvedCommand = command ?? autoDetect();
 69→
 70→  switch (resolvedCommand) {
 71→    case "serve": {
 72→      const { values } = parseArgs({
 73→        args: commandArgs,
