#!/usr/bin/env node

/**
 * Deus CLI — run Deus IDE from the command line.
 *
 * Smart default:
 *   deus              On a desktop → launch app (install if needed)
 *                     On a server  → start headless with web UI
 *
 * Explicit commands:
 *   deus serve        Start headless server with web UI
 *   deus desktop      Download and install the desktop app
 */

import { parseArgs } from "node:util";
import { serve } from "./serve.js";
import { installDesktop, hasDisplay, findInstalledApp, launchDesktop } from "./desktop.js";
import { banner, c, blank, info, hint, success, error } from "./ui.js";

function printHelp(version: string) {
  banner(version);
  console.log(`  ${c.bold("Usage:")}   deus ${c.dim("[command] [options]")}`);
  blank();
  console.log(`  ${c.bold("Commands:")}`);
  console.log(`    ${c.dim("(none)")}        Auto-detect: launch desktop app or start server`);
  console.log(`    ${c.cyan("serve")}        Start server with web UI ${c.dim("(headless)")}`);
  console.log(`    ${c.cyan("desktop")}      Download and install the desktop app`);
  blank();
  console.log(`  ${c.bold("Options")} ${c.dim("(serve):")}`);
  console.log(`    ${c.cyan("--port, -p")}   Port for the web UI ${c.dim("(default: 3000)")}`);
  console.log(`    ${c.cyan("--host")}       Host to bind to ${c.dim("(default: localhost)")}`);
  console.log(`    ${c.cyan("--open")}       Open browser after starting`);
  console.log(`    ${c.cyan("--data-dir")}   Directory for database and data files`);
  blank();
  console.log(`  ${c.bold("Examples:")}`);
  console.log(`    ${c.dim("$")} deus                    ${c.dim("# auto-detect mode")}`);
  console.log(`    ${c.dim("$")} deus serve -p 8080      ${c.dim("# server on port 8080")}`);
  console.log(`    ${c.dim("$")} deus serve --open       ${c.dim("# server + open browser")}`);
  console.log(`    ${c.dim("$")} deus desktop            ${c.dim("# install desktop app")}`);
  blank();
}

async function main() {
  const args = process.argv.slice(2);
  const command = args[0] && !args[0].startsWith("-") ? args[0] : null;
  const commandArgs = command ? args.slice(1) : args;

  // Load version once
  const pkg = await import("../package.json", { with: { type: "json" } });
  const version = pkg.default.version;

  // Version (plain output, no banner)
  if (args.includes("--version") || args.includes("-v")) {
    console.log(version);
    process.exit(0);
  }

  // Help
  if (command === "help" || args.includes("--help") || args.includes("-h")) {
    printHelp(version);
    process.exit(0);
  }

  // Show banner
  banner(version);

  // Resolve command
  const resolvedCommand = command ?? autoDetect();

  switch (resolvedCommand) {
    case "serve": {
      const { values } = parseArgs({
        args: commandArgs,
        options: {
          port: { type: "string", short: "p", default: "3000" },
          host: { type: "string", default: "localhost" },
          open: { type: "boolean", default: false },
          "data-dir": { type: "string" },
        },
        strict: false,
      });

      await serve({
        port: parseInt(values.port as string, 10),
        host: values.host as string,
        open: values.open as boolean,
        dataDir: values["data-dir"] as string | undefined,
      });
      break;
    }

    case "desktop": {
      // Check if already installed — just launch
      const installedPath = findInstalledApp();
      if (installedPath) {
        success(`Deus is installed at ${c.dim(installedPath)}`);
        blank();
        launchDesktop(installedPath);
        success("Deus is launching!");
        blank();
        return;
      }

      const { values } = parseArgs({
        args: commandArgs,
        options: {
          version: { type: "string", default: "latest" },
        },
        strict: false,
      });

      await installDesktop({ version: values.version as string });
      break;
    }

    default:
      error(`Unknown command: ${c.bold(resolvedCommand)}`);
      blank();
      hint(`Run ${c.cyan("deus --help")} to see available commands.`);
      blank();
      process.exit(1);
  }
}

/**
 * Auto-detect the best mode based on environment.
 */
function autoDetect(): "serve" | "desktop" {
  if (!hasDisplay()) {
    info("No display detected " + c.dim("— starting in server mode"));
    blank();
    return "serve";
  }

  const installedPath = findInstalledApp();
  if (installedPath) {
    return "desktop";
  }

  info("Desktop environment detected " + c.dim("— installing Deus app"));
  blank();
  return "desktop";
}

main().catch((err) => {
  blank();
  error(`${err.message || err}`);
  blank();
  process.exit(1);
});

