  1→/**
  2→ * Headless serve mode — starts agent-server, backend, and serves the web UI.
  3→ *
  4→ * Process orchestration mirrors scripts/dev.sh but in production mode:
  5→ * 1. Start agent-server → capture LISTEN_URL from stdout
  6→ * 2. Start backend with AGENT_SERVER_URL → capture [BACKEND_PORT] from stdout
  7→ * 3. Serve static frontend files, proxying /api and /ws to backend
  8→ */
  9→
 10→import { spawn, execSync, type ChildProcess } from "node:child_process";
 11→import { createServer, request as httpRequest } from "node:http";
 12→import { readFileSync, existsSync, statSync } from "node:fs";
 13→import { join, resolve, extname, dirname } from "node:path";
 14→import { fileURLToPath } from "node:url";
 15→import { platform, homedir, networkInterfaces } from "node:os";
 16→import { mkdirSync } from "node:fs";
 17→import {
 18→  spinner as createSpinner,
 19→  c,
 20→  sym,
 21→  box,
 22→  divider,
 23→  kv,
 24→  blank,
 25→  success,
 26→  error,
 27→  warn,
 28→  hint,
 29→} from "./ui.js";
 30→
 31→const __filename = fileURLToPath(import.meta.url);
 32→const __dirname = dirname(__filename);
 33→
 34→const MIME_TYPES: Record<string, string> = {
 35→  ".html": "text/html",
 36→  ".js": "application/javascript",
 37→  ".mjs": "application/javascript",
 38→  ".css": "text/css",
 39→  ".json": "application/json",
 40→  ".png": "image/png",
 41→  ".jpg": "image/jpeg",
 42→  ".jpeg": "image/jpeg",
 43→  ".gif": "image/gif",
 44→  ".svg": "image/svg+xml",
 45→  ".ico": "image/x-icon",
 46→  ".woff": "font/woff",
 47→  ".woff2": "font/woff2",
 48→  ".ttf": "font/ttf",
 49→  ".map": "application/json",
 50→};
 51→
 52→export interface ServeOptions {
 53→  port: number;
 54→  host: string;
 55→  open: boolean;
 56→  dataDir?: string;
 57→}
 58→
 59→interface ProcessInfo {
 60→  process: ChildProcess;
 61→  name: string;
 62→}
 63→
 64→export async function serve(options: ServeOptions): Promise<void> {
 65→  const { port, host, open, dataDir } = options;
 66→
 67→  // Resolve paths to bundles
 68→  const paths = resolveBundlePaths();
 69→  if (!paths) {
 70→    error("Could not find Deus bundles.");
 71→    blank();
 72→    hint(`Run ${c.cyan("bun run build:cli")} from the monorepo root first.`);
 73→    blank();
 74→    process.exit(1);
 75→  }
 76→
 77→  // Resolve Node binary (handles Electron ABI mismatch in dev)
 78→  const nodeCmd = resolveNodeBinary();
 79→
 80→  // Resolve database
 81→  const dbPath = resolveDataDir(dataDir);
 82→  kv("Database", c.dim(dbPath));
 83→  blank();
 84→
 85→  // Track child processes for cleanup
 86→  const children: ProcessInfo[] = [];
 87→
 88→  function shutdown() {
 89→    blank();
 90→    hint("Shutting down...");
 91→    for (const child of children) {
 92→      if (!child.process.killed) child.process.kill("SIGTERM");
 93→    }
 94→    process.exit(0);
 95→  }
 96→  process.on("SIGINT", shutdown);
 97→  process.on("SIGTERM", shutdown);
 98→
 99→  // ── Step 1: Agent server ─────────────────────────────────────────
100→  const s1 = createSpinner("Starting agent server...");
101→  const agentServerUrl = await startProcess({
102→    name: "agent-server",
103→    command: nodeCmd,
104→    args: [paths.agentServer],
105→    env: { DATABASE_PATH: dbPath },
106→    waitFor: /LISTEN_URL=(.+)/,
107→    children,
108→  });
109→
110→  if (!agentServerUrl) {
111→    s1.fail("Agent server failed to start");
112→    blank();
113→    process.exit(1);
114→  }
115→  s1.succeed(`Agent server ${c.dim("ready")}`);
116→
117→  // ── Step 2: Backend ──────────────────────────────────────────────
118→  const s2 = createSpinner("Starting backend...");
119→  const backendPort = await startProcess({
120→    name: "backend",
121→    command: nodeCmd,
122→    args: [paths.backend],
123→    env: {
124→      AGENT_SERVER_URL: agentServerUrl,
125→      DATABASE_PATH: dbPath,
126→      PORT: "0",
127→    },
128→    waitFor: /\[BACKEND_PORT\](\d+)/,
129→    children,
130→  });
131→
132→  if (!backendPort) {
133→    s2.fail("Backend failed to start");
134→    blank();
135→    process.exit(1);
136→  }
137→  s2.succeed(`Backend ${c.dim("ready")}`);
138→
139→  // ── Step 3: Web server ───────────────────────────────────────────
140→  const hasFrontend = existsSync(paths.frontend) && existsSync(join(paths.frontend, "index.html"));
141→
142→  const s3 = createSpinner("Starting web server...");
143→  const webServer = createWebServer(parseInt(backendPort, 10), paths.frontend);
144→
145→  await new Promise<void>((resolve) => {
146→    webServer.listen(port, host, () => resolve());
147→  });
148→
149→  if (hasFrontend) {
150→    s3.succeed(`Web UI ${c.dim("ready")}`);
151→  } else {
152→    s3.warn(`Web UI ${c.dim("— frontend not built, API-only mode")}`);
153→  }
154→
155→  // ── Ready! ───────────────────────────────────────────────────────
156→  blank();
157→
158→  const url = `http://${host === "0.0.0.0" ? "localhost" : host}:${port}`;
159→  box([c.bold(c.brightWhite(url))], { borderColor: c.cyan, width: 36 });
160→
161→  blank();
162→  kv("Local", c.cyan(url), 10);
163→
164→  // Show network URL if binding to all interfaces or a specific host
165→  const lanIp = getLanIp();
166→  if (lanIp && (host === "0.0.0.0" || host === "localhost")) {
167→    kv("Network", c.dim(`http://${lanIp}:${port}`), 10);
168→  }
169→
170→  blank();
171→  divider("Remote Access");
172→  blank();
173→  hint("To access from your phone or another computer:");
174→  blank();
175→  console.log(`    1. Open  ${c.cyan(c.underline("app.rundeus.com"))}`);
176→  console.log(`    2. Pair your device with this server`);
177→  blank();
178→  hint(`Or enable remote access in Settings ${sym.arrow} Remote Access`);
179→  blank();
180→  divider();
181→  blank();
182→  hint(`Press ${c.dim("Ctrl+C")} to stop`);
183→  blank();
184→
185→  if (open) {
186→    openBrowser(url);
187→  }
188→
189→  // Keep the process alive
190→  await new Promise(() => {});
191→}
192→
193→// ── Bundle resolution ────────────────────────────────────────────────
194→
195→function resolveBundlePaths(): {
196→  agentServer: string;
197→  backend: string;
198→  frontend: string;
199→} | null {
200→  const cliRoot = resolve(__dirname, "..");
201→
202→  // Bundled mode (npm package)
203→  const bundledDir = join(cliRoot, "bundles");
204→  if (existsSync(join(bundledDir, "agent-server.bundled.cjs"))) {
205→    return {
206→      agentServer: join(bundledDir, "agent-server.bundled.cjs"),
207→      backend: join(bundledDir, "server.bundled.cjs"),
208→      frontend: join(bundledDir, "web"),
209→    };
210→  }
211→
212→  // Dev mode (monorepo)
213→  const monorepoRoot = resolve(cliRoot, "../..");
214→  const agentServer = join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs");
215→  const backend = join(monorepoRoot, "apps/backend/dist/server.bundled.cjs");
216→  const frontend = join(monorepoRoot, "apps/web/dist/web");
217→
218→  if (existsSync(agentServer) && existsSync(backend)) {
219→    return { agentServer, backend, frontend };
220→  }
221→
222→  return null;
223→}
224→
225→// ── Data directory ───────────────────────────────────────────────────
226→
227→function resolveDataDir(customDir?: string): string {
228→  if (customDir) {
229→    mkdirSync(customDir, { recursive: true });
230→    return join(customDir, "deus.db");
231→  }
232→
233→  const os = platform();
234→  let dir: string;
235→
236→  if (os === "darwin") {
237→    dir = join(homedir(), "Library/Application Support/com.deus.app");
238→  } else if (os === "win32") {
239→    dir = join(process.env.APPDATA || join(homedir(), "AppData/Roaming"), "com.deus.app");
240→  } else {
241→    dir = join(process.env.XDG_DATA_HOME || join(homedir(), ".local/share"), "deus");
242→  }
243→
244→  mkdirSync(dir, { recursive: true });
245→  return join(dir, "deus.db");
246→}
247→
248→// ── Node binary resolution ───────────────────────────────────────────
249→
250→function resolveNodeBinary(): string {
251→  if (process.env.ELECTRON_RUN_AS_NODE === "1") return process.execPath;
252→
253→  try {
254→    const electronPath = execSync(
255→      'node -e "try { console.log(require(\'electron\')) } catch { process.exit(1) }"',
256→      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
257→    ).trim();
258→
259→    if (electronPath && existsSync(electronPath)) {
260→      try {
261→        execSync(
262→          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
263→          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
264→        );
265→        return process.execPath;
266→      } catch {
267→        return electronPath;
268→      }
269→    }
270→  } catch {}
271→
272→  return process.execPath;
273→}
274→
275→// ── Process spawner ──────────────────────────────────────────────────
276→
277→async function startProcess(opts: {
278→  name: string;
279→  command: string;
280→  args: string[];
281→  env: Record<string, string>;
282→  waitFor: RegExp;
283→  children: ProcessInfo[];
284→  timeoutMs?: number;
285→}): Promise<string | null> {
286→  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
287→
288→  return new Promise((resolve) => {
289→    const extraEnv: Record<string, string> = {};
290→    if (command !== process.execPath && command.includes("Electron")) {
291→      extraEnv.ELECTRON_RUN_AS_NODE = "1";
292→    }
293→
294→    const child = spawn(command, args, {
295→      stdio: ["ignore", "pipe", "pipe"],
296→      env: { ...process.env, ...extraEnv, ...env },
297→    });
298→
299→    children.push({ process: child, name });
300→
301→    let buffer = "";
302→    let resolved = false;
303→
304→    const timeout = setTimeout(() => {
305→      if (!resolved) {
306→        resolved = true;
307→        resolve(null);
308→      }
309→    }, timeoutMs);
310→
311→    child.stdout?.on("data", (data: Buffer) => {
312→      buffer += data.toString();
313→      const match = buffer.match(waitFor);
314→      if (match && !resolved) {
315→        resolved = true;
316→        clearTimeout(timeout);
317→        resolve(match[1]);
318→      }
319→    });
320→
321→    child.stderr?.on("data", () => {
322→      // Suppress stderr in normal mode
323→    });
324→
325→    child.on("exit", (code, signal) => {
326→      if (!resolved) {
327→        resolved = true;
328→        clearTimeout(timeout);
329→        resolve(null);
330→      }
331→    });
332→  });
333→}
334→
335→// ── Web server (static + proxy) ──────────────────────────────────────
336→
337→function createWebServer(backendPort: number, frontendDir: string) {
338→  const hasFrontend = existsSync(frontendDir) && existsSync(join(frontendDir, "index.html"));
339→
340→  const server = createServer(async (req, res) => {
341→    const url = req.url || "/";
342→
343→    if (url.startsWith("/api/") || url.startsWith("/api")) {
344→      return proxyRequest(req, res, backendPort);
345→    }
346→
347→    if (url === "/__backend_port") {
348→      res.writeHead(200, {
349→        "Content-Type": "application/json",
350→        "Access-Control-Allow-Origin": "*",
351→      });
352→      res.end(JSON.stringify({ port: backendPort }));
353→      return;
354→    }
355→
356→    if (hasFrontend) {
357→      serveStaticFile(req, res, frontendDir);
358→    } else {
359→      res.writeHead(200, { "Content-Type": "text/html" });
360→      res.end(`<!DOCTYPE html><html><head><title>Deus IDE</title>
361→<style>body{font-family:system-ui;padding:3rem;background:#0a0a0a;color:#e5e5e5}
362→code{background:#1a1a1a;padding:2px 6px;border-radius:4px;font-size:14px}
363→a{color:#22d3ee}</style></head><body>
364→<h1>Deus IDE Server</h1>
365→<p>Backend API: <code>http://localhost:${backendPort}/api</code></p>
366→<p>WebSocket: <code>ws://localhost:${backendPort}/ws</code></p>
367→<p style="color:#a3a3a3">Frontend not built. Run <code>bun run build:web</code> to enable the UI.</p>
368→</body></html>`);
369→    }
370→  });
371→
372→  server.on("upgrade", (req, socket, head) => {
373→    const proxyReq = httpRequest({
374→      hostname: "localhost",
375→      port: backendPort,
376→      path: req.url,
377→      method: req.method,
378→      headers: req.headers,
379→    });
380→
381→    proxyReq.on("upgrade", (_proxyRes: any, proxySocket: any, proxyHead: any) => {
382→      socket.write(
383→        "HTTP/1.1 101 Switching Protocols\r\n" +
384→          Object.entries(_proxyRes.headers)
385→            .map(([k, v]: [string, any]) => `${k}: ${v}`)
386→            .join("\r\n") +
387→          "\r\n\r\n"
388→      );
389→      if (proxyHead.length > 0) socket.write(proxyHead);
390→      proxySocket.pipe(socket);
391→      socket.pipe(proxySocket);
392→    });
393→
394→    proxyReq.on("error", () => socket.end());
395→    proxyReq.end();
396→  });
397→
398→  return server;
399→}
400→
401→function proxyRequest(
402→  req: import("node:http").IncomingMessage,
403→  res: import("node:http").ServerResponse,
404→  backendPort: number
405→) {
406→  const proxyReq = httpRequest(
407→    {
408→      hostname: "localhost",
409→      port: backendPort,
410→      path: req.url,
411→      method: req.method,
412→      headers: { ...req.headers, host: `localhost:${backendPort}` },
413→    },
414→    (proxyRes) => {
415→      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
416→      proxyRes.pipe(res);
417→    }
418→  );
419→
420→  proxyReq.on("error", () => {
421→    res.writeHead(502, { "Content-Type": "application/json" });
422→    res.end(JSON.stringify({ error: "Backend unavailable" }));
423→  });
424→
425→  req.pipe(proxyReq);
426→}
427→
428→function serveStaticFile(
429→  req: import("node:http").IncomingMessage,
430→  res: import("node:http").ServerResponse,
431→  frontendDir: string
432→) {
433→  let pathname = (req.url || "/").split("?")[0];
434→  if (pathname === "/") pathname = "/index.html";
435→
436→  let filePath = join(frontendDir, pathname);
437→
438→  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
439→    filePath = join(frontendDir, "index.html");
440→  }
441→
442→  if (!existsSync(filePath)) {
443→    res.writeHead(404);
444→    res.end("Not found");
445→    return;
446→  }
447→
448→  const ext = extname(filePath);
449→  const contentType = MIME_TYPES[ext] || "application/octet-stream";
450→
451→  try {
452→    const content = readFileSync(filePath);
453→    res.writeHead(200, {
454→      "Content-Type": contentType,
455→      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
456→    });
457→    res.end(content);
458→  } catch {
459→    res.writeHead(500);
460→    res.end("Internal server error");
461→  }
462→}
463→
464→// ── Utilities ────────────────────────────────────────────────────────
465→
466→function getLanIp(): string | null {
467→  const nets = networkInterfaces();
468→  for (const ifaces of Object.values(nets)) {
469→    for (const iface of ifaces ?? []) {
470→      if (iface.family === "IPv4" && !iface.internal) {
