/**
 * Headless serve mode — starts agent-server, backend, and serves the web UI.
 *
 * Process orchestration mirrors scripts/dev.sh but in production mode:
 * 1. Start agent-server → capture LISTEN_URL from stdout
 * 2. Start backend with AGENT_SERVER_URL → capture [BACKEND_PORT] from stdout
 * 3. Serve static frontend files, proxying /api and /ws to backend
 */

import { spawn, execSync, type ChildProcess } from "node:child_process";
import { createServer, request as httpRequest } from "node:http";
import { readFileSync, existsSync, statSync } from "node:fs";
import { join, resolve, extname, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { platform, homedir, networkInterfaces } from "node:os";
import { mkdirSync } from "node:fs";
import {
  spinner as createSpinner,
  c,
  sym,
  box,
  divider,
  kv,
  blank,
  success,
  error,
  warn,
  hint,
} from "./ui.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const MIME_TYPES: Record<string, string> = {
  ".html": "text/html",
  ".js": "application/javascript",
  ".mjs": "application/javascript",
  ".css": "text/css",
  ".json": "application/json",
  ".png": "image/png",
  ".jpg": "image/jpeg",
  ".jpeg": "image/jpeg",
  ".gif": "image/gif",
  ".svg": "image/svg+xml",
  ".ico": "image/x-icon",
  ".woff": "font/woff",
  ".woff2": "font/woff2",
  ".ttf": "font/ttf",
  ".map": "application/json",
};

export interface ServeOptions {
  port: number;
  host: string;
  open: boolean;
  dataDir?: string;
}

interface ProcessInfo {
  process: ChildProcess;
  name: string;
}

export async function serve(options: ServeOptions): Promise<void> {
  const { port, host, open, dataDir } = options;

  // Resolve paths to bundles
  const paths = resolveBundlePaths();
  if (!paths) {
    error("Could not find Deus bundles.");
    blank();
    hint(`Run ${c.cyan("bun run build:cli")} from the monorepo root first.`);
    blank();
    process.exit(1);
  }

  // Resolve Node binary (handles Electron ABI mismatch in dev)
  const nodeCmd = resolveNodeBinary();

  // Resolve database
  const dbPath = resolveDataDir(dataDir);
  kv("Database", c.dim(dbPath));
  blank();

  // Track child processes for cleanup
  const children: ProcessInfo[] = [];

  function shutdown() {
    blank();
    hint("Shutting down...");
    for (const child of children) {
      if (!child.process.killed) child.process.kill("SIGTERM");
    }
    process.exit(0);
  }
  process.on("SIGINT", shutdown);
  process.on("SIGTERM", shutdown);

  // ── Step 1: Agent server ─────────────────────────────────────────
  const s1 = createSpinner("Starting agent server...");
  const agentServerUrl = await startProcess({
    name: "agent-server",
    command: nodeCmd,
    args: [paths.agentServer],
    env: { DATABASE_PATH: dbPath },
    waitFor: /LISTEN_URL=(.+)/,
    children,
  });

  if (!agentServerUrl) {
    s1.fail("Agent server failed to start");
    blank();
    process.exit(1);
  }
  s1.succeed(`Agent server ${c.dim("ready")}`);

  // ── Step 2: Backend ──────────────────────────────────────────────
  const s2 = createSpinner("Starting backend...");
  const backendPort = await startProcess({
    name: "backend",
    command: nodeCmd,
    args: [paths.backend],
    env: {
      AGENT_SERVER_URL: agentServerUrl,
      DATABASE_PATH: dbPath,
      PORT: "0",
    },
    waitFor: /\[BACKEND_PORT\](\d+)/,
    children,
  });

  if (!backendPort) {
    s2.fail("Backend failed to start");
    blank();
    process.exit(1);
  }
  s2.succeed(`Backend ${c.dim("ready")}`);

  // ── Step 3: Web server ───────────────────────────────────────────
  const hasFrontend = existsSync(paths.frontend) && existsSync(join(paths.frontend, "index.html"));

  const s3 = createSpinner("Starting web server...");
  const webServer = createWebServer(parseInt(backendPort, 10), paths.frontend);

  await new Promise<void>((resolve) => {
    webServer.listen(port, host, () => resolve());
  });

  if (hasFrontend) {
    s3.succeed(`Web UI ${c.dim("ready")}`);
  } else {
    s3.warn(`Web UI ${c.dim("— frontend not built, API-only mode")}`);
  }

  // ── Ready! ───────────────────────────────────────────────────────
  blank();

  const url = `http://${host === "0.0.0.0" ? "localhost" : host}:${port}`;
  box([c.bold(c.brightWhite(url))], { borderColor: c.cyan, width: 36 });

  blank();
  kv("Local", c.cyan(url), 10);

  // Show network URL if binding to all interfaces or a specific host
  const lanIp = getLanIp();
  if (lanIp && (host === "0.0.0.0" || host === "localhost")) {
    kv("Network", c.dim(`http://${lanIp}:${port}`), 10);
  }

  blank();
  divider("Remote Access");
  blank();
  hint("To access from your phone or another computer:");
  blank();
  console.log(`    1. Open  ${c.cyan(c.underline("app.rundeus.com"))}`);
  console.log(`    2. Pair your device with this server`);
  blank();
  hint(`Or enable remote access in Settings ${sym.arrow} Remote Access`);
  blank();
  divider();
  blank();
  hint(`Press ${c.dim("Ctrl+C")} to stop`);
  blank();

  if (open) {
    openBrowser(url);
  }

  // Keep the process alive
  await new Promise(() => {});
}

// ── Bundle resolution ────────────────────────────────────────────────

function resolveBundlePaths(): {
  agentServer: string;
  backend: string;
  frontend: string;
} | null {
  const cliRoot = resolve(__dirname, "..");

  // Bundled mode (npm package)
  const bundledDir = join(cliRoot, "bundles");
  if (existsSync(join(bundledDir, "agent-server.bundled.cjs"))) {
    return {
      agentServer: join(bundledDir, "agent-server.bundled.cjs"),
      backend: join(bundledDir, "server.bundled.cjs"),
      frontend: join(bundledDir, "web"),
    };
  }

  // Dev mode (monorepo)
  const monorepoRoot = resolve(cliRoot, "../..");
  const agentServer = join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs");
  const backend = join(monorepoRoot, "apps/backend/dist/server.bundled.cjs");
  const frontend = join(monorepoRoot, "apps/web/dist/web");

  if (existsSync(agentServer) && existsSync(backend)) {
    return { agentServer, backend, frontend };
  }

  return null;
}

// ── Data directory ───────────────────────────────────────────────────

function resolveDataDir(customDir?: string): string {
  if (customDir) {
    mkdirSync(customDir, { recursive: true });
    return join(customDir, "deus.db");
  }

  const os = platform();
  let dir: string;

  if (os === "darwin") {
    dir = join(homedir(), "Library/Application Support/com.deus.app");
  } else if (os === "win32") {
    dir = join(process.env.APPDATA || join(homedir(), "AppData/Roaming"), "com.deus.app");
  } else {
    dir = join(process.env.XDG_DATA_HOME || join(homedir(), ".local/share"), "deus");
  }

  mkdirSync(dir, { recursive: true });
  return join(dir, "deus.db");
}

// ── Node binary resolution ───────────────────────────────────────────

function resolveNodeBinary(): string {
  if (process.env.ELECTRON_RUN_AS_NODE === "1") return process.execPath;

  try {
    const electronPath = execSync(
      'node -e "try { console.log(require(\'electron\')) } catch { process.exit(1) }"',
      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
    ).trim();

    if (electronPath && existsSync(electronPath)) {
      try {
        execSync(
          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
        );
        return process.execPath;
      } catch {
        return electronPath;
      }
    }
  } catch {}

  return process.execPath;
}

// ── Process spawner ──────────────────────────────────────────────────

async function startProcess(opts: {
  name: string;
  command: string;
  args: string[];
  env: Record<string, string>;
  waitFor: RegExp;
  children: ProcessInfo[];
  timeoutMs?: number;
}): Promise<string | null> {
  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;

  return new Promise((resolve) => {
    const extraEnv: Record<string, string> = {};
    if (command !== process.execPath && command.includes("Electron")) {
      extraEnv.ELECTRON_RUN_AS_NODE = "1";
    }

    const child = spawn(command, args, {
      stdio: ["ignore", "pipe", "pipe"],
      env: { ...process.env, ...extraEnv, ...env },
    });

    children.push({ process: child, name });

    let buffer = "";
    let resolved = false;

    const timeout = setTimeout(() => {
      if (!resolved) {
        resolved = true;
        resolve(null);
      }
    }, timeoutMs);

    child.stdout?.on("data", (data: Buffer) => {
      buffer += data.toString();
      const match = buffer.match(waitFor);
      if (match && !resolved) {
        resolved = true;
        clearTimeout(timeout);
        resolve(match[1]);
      }
    });

    child.stderr?.on("data", () => {
      // Suppress stderr in normal mode
    });

    child.on("exit", (code, signal) => {
      if (!resolved) {
        resolved = true;
        clearTimeout(timeout);
        resolve(null);
      }
    });
  });
}

// ── Web server (static + proxy) ──────────────────────────────────────

function createWebServer(backendPort: number, frontendDir: string) {
  const hasFrontend = existsSync(frontendDir) && existsSync(join(frontendDir, "index.html"));

  const server = createServer(async (req, res) => {
    const url = req.url || "/";

    if (url.startsWith("/api/") || url.startsWith("/api")) {
      return proxyRequest(req, res, backendPort);
    }

    if (url === "/__backend_port") {
      res.writeHead(200, {
        "Content-Type": "application/json",
        "Access-Control-Allow-Origin": "*",
      });
      res.end(JSON.stringify({ port: backendPort }));
      return;
    }

    if (hasFrontend) {
      serveStaticFile(req, res, frontendDir);
    } else {
      res.writeHead(200, { "Content-Type": "text/html" });
      res.end(`<!DOCTYPE html><html><head><title>Deus IDE</title>
<style>body{font-family:system-ui;padding:3rem;background:#0a0a0a;color:#e5e5e5}
code{background:#1a1a1a;padding:2px 6px;border-radius:4px;font-size:14px}
a{color:#22d3ee}</style></head><body>
<h1>Deus IDE Server</h1>
<p>Backend API: <code>http://localhost:${backendPort}/api</code></p>
<p>WebSocket: <code>ws://localhost:${backendPort}/ws</code></p>
<p style="color:#a3a3a3">Frontend not built. Run <code>bun run build:web</code> to enable the UI.</p>
</body></html>`);
    }
  });

  server.on("upgrade", (req, socket, head) => {
    const proxyReq = httpRequest({
      hostname: "localhost",
      port: backendPort,
      path: req.url,
      method: req.method,
      headers: req.headers,
    });

    proxyReq.on("upgrade", (_proxyRes: any, proxySocket: any, proxyHead: any) => {
      socket.write(
        "HTTP/1.1 101 Switching Protocols\r\n" +
          Object.entries(_proxyRes.headers)
            .map(([k, v]: [string, any]) => `${k}: ${v}`)
            .join("\r\n") +
          "\r\n\r\n"
      );
      if (proxyHead.length > 0) socket.write(proxyHead);
      proxySocket.pipe(socket);
      socket.pipe(proxySocket);
    });

    proxyReq.on("error", () => socket.end());
    proxyReq.end();
  });

  return server;
}

function proxyRequest(
  req: import("node:http").IncomingMessage,
  res: import("node:http").ServerResponse,
  backendPort: number
) {
  const proxyReq = httpRequest(
    {
      hostname: "localhost",
      port: backendPort,
      path: req.url,
      method: req.method,
      headers: { ...req.headers, host: `localhost:${backendPort}` },
    },
    (proxyRes) => {
      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
      proxyRes.pipe(res);
    }
  );

  proxyReq.on("error", () => {
    res.writeHead(502, { "Content-Type": "application/json" });
    res.end(JSON.stringify({ error: "Backend unavailable" }));
  });

  req.pipe(proxyReq);
}

function serveStaticFile(
  req: import("node:http").IncomingMessage,
  res: import("node:http").ServerResponse,
  frontendDir: string
) {
  let pathname = (req.url || "/").split("?")[0];
  if (pathname === "/") pathname = "/index.html";

  let filePath = join(frontendDir, pathname);

  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
    filePath = join(frontendDir, "index.html");
  }

  if (!existsSync(filePath)) {
    res.writeHead(404);
    res.end("Not found");
    return;
  }

  const ext = extname(filePath);
  const contentType = MIME_TYPES[ext] || "application/octet-stream";

  try {
    const content = readFileSync(filePath);
    res.writeHead(200, {
      "Content-Type": contentType,
      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
    });
    res.end(content);
  } catch {
    res.writeHead(500);
    res.end("Internal server error");
  }
}

// ── Utilities ────────────────────────────────────────────────────────

function getLanIp(): string | null {
  const nets = networkInterfaces();
  for (const ifaces of Object.values(nets)) {
    for (const iface of ifaces ?? []) {
      if (iface.family === "IPv4" && !iface.internal) {
        return iface.address;
      }
    }
  }
  return null;
}

function openBrowser(url: string) {
  const os = platform();
  const cmd = os === "darwin" ? "open" : os === "win32" ? "start" : "xdg-open";
  spawn(cmd, [url], { detached: true, stdio: "ignore" }).unref();
}

content.content:
  1→/**
  2→ * Desktop installer — downloads and installs the Electron desktop app.
  3→ *
  4→ * Fetches the latest release from GitHub, downloads the appropriate installer
  5→ * for the current platform, and runs it.
  6→ */
  7→
  8→import { execSync, spawn } from "node:child_process";
  9→import { createWriteStream, existsSync, mkdirSync, unlinkSync } from "node:fs";
 10→import { join } from "node:path";
 11→import { tmpdir, platform, arch, homedir } from "node:os";
 12→import { get } from "node:https";
 13→import { IncomingMessage } from "node:http";
 14→import {
 15→  spinner as createSpinner,
 16→  progressBar,
 17→  progressBarDone,
 18→  c,
 19→  blank,
 20→  success,
 21→  error,
 22→  warn,
 23→  hint,
 24→  kv,
 25→} from "./ui.js";
 26→
 27→const GITHUB_REPO = "zvadaadam/box-ide";
 28→
 29→const INSTALL_PATHS: Record<string, string[]> = {
 30→  darwin: ["/Applications/Deus.app", `${homedir()}/Applications/Deus.app`],
 31→  win32: [
 32→    `${process.env.LOCALAPPDATA || ""}\\Programs\\Deus\\Deus.exe`,
 33→    `${process.env.PROGRAMFILES || ""}\\Deus\\Deus.exe`,
 34→  ],
 35→  linux: [
 36→    `${homedir()}/.local/bin/Deus.AppImage`,
 37→    "/usr/local/bin/Deus.AppImage",
 38→    "/usr/bin/deus",
 39→  ],
 40→};
 41→
 42→export interface DesktopOptions {
 43→  version: string;
 44→}
 45→
 46→interface GithubRelease {
 47→  tag_name: string;
 48→  assets: { name: string; browser_download_url: string }[];
 49→}
 50→
 51→/** Check if a display/GUI is available. */
 52→export function hasDisplay(): boolean {
 53→  const os = platform();
 54→  if (process.env.CI || process.env.DOCKER || existsSync("/.dockerenv")) return false;
 55→  if (os === "darwin") return true;
 56→  if (os === "win32") return !process.env.SSH_CONNECTION;
 57→  if (os === "linux") return !!(process.env.DISPLAY || process.env.WAYLAND_DISPLAY);
 58→  return false;
 59→}
 60→
 61→/** Check if the desktop app is already installed. */
 62→export function findInstalledApp(): string | null {
 63→  const os = platform();
 64→  const paths = INSTALL_PATHS[os] || [];
 65→  for (const p of paths) {
 66→    if (p && existsSync(p)) return p;
 67→  }
 68→  return null;
 69→}
 70→
 71→/** Launch an already-installed desktop app. */
 72→export function launchDesktop(appPath: string): void {
 73→  const os = platform();
 74→  switch (os) {
 75→    case "darwin":
 76→      spawn("open", [appPath], { detached: true, stdio: "ignore" }).unref();
 77→      break;
 78→    case "win32":
 79→    case "linux":
 80→      spawn(appPath, [], { detached: true, stdio: "ignore" }).unref();
 81→      break;
 82→  }
 83→}
 84→
 85→export async function installDesktop(options: DesktopOptions): Promise<void> {
 86→  const { version } = options;
 87→  const os = platform();
 88→  const cpuArch = arch();
 89→
 90→  // Determine which asset to download
 91→  const assetPattern = getAssetPattern(os, cpuArch);
 92→  if (!assetPattern) {
 93→    error(`Unsupported platform: ${os} ${cpuArch}`);
 94→    blank();
 95→    hint("Supported: macOS (arm64/x64), Windows (x64), Linux (x64)");
 96→    hint(`Or run ${c.cyan("deus serve")} to use the web version instead.`);
 97→    blank();
 98→    process.exit(1);
 99→  }
100→
101→  kv("Platform", `${os} ${cpuArch}`, 10);
102→  kv("Package", c.dim(assetPattern.description), 10);
103→  blank();
104→
105→  // Fetch release info
106→  const s1 = createSpinner("Fetching latest release...");
107→  const release = await fetchRelease(version);
108→
109→  if (!release) {
110→    s1.fail("Could not find a release on GitHub");
111→    blank();
112→    hint(`Repo: ${c.dim(GITHUB_REPO)}`);
113→    hint("Make sure the repository has published releases.");
114→    hint(`Or run ${c.cyan("deus serve")} to use the web version.`);
115→    blank();
116→    process.exit(1);
117→  }
118→
119→  s1.succeed(`Found release ${c.cyan(release.tag_name)}`);
120→
121→  // Find matching asset
122→  const asset = release.assets.find((a) => assetPattern.matcher(a.name));
123→  if (!asset) {
124→    error(`No matching installer for ${os} ${cpuArch}`);
125→    blank();
126→    hint("Available downloads:");
127→    for (const a of release.assets) {
128→      hint(`  ${a.name}`);
129→    }
130→    blank();
131→    process.exit(1);
132→  }
133→
134→  // Download
135→  const downloadDir = join(tmpdir(), "deus-installer");
136→  mkdirSync(downloadDir, { recursive: true });
137→  const downloadPath = join(downloadDir, asset.name);
138→
139→  await downloadFile(asset.browser_download_url, downloadPath);
140→
141→  // Install
142→  const s3 = createSpinner("Installing...");
143→  const installed = await installForPlatform(os, downloadPath, s3);
144→
145→  // Cleanup temp file
146→  try {
147→    unlinkSync(downloadPath);
148→  } catch {}
149→
150→  if (installed) {
151→    blank();
152→    success("Deus is ready!");
153→    blank();
154→  }
155→}
156→
157→function getAssetPattern(
158→  os: string,
159→  cpuArch: string
160→): { matcher: (name: string) => boolean; description: string } | null {
161→  switch (os) {
162→    case "darwin": {
163→      const archSuffix = cpuArch === "arm64" ? "arm64" : "x64";
164→      return {
165→        matcher: (name) => name.endsWith(".dmg") && name.includes(archSuffix),
166→        description: `macOS DMG (${archSuffix})`,
167→      };
168→    }
169→    case "win32":
170→      return {
171→        matcher: (name) => name.endsWith(".exe") && !name.includes("blockmap"),
172→        description: "Windows installer (exe)",
173→      };
174→    case "linux":
175→      return {
176→        matcher: (name) => name.endsWith(".AppImage"),
177→        description: "Linux AppImage",
178→      };
179→    default:
180→      return null;
181→  }
182→}
183→
184→async function fetchRelease(version: string): Promise<GithubRelease | null> {
185→  const endpoint =
186→    version === "latest"
187→      ? `https://api.github.com/repos/${GITHUB_REPO}/releases/latest`
188→      : `https://api.github.com/repos/${GITHUB_REPO}/releases/tags/${version}`;
189→
190→  return new Promise((resolve) => {
191→    get(
192→      endpoint,
193→      { headers: { "User-Agent": "deus-cli", Accept: "application/vnd.github.v3+json" } },
194→      (res) => {
195→        if (res.statusCode === 302 || res.statusCode === 301) {
196→          const loc = res.headers.location;
197→          if (loc) {
198→            get(loc, { headers: { "User-Agent": "deus-cli" } }, (r) => {
199→              collectBody(r).then((b) => {
200→                try { resolve(JSON.parse(b)); } catch { resolve(null); }
201→              });
202→            }).on("error", () => resolve(null));
203→            return;
204→          }
205→        }
206→        if (res.statusCode !== 200) { resolve(null); return; }
207→        collectBody(res).then((b) => {
208→          try { resolve(JSON.parse(b)); } catch { resolve(null); }
209→        });
210→      }
211→    ).on("error", () => resolve(null));
212→  });
213→}
214→
215→function collectBody(res: IncomingMessage): Promise<string> {
216→  return new Promise((resolve) => {
217→    let body = "";
218→    res.on("data", (chunk: Buffer) => (body += chunk.toString()));
219→    res.on("end", () => resolve(body));
220→    res.on("error", () => resolve(""));
221→  });
222→}
223→
224→async function downloadFile(url: string, dest: string): Promise<void> {
225→  return new Promise((resolve, reject) => {
226→    const download = (downloadUrl: string) => {
227→      get(downloadUrl, { headers: { "User-Agent": "deus-cli" } }, (res) => {
228→        if (res.statusCode === 302 || res.statusCode === 301) {
229→          const loc = res.headers.location;
230→          if (loc) { download(loc); return; }
231→        }
232→
233→        if (res.statusCode !== 200) {
234→          reject(new Error(`Download failed with status ${res.statusCode}`));
235→          return;
236→        }
237→
238→        const totalSize = parseInt(res.headers["content-length"] || "0", 10);
239→        let downloaded = 0;
240→
241→        const file = createWriteStream(dest);
242→        res.on("data", (chunk: Buffer) => {
243→          downloaded += chunk.length;
244→          if (totalSize > 0) {
245→            progressBar(downloaded, totalSize, formatBytes(downloaded) + " / " + formatBytes(totalSize));
246→          }
247→        });
248→        res.pipe(file);
249→        file.on("finish", () => {
250→          file.close();
251→          progressBarDone(`Downloaded ${c.dim(formatBytes(totalSize))}`);
252→          resolve();
253→        });
254→        file.on("error", reject);
