  1→/**
  2→ * Terminal UI primitives for the Deus CLI.
  3→ *
  4→ * Zero dependencies — uses raw ANSI escape codes so everything
  5→ * bundles into a single file with esbuild. Inspired by Claude Code,
  6→ * Vercel CLI, and create-next-app.
  7→ */
  8→
  9→// ── ANSI Colors ──────────────────────────────────────────────────────
 10→
 11→const ESC = "\x1b[";
 12→const RESET = `${ESC}0m`;
 13→
 14→// Check NO_COLOR / FORCE_COLOR env vars (respect user preference)
 15→const noColor = !!process.env.NO_COLOR || process.argv.includes("--no-color");
 16→
 17→function wrap(code: string, text: string): string {
 18→  if (noColor) return text;
 19→  return `${ESC}${code}m${text}${RESET}`;
 20→}
 21→
 22→export const c = {
 23→  // Modifiers
 24→  bold: (t: string) => wrap("1", t),
 25→  dim: (t: string) => wrap("2", t),
 26→  italic: (t: string) => wrap("3", t),
 27→  underline: (t: string) => wrap("4", t),
 28→
 29→  // Colors
 30→  red: (t: string) => wrap("31", t),
 31→  green: (t: string) => wrap("32", t),
 32→  yellow: (t: string) => wrap("33", t),
 33→  blue: (t: string) => wrap("34", t),
 34→  magenta: (t: string) => wrap("35", t),
 35→  cyan: (t: string) => wrap("36", t),
 36→  white: (t: string) => wrap("37", t),
 37→  gray: (t: string) => wrap("90", t),
 38→
 39→  // Bright colors
 40→  brightCyan: (t: string) => wrap("96", t),
 41→  brightWhite: (t: string) => wrap("97", t),
 42→
 43→  // Backgrounds
 44→  bgCyan: (t: string) => wrap("46", t),
 45→  bgBlue: (t: string) => wrap("44", t),
 46→
 47→  // Combos
 48→  success: (t: string) => wrap("32", t), // green
 49→  error: (t: string) => wrap("31", t), // red
 50→  warn: (t: string) => wrap("33", t), // yellow
 51→  info: (t: string) => wrap("36", t), // cyan
 52→  label: (t: string) => wrap("1;36", t), // bold cyan
 53→};
 54→
 55→// True-color (24-bit) foreground
 56→function rgb(r: number, g: number, b: number, text: string): string {
 57→  if (noColor) return text;
 58→  return `\x1b[38;2;${r};${g};${b}m${text}${RESET}`;
 59→}
 60→
 61→// ── Symbols ──────────────────────────────────────────────────────────
 62→
 63→// Unicode symbols with ASCII fallbacks for limited terminals
 64→const isUnicode = process.platform !== "win32" || !!process.env.WT_SESSION;
 65→
 66→export const sym = {
 67→  tick: isUnicode ? "✓" : "√",
 68→  cross: isUnicode ? "✗" : "×",
 69→  dot: isUnicode ? "●" : "*",
 70→  dash: isUnicode ? "─" : "-",
 71→  arrow: isUnicode ? "→" : "->",
 72→  diamond: isUnicode ? "◆" : "*",
 73→  pointer: isUnicode ? "❯" : ">",
 74→  info: isUnicode ? "ℹ" : "i",
 75→  warning: isUnicode ? "⚠" : "!",
 76→  bullet: isUnicode ? "•" : "-",
 77→
 78→  // Box drawing
 79→  tl: isUnicode ? "╭" : "+",
 80→  tr: isUnicode ? "╮" : "+",
 81→  bl: isUnicode ? "╰" : "+",
 82→  br: isUnicode ? "╯" : "+",
 83→  h: isUnicode ? "─" : "-",
 84→  v: isUnicode ? "│" : "|",
 85→};
 86→
 87→// ── Logo / Banner ────────────────────────────────────────────────────
 88→
 89→// DEUS in block characters (ANSI Shadow style), per-letter for gradient coloring
 90→const LOGO_D = [
 91→  "██████╗ ",
 92→  "██╔══██╗",
 93→  "██║  ██║",
 94→  "██║  ██║",
 95→  "██████╔╝",
 96→  "╚═════╝ ",
 97→];
 98→const LOGO_E = [
 99→  "███████╗",
100→  "██╔════╝",
101→  "█████╗  ",
102→  "██╔══╝  ",
103→  "███████╗",
104→  "╚══════╝",
105→];
106→const LOGO_U = [
107→  "██╗   ██╗",
108→  "██║   ██║",
109→  "██║   ██║",
110→  "██║   ██║",
111→  "╚██████╔╝",
112→  " ╚═════╝ ",
113→];
114→const LOGO_S = [
115→  "███████╗",
116→  "██╔════╝",
117→  "███████╗",
118→  "╚════██║",
119→  "███████║",
120→  "╚══════╝",
121→];
122→
123→// Gradient for block chars (█): violet → indigo → blue → cyan
124→const LOGO_BLOCK: [number, number, number][] = [
125→  [167, 139, 250],
126→  [129, 140, 248],
127→  [96, 165, 250],
128→  [34, 211, 238],
129→];
130→
131→// Shadow for border chars (╔═╗║╚╝) in rows 0-4
132→const LOGO_INNER: [number, number, number][] = [
133→  [100, 83, 150],
134→  [77, 84, 149],
135→  [58, 99, 150],
136→  [20, 127, 143],
137→];
138→
139→// Extra-dim shadow for the bottom row (╚═╝)
140→const LOGO_FLOOR: [number, number, number][] = [
141→  [60, 50, 90],
142→  [46, 50, 89],
143→  [35, 59, 90],
144→  [12, 76, 86],
145→];
146→
147→const SHADOW_CHARS = new Set("╔═╗║╚╝╬╠╣╦╩╓╖╙╜╒╕╘╛┌┐└┘┬┴├┤┼─│");
148→
149→/** Color a logo row: block chars in main color, shadow chars in dim */
150→function colorLogo(
151→  text: string,
152→  block: [number, number, number],
153→  shadow: [number, number, number]
154→): string {
155→  let result = "";
156→  let buf = "";
157→  let cur: "b" | "s" | " " | null = null;
158→
159→  function flush() {
160→    if (!buf) return;
161→    if (cur === "b") result += rgb(block[0], block[1], block[2], buf);
162→    else if (cur === "s") result += rgb(shadow[0], shadow[1], shadow[2], buf);
163→    else result += buf;
164→    buf = "";
165→  }
166→
167→  for (const ch of text) {
168→    const t = ch === " " ? " " : SHADOW_CHARS.has(ch) ? "s" : "b";
169→    if (t !== cur) {
170→      flush();
171→      cur = t;
172→    }
173→    buf += ch;
174→  }
175→  flush();
176→  return result;
177→}
178→
179→// ASCII fallback for limited terminals
180→const LOGO_ASCII = [
181→  "  DDDD   EEEEE  U   U  SSSS ",
182→  "  D   D  E      U   U  S    ",
183→  "  D   D  EEE    U   U   SS  ",
184→  "  D   D  E      U   U     S ",
185→  "  DDDD   EEEEE  UUUUU  SSSS ",
186→];
187→
188→export function banner(version?: string): void {
189→  const letters = [LOGO_D, LOGO_E, LOGO_U, LOGO_S];
190→
191→  console.log("");
192→
193→  if (isUnicode) {
194→    for (let row = 0; row < 6; row++) {
195→      const shadow = row === 5 ? LOGO_FLOOR : LOGO_INNER;
196→      let line = "  ";
197→      for (let l = 0; l < letters.length; l++) {
198→        line += colorLogo(letters[l][row], LOGO_BLOCK[l], shadow[l]);
199→      }
200→      console.log(line);
201→    }
202→  } else {
203→    for (const line of LOGO_ASCII) {
204→      console.log(c.cyan(line));
205→    }
206→  }
207→
208→  console.log("");
209→
210→  const tag = c.dim("  Agentic Engineering");
211→  const ver = version ? `  ${c.dim("v" + version)}` : "";
212→  console.log(tag + ver);
213→  console.log("");
214→}
215→
216→// ── Spinner ──────────────────────────────────────────────────────────
217→
218→const SPINNER_FRAMES = isUnicode
219→  ? ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"]
220→  : ["-", "\\", "|", "/"];
221→
222→const SPINNER_INTERVAL = 80;
223→
224→export interface Spinner {
225→  /** Update the spinner text while it's running */
226→  update(text: string): void;
227→  /** Stop with a success message */
228→  succeed(text?: string): void;
229→  /** Stop with a failure message */
230→  fail(text?: string): void;
231→  /** Stop with a warning message */
232→  warn(text?: string): void;
233→  /** Stop with an info message */
234→  info(text?: string): void;
235→  /** Stop and clear the line */
236→  stop(): void;
237→}
238→
239→export function spinner(text: string): Spinner {
240→  let frameIdx = 0;
241→  let currentText = text;
242→  let stopped = false;
243→
244→  const stream = process.stderr;
245→
246→  function render() {
247→    if (stopped) return;
248→    const frame = c.cyan(SPINNER_FRAMES[frameIdx % SPINNER_FRAMES.length]);
249→    stream.write(`\r${ESC}2K  ${frame} ${currentText}`);
250→    frameIdx++;
251→  }
252→
253→  const interval = setInterval(render, SPINNER_INTERVAL);
254→  render();
255→
256→  function stop(symbol: string, finalText: string) {
257→    if (stopped) return;
258→    stopped = true;
259→    clearInterval(interval);
260→    stream.write(`\r${ESC}2K  ${symbol} ${finalText}\n`);
261→  }
262→
263→  return {
264→    update(t: string) {
265→      currentText = t;
266→    },
267→    succeed(t?: string) {
268→      stop(c.green(sym.tick), t ?? currentText);
269→    },
270→    fail(t?: string) {
271→      stop(c.red(sym.cross), t ?? currentText);
272→    },
273→    warn(t?: string) {
274→      stop(c.yellow(sym.warning), t ?? currentText);
275→    },
276→    info(t?: string) {
277→      stop(c.blue(sym.info), t ?? currentText);
278→    },
279→    stop() {
280→      if (stopped) return;
281→      stopped = true;
282→      clearInterval(interval);
283→      stream.write(`\r${ESC}2K`);
284→    },
285→  };
286→}
287→
288→// ── Box ──────────────────────────────────────────────────────────────
289→
290→/** Draw a rounded box around content lines */
