  [167, 139, 250],
  [129, 140, 248],
  [96, 165, 250],
  [34, 211, 238],
];

// Shadow for border chars (╔═╗║╚╝) in rows 0-4
const LOGO_INNER: [number, number, number][] = [
  [100, 83, 150],
  [77, 84, 149],
  [58, 99, 150],
  [20, 127, 143],
];

// Extra-dim shadow for the bottom row (╚═╝)
const LOGO_FLOOR: [number, number, number][] = [
  [60, 50, 90],
  [46, 50, 89],
  [35, 59, 90],
  [12, 76, 86],
];

