  4→ * 1. Bundle the CLI TypeScript → dist/cli.js (esbuild)
  5→ * 2. Copy pre-built bundles into bundles/ for distribution:
  6→ *    - agent-server.bundled.cjs (from apps/agent-server/dist/)
  7→ *    - server.bundled.cjs (from apps/backend/dist/)
  8→ *    - web/ (from dist/web/ — built by `bun run build:web`)
  9→ *
 10→ * Prerequisites: run these from the monorepo root before building the CLI:
 11→ *   bun run build:agent-server
 12→ *   bun run build:backend
 13→ *   bun run build:web
 14→ */
 15→
 16→import { build } from "esbuild";
