 25→async function main() {
 26→  console.log("Building @deus/cli...\n");
 27→
 28→  // Step 1: Bundle CLI TypeScript
 29→  console.log("1. Bundling CLI...");
 30→  await build({
 31→    entryPoints: [join(cliDir, "src/cli.ts")],
 32→    bundle: true,
 33→    platform: "node",
 34→    target: "node20",
 35→    format: "esm",
 36→    outfile: join(cliDir, "dist/cli.js"),
 37→    external: [
 38→      // Native modules resolved at runtime
 39→      "better-sqlite3",
