 47→  });
 48→
 49→  // Step 2: Create bin/ entry point
 50→  console.log("\n2. Creating bin/deus.js...");
 51→  mkdirSync(join(cliDir, "bin"), { recursive: true });
 52→  writeFileSync(
 53→    join(cliDir, "bin/deus.js"),
 54→    `#!/usr/bin/env node\nimport "../dist/cli.js";\n`,
 55→    { mode: 0o755 }
 56→  );
 57→
 58→  // Step 3: Copy bundles for distribution
 59→  console.log("\n3. Copying bundles...");
 60→  const bundlesDir = join(cliDir, "bundles");
 61→  mkdirSync(bundlesDir, { recursive: true });
 62→
 63→  const copies: { src: string; dest: string; name: string; required: boolean }[] = [
 64→    {
 65→      src: join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs"),
 66→      dest: join(bundlesDir, "agent-server.bundled.cjs"),
 67→      name: "agent-server bundle",
 68→      required: true,
 69→    },
 70→    {
 71→      src: join(monorepoRoot, "apps/backend/dist/server.bundled.cjs"),
 72→      dest: join(bundlesDir, "server.bundled.cjs"),
