 79→      name: "frontend build",
 80→      required: false,
 81→    },
 82→  ];
 83→
 84→  let hasErrors = false;
 85→  for (const copy of copies) {
 86→    if (existsSync(copy.src)) {
 87→      cpSync(copy.src, copy.dest, { recursive: true });
 88→      console.log(`   ✓ ${copy.name}`);
 89→    } else if (copy.required) {
 90→      console.error(`   ✗ ${copy.name} not found: ${copy.src}`);
 91→      hasErrors = true;
 92→    } else {
