 94→    }
 95→  }
 96→
 97→  if (hasErrors) {
 98→    console.error("\nMissing required bundles. Run these first:");
 99→    console.error("  bun run build:agent-server");
100→    console.error("  bun run build:backend");
101→    console.error("  bun run build:web  (optional, for web UI)");
102→    process.exit(1);
103→  }
104→
105→  // Step 4: Generate a standalone package.json for the published CLI
106→  console.log("\n4. Generating publish-ready package.json...");
107→  const pkg = JSON.parse(readFileSync(join(cliDir, "package.json"), "utf-8"));
108→  // Ensure we don't ship "private: true" or monorepo-specific fields
109→  delete pkg.scripts;
110→  pkg.main = "dist/cli.js";
111→  pkg.type = "module";
112→  // Note: we don't overwrite — the original is fine for publishing
113→
114→  console.log("\n✓ Build complete!");
