269→/**
270→ * Parse simple YAML frontmatter from a SKILL.md file.
271→ * Returns key-value pairs from the --- delimited block at the top.
272→ */
273→function parseFrontmatter(content: string): { frontmatter: Record<string, string>; body: string } {
274→  const match = content.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);
275→  if (!match) return { frontmatter: {}, body: content };
276→
277→  const frontmatter: Record<string, string> = {};
278→  match[1].split("\n").forEach((line) => {
279→    const colonIdx = line.indexOf(":");
280→    if (colonIdx > 0) {
281→      const key = line.slice(0, colonIdx).trim();
282→      const value = line
283→        .slice(colonIdx + 1)
284→        .trim()
285→        .replace(/^["']|["']$/g, "");
286→      frontmatter[key] = value;
287→    }
288→  });
289→
290→  return { frontmatter, body: match[2] };
291→}
