295→  if (!fs.existsSync(skillsDir)) return [];
296→
297→  const entries = fs.readdirSync(skillsDir, { withFileTypes: true });
298→  const skills: SkillItem[] = [];
299→
300→  entries.forEach((entry) => {
301→    if (!entry.isDirectory()) return;
302→    const skillMdPath = path.join(skillsDir, entry.name, "SKILL.md");
303→    if (!fs.existsSync(skillMdPath)) return;
304→
305→    try {
306→      const content = fs.readFileSync(skillMdPath, "utf8");
307→      const { frontmatter } = parseFrontmatter(content);
308→      // Use directory name as canonical identity — frontmatter.name is display-only
309→      skills.push({
310→        name: entry.name,
311→        description: frontmatter.description || frontmatter.name || "",
312→        content,
313→      });
314→    } catch {
315→      // Skip unreadable skill directories
316→      console.error(`Failed to read skill: ${entry.name}`);
317→    }
318→  });
319→
320→  return skills;
321→}
322→
323→export function saveSkill(name: string, content: string, projectPath?: string): void {
324→  name = sanitizeName(name);
325→  const skillDir = path.join(resolveClaudeDir(projectPath), "skills", name);
326→  if (!fs.existsSync(skillDir)) {
327→    fs.mkdirSync(skillDir, { recursive: true });
328→  }
329→  fs.writeFileSync(path.join(skillDir, "SKILL.md"), content);
330→}
331→
332→export function deleteSkill(name: string, projectPath?: string): boolean {
333→  name = sanitizeName(name);
334→  const skillDir = path.join(resolveClaudeDir(projectPath), "skills", name);
335→  if (fs.existsSync(skillDir)) {
336→    fs.rmSync(skillDir, { recursive: true });
337→    return true;
338→  }
339→  return false;
340→}
