  3→ *
  4→ * Process orchestration mirrors scripts/dev.sh but in production mode:
  5→ * 1. Start agent-server → capture LISTEN_URL from stdout
  6→ * 2. Start backend with AGENT_SERVER_URL → capture [BACKEND_PORT] from stdout
  7→ * 3. Serve static frontend files, proxying /api and /ws to backend
  8→ */
  9→
 10→import { spawn, execSync, type ChildProcess } from "node:child_process";
 11→import { createServer, request as httpRequest } from "node:http";
 12→import { readFileSync, existsSync, statSync } from "node:fs";
 13→import { join, resolve, extname, dirname } from "node:path";
 14→import { fileURLToPath } from "node:url";
 15→import { platform, homedir, networkInterfaces } from "node:os";
 16→import { mkdirSync } from "node:fs";
 17→import {
 18→  spinner as createSpinner,
 19→  statusLine,
 20→  c,
 21→  sym,
 22→  box,
 23→  divider,
 24→  kv,
 25→  blank,
 26→  sleep,
 27→  success,
 28→  error,
 29→  warn,
 30→  hint,
 31→  gradientText,
 32→} from "./ui.js";
 33→
 34→const __filename = fileURLToPath(import.meta.url);
 35→const __dirname = dirname(__filename);
 36→
 37→const MIME_TYPES: Record<string, string> = {
 38→  ".html": "text/html",
 39→  ".js": "application/javascript",
 40→  ".mjs": "application/javascript",
 41→  ".css": "text/css",
 42→  ".json": "application/json",
 43→  ".png": "image/png",
 44→  ".jpg": "image/jpeg",
 45→  ".jpeg": "image/jpeg",
 46→  ".gif": "image/gif",
 47→  ".svg": "image/svg+xml",
 48→  ".ico": "image/x-icon",
 49→  ".woff": "font/woff",
 50→  ".woff2": "font/woff2",
 51→  ".ttf": "font/ttf",
 52→  ".map": "application/json",
 53→};
 54→
 55→export interface ServeOptions {
 56→  port: number;
 57→  host: string;
 58→  open: boolean;
 59→  dataDir?: string;
 60→}
 61→
 62→interface ProcessInfo {
 63→  process: ChildProcess;
 64→  name: string;
 65→}
 66→
 67→export async function serve(options: ServeOptions): Promise<void> {
 68→  const { port, host, open, dataDir } = options;
 69→
 70→  // Resolve paths to bundles
 71→  const paths = resolveBundlePaths();
 72→  if (!paths) {
 73→    error("Could not find Deus bundles.");
 74→    blank();
 75→    hint(`Run ${c.cyan("bun run build:cli")} from the monorepo root first.`);
 76→    blank();
 77→    process.exit(1);
 78→  }
 79→
 80→  // Resolve Node binary (handles Electron ABI mismatch in dev)
 81→  const nodeCmd = resolveNodeBinary();
 82→
 83→  // Resolve database
 84→  const dbPath = resolveDataDir(dataDir);
 85→  kv("Database", c.dim(dbPath));
 86→  blank();
 87→
 88→  // Track child processes for cleanup
 89→  const children: ProcessInfo[] = [];
 90→  let status: ReturnType<typeof statusLine> | null = null;
 91→
 92→  function shutdown() {
 93→    if (status) status.stop();
 94→    blank();
 95→
 96→    const msg = gradientText("Thanks for using Deus!", [167, 139, 250], [34, 211, 238]);
 97→    console.log(`  ${msg}`);
 98→    blank();
 99→
100→    for (const child of children) {
101→      if (!child.process.killed) child.process.kill("SIGTERM");
102→    }
103→    process.exit(0);
104→  }
105→  process.on("SIGINT", shutdown);
106→  process.on("SIGTERM", shutdown);
107→
108→  // ── Step 1: Agent server ─────────────────────────────────────────
109→  const s1 = createSpinner("Starting agent server...");
110→  const agentServerUrl = await startProcess({
111→    name: "agent-server",
112→    command: nodeCmd,
113→    args: [paths.agentServer],
114→    env: { DATABASE_PATH: dbPath },
115→    waitFor: /LISTEN_URL=(.+)/,
116→    children,
117→  });
118→
119→  if (!agentServerUrl) {
120→    s1.fail("Agent server failed to start");
121→    blank();
122→    process.exit(1);
123→  }
124→  s1.succeed(`Agent server ${c.dim("ready")}`);
125→
126→  // ── Step 2: Backend ──────────────────────────────────────────────
127→  const s2 = createSpinner("Starting backend...");
128→  const backendPort = await startProcess({
129→    name: "backend",
130→    command: nodeCmd,
131→    args: [paths.backend],
132→    env: {
133→      AGENT_SERVER_URL: agentServerUrl,
134→      DATABASE_PATH: dbPath,
135→      PORT: "0",
136→    },
137→    waitFor: /\[BACKEND_PORT\](\d+)/,
138→    children,
139→  });
140→
141→  if (!backendPort) {
142→    s2.fail("Backend failed to start");
143→    blank();
144→    process.exit(1);
145→  }
146→  s2.succeed(`Backend ${c.dim("ready")}`);
147→
148→  // ── Step 3: Web server ───────────────────────────────────────────
149→  const hasFrontend = existsSync(paths.frontend) && existsSync(join(paths.frontend, "index.html"));
150→
151→  const s3 = createSpinner("Starting web server...");
152→  const webServer = createWebServer(parseInt(backendPort, 10), paths.frontend);
153→
154→  await new Promise<void>((resolve) => {
155→    webServer.listen(port, host, () => resolve());
156→  });
157→
158→  if (hasFrontend) {
159→    s3.succeed(`Web UI ${c.dim("ready")}`);
160→  } else {
161→    s3.warn(`Web UI ${c.dim("— frontend not built, API-only mode")}`);
162→  }
163→
164→  // ── Ready! ───────────────────────────────────────────────────────
165→  blank();
166→
167→  const url = `http://${host === "0.0.0.0" ? "localhost" : host}:${port}`;
168→  box(
169→    [
170→      gradientText("Deus is running", [167, 139, 250], [34, 211, 238]),
171→      "",
172→      c.bold(c.brightWhite(url)),
173→    ],
174→    { borderColor: c.cyan, width: 38 }
175→  );
176→
177→  blank();
178→  kv("Local", c.cyan(url), 10);
179→
180→  // Show network URL if binding to all interfaces or a specific host
181→  const lanIp = getLanIp();
182→  if (lanIp && (host === "0.0.0.0" || host === "localhost")) {
183→    kv("Network", c.dim(`http://${lanIp}:${port}`), 10);
184→  }
185→
186→  // ── Remote Access ────────────────────────────────────────────────
187→  blank();
188→  divider("Remote Access");
189→  blank();
190→  hint("To access from your phone or another computer:");
191→  blank();
192→  console.log(`    1. Open  ${c.cyan(c.underline("app.rundeus.com"))}`);
193→  console.log(`    2. Pair your device with this server`);
194→  blank();
195→  hint(`Or enable remote access in Settings ${sym.arrow} Remote Access`);
196→  blank();
197→  divider();
198→
199→  // ── API Key Check ────────────────────────────────────────────────
200→  const hasApiKey = !!(process.env.ANTHROPIC_API_KEY || process.env.OPENAI_API_KEY);
201→  if (!hasApiKey) {
202→    blank();
203→    warn("No API key detected in environment");
204→    blank();
205→    hint("AI agents need an API key to work. Set one of:");
206→    blank();
207→    console.log(`    ${c.cyan("export ANTHROPIC_API_KEY")}=${c.dim('"sk-ant-..."')}`);
208→    console.log(`    ${c.cyan("export OPENAI_API_KEY")}=${c.dim('"sk-..."')}`);
209→    blank();
210→    hint(`Or configure it in the app: Settings ${sym.arrow} API Keys`);
211→    blank();
212→    divider();
213→  }
214→
215→  // ── Status line ──────────────────────────────────────────────────
216→  blank();
217→  const startedAt = new Date();
218→  status = statusLine(() => {
219→    const elapsed = formatUptime(Date.now() - startedAt.getTime());
220→    return `${c.dim(`Running for ${elapsed}`)}  ${c.dim(`${sym.bullet} Ctrl+C to stop`)}`;
221→  }, 2000);
222→
223→  if (open) {
224→    openBrowser(url);
225→  }
226→
227→  // Keep the process alive
228→  await new Promise(() => {});
229→}
230→
231→// ── Bundle resolution ────────────────────────────────────────────────
232→
233→function resolveBundlePaths(): {
234→  agentServer: string;
235→  backend: string;
236→  frontend: string;
237→} | null {
238→  const cliRoot = resolve(__dirname, "..");
239→
240→  // Bundled mode (npm package)
241→  const bundledDir = join(cliRoot, "bundles");
242→  if (existsSync(join(bundledDir, "agent-server.bundled.cjs"))) {
243→    return {
244→      agentServer: join(bundledDir, "agent-server.bundled.cjs"),
245→      backend: join(bundledDir, "server.bundled.cjs"),
246→      frontend: join(bundledDir, "web"),
247→    };
248→  }
249→
250→  // Dev mode (monorepo)
251→  const monorepoRoot = resolve(cliRoot, "../..");
252→  const agentServer = join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs");
253→  const backend = join(monorepoRoot, "apps/backend/dist/server.bundled.cjs");
254→  const frontend = join(monorepoRoot, "apps/web/dist/web");
255→
256→  if (existsSync(agentServer) && existsSync(backend)) {
257→    return { agentServer, backend, frontend };
258→  }
259→
260→  return null;
261→}
262→
263→// ── Data directory ───────────────────────────────────────────────────
264→
265→function resolveDataDir(customDir?: string): string {
266→  if (customDir) {
267→    mkdirSync(customDir, { recursive: true });
268→    return join(customDir, "deus.db");
269→  }
270→
271→  const os = platform();
272→  let dir: string;
273→
274→  if (os === "darwin") {
275→    dir = join(homedir(), "Library/Application Support/com.deus.app");
276→  } else if (os === "win32") {
277→    dir = join(process.env.APPDATA || join(homedir(), "AppData/Roaming"), "com.deus.app");
278→  } else {
279→    dir = join(process.env.XDG_DATA_HOME || join(homedir(), ".local/share"), "deus");
280→  }
281→
282→  mkdirSync(dir, { recursive: true });
283→  return join(dir, "deus.db");
284→}
285→
286→// ── Node binary resolution ───────────────────────────────────────────
287→
288→function resolveNodeBinary(): string {
289→  if (process.env.ELECTRON_RUN_AS_NODE === "1") return process.execPath;
290→
291→  try {
292→    const electronPath = execSync(
293→      'node -e "try { console.log(require(\'electron\')) } catch { process.exit(1) }"',
294→      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
295→    ).trim();
296→
297→    if (electronPath && existsSync(electronPath)) {
298→      try {
299→        execSync(
300→          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
301→          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
302→        );
303→        return process.execPath;
304→      } catch {
305→        return electronPath;
306→      }
307→    }
308→  } catch {}
309→
310→  return process.execPath;
311→}
312→
313→// ── Process spawner ──────────────────────────────────────────────────
314→
315→async function startProcess(opts: {
316→  name: string;
317→  command: string;
318→  args: string[];
319→  env: Record<string, string>;
320→  waitFor: RegExp;
321→  children: ProcessInfo[];
322→  timeoutMs?: number;
323→}): Promise<string | null> {
324→  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
325→
326→  return new Promise((resolve) => {
327→    const extraEnv: Record<string, string> = {};
328→    if (command !== process.execPath && command.includes("Electron")) {
329→      extraEnv.ELECTRON_RUN_AS_NODE = "1";
330→    }
331→
332→    const child = spawn(command, args, {
333→      stdio: ["ignore", "pipe", "pipe"],
334→      env: { ...process.env, ...extraEnv, ...env },
335→    });
336→
337→    children.push({ process: child, name });
338→
339→    let buffer = "";
340→    let resolved = false;
341→
342→    const timeout = setTimeout(() => {
343→      if (!resolved) {
344→        resolved = true;
345→        resolve(null);
346→      }
347→    }, timeoutMs);
348→
349→    child.stdout?.on("data", (data: Buffer) => {
350→      buffer += data.toString();
351→      const match = buffer.match(waitFor);
352→      if (match && !resolved) {
353→        resolved = true;
354→        clearTimeout(timeout);
355→        resolve(match[1]);
356→      }
357→    });
358→
359→    child.stderr?.on("data", () => {
360→      // Suppress stderr in normal mode
361→    });
362→
363→    child.on("exit", (code, signal) => {
364→      if (!resolved) {
365→        resolved = true;
366→        clearTimeout(timeout);
367→        resolve(null);
368→      }
369→    });
370→  });
371→}
372→
373→// ── Web server (static + proxy) ──────────────────────────────────────
374→
375→function createWebServer(backendPort: number, frontendDir: string) {
376→  const hasFrontend = existsSync(frontendDir) && existsSync(join(frontendDir, "index.html"));
377→
378→  const server = createServer(async (req, res) => {
379→    const url = req.url || "/";
380→
381→    if (url.startsWith("/api/") || url.startsWith("/api")) {
382→      return proxyRequest(req, res, backendPort);
383→    }
384→
385→    if (url === "/__backend_port") {
386→      res.writeHead(200, {
387→        "Content-Type": "application/json",
388→        "Access-Control-Allow-Origin": "*",
389→      });
390→      res.end(JSON.stringify({ port: backendPort }));
391→      return;
392→    }
393→
394→    if (hasFrontend) {
395→      serveStaticFile(req, res, frontendDir);
396→    } else {
397→      res.writeHead(200, { "Content-Type": "text/html" });
398→      res.end(`<!DOCTYPE html><html><head><title>Deus IDE</title>
399→<style>body{font-family:system-ui;padding:3rem;background:#0a0a0a;color:#e5e5e5}
400→code{background:#1a1a1a;padding:2px 6px;border-radius:4px;font-size:14px}
401→a{color:#22d3ee}</style></head><body>
402→<h1>Deus IDE Server</h1>
403→<p>Backend API: <code>http://localhost:${backendPort}/api</code></p>
404→<p>WebSocket: <code>ws://localhost:${backendPort}/ws</code></p>
405→<p style="color:#a3a3a3">Frontend not built. Run <code>bun run build:web</code> to enable the UI.</p>
406→</body></html>`);
407→    }
408→  });
409→
410→  server.on("upgrade", (req, socket, head) => {
411→    const proxyReq = httpRequest({
412→      hostname: "localhost",
413→      port: backendPort,
414→      path: req.url,
415→      method: req.method,
416→      headers: req.headers,
417→    });
418→
419→    proxyReq.on("upgrade", (_proxyRes: any, proxySocket: any, proxyHead: any) => {
420→      socket.write(
421→        "HTTP/1.1 101 Switching Protocols\r\n" +
422→          Object.entries(_proxyRes.headers)
423→            .map(([k, v]: [string, any]) => `${k}: ${v}`)
424→            .join("\r\n") +
425→          "\r\n\r\n"
426→      );
427→      if (proxyHead.length > 0) socket.write(proxyHead);
428→      proxySocket.pipe(socket);
429→      socket.pipe(proxySocket);
430→    });
431→
432→    proxyReq.on("error", () => socket.end());
433→    proxyReq.end();
434→  });
435→
436→  return server;
437→}
438→
439→function proxyRequest(
440→  req: import("node:http").IncomingMessage,
441→  res: import("node:http").ServerResponse,
442→  backendPort: number
443→) {
444→  const proxyReq = httpRequest(
445→    {
446→      hostname: "localhost",
447→      port: backendPort,
448→      path: req.url,
449→      method: req.method,
450→      headers: { ...req.headers, host: `localhost:${backendPort}` },
451→    },
452→    (proxyRes) => {
453→      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
454→      proxyRes.pipe(res);
455→    }
456→  );
457→
458→  proxyReq.on("error", () => {
459→    res.writeHead(502, { "Content-Type": "application/json" });
460→    res.end(JSON.stringify({ error: "Backend unavailable" }));
461→  });
462→
463→  req.pipe(proxyReq);
464→}
465→
466→function serveStaticFile(
467→  req: import("node:http").IncomingMessage,
468→  res: import("node:http").ServerResponse,
469→  frontendDir: string
470→) {
471→  let pathname = (req.url || "/").split("?")[0];
472→  if (pathname === "/") pathname = "/index.html";
473→
474→  let filePath = join(frontendDir, pathname);
475→
476→  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
477→    filePath = join(frontendDir, "index.html");
478→  }
479→
480→  if (!existsSync(filePath)) {
481→    res.writeHead(404);
482→    res.end("Not found");
483→    return;
484→  }
485→
486→  const ext = extname(filePath);
487→  const contentType = MIME_TYPES[ext] || "application/octet-stream";
488→
489→  try {
490→    const content = readFileSync(filePath);
491→    res.writeHead(200, {
492→      "Content-Type": contentType,
493→      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
494→    });
495→    res.end(content);
496→  } catch {
497→    res.writeHead(500);
498→    res.end("Internal server error");
499→  }
500→}
501→
502→// ── Utilities ────────────────────────────────────────────────────────
503→
504→function getLanIp(): string | null {
505→  const nets = networkInterfaces();
506→  for (const ifaces of Object.values(nets)) {
507→    for (const iface of ifaces ?? []) {
508→      if (iface.family === "IPv4" && !iface.internal) {
509→        return iface.address;
510→      }
511→    }
512→  }
513→  return null;
514→}
515→
516→function openBrowser(url: string) {
517→  const os = platform();
518→  const cmd = os === "darwin" ? "open" : os === "win32" ? "start" : "xdg-open";
519→  spawn(cmd, [url], { detached: true, stdio: "ignore" }).unref();
520→}
521→
522→function formatUptime(ms: number): string {
523→  const s = Math.floor(ms / 1000);
524→  if (s < 60) return `${s}s`;
525→  const m = Math.floor(s / 60);
526→  if (m < 60) return `${m}m ${s % 60}s`;
527→  const h = Math.floor(m / 60);
528→  return `${h}h ${m % 60}m`;
529→}
530→

