263→  if (bytes < 1024) return `${bytes} B`;
264→  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
265→  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
266→}
