  1→/**
  2→ * Terminal UI primitives for the Deus CLI.
  3→ *
  4→ * Zero dependencies — uses raw ANSI escape codes so everything
  5→ * bundles into a single file with esbuild. Inspired by Claude Code,
  6→ * Vercel CLI, and create-next-app.
  7→ */
  8→
  9→// ── ANSI Colors ──────────────────────────────────────────────────────
 10→
 11→const ESC = "\x1b[";
 12→const RESET = `${ESC}0m`;
 13→
 14→// Check NO_COLOR / FORCE_COLOR env vars (respect user preference)
 15→const noColor = !!process.env.NO_COLOR || process.argv.includes("--no-color");
 16→
 17→function wrap(code: string, text: string): string {
 18→  if (noColor) return text;
 19→  return `${ESC}${code}m${text}${RESET}`;
 20→}
 21→
 22→export const c = {
 23→  // Modifiers
 24→  bold: (t: string) => wrap("1", t),
 25→  dim: (t: string) => wrap("2", t),
 26→  italic: (t: string) => wrap("3", t),
 27→  underline: (t: string) => wrap("4", t),
 28→
 29→  // Colors
 30→  red: (t: string) => wrap("31", t),
 31→  green: (t: string) => wrap("32", t),
 32→  yellow: (t: string) => wrap("33", t),
 33→  blue: (t: string) => wrap("34", t),
 34→  magenta: (t: string) => wrap("35", t),
 35→  cyan: (t: string) => wrap("36", t),
 36→  white: (t: string) => wrap("37", t),
 37→  gray: (t: string) => wrap("90", t),
 38→
 39→  // Bright colors
 40→  brightCyan: (t: string) => wrap("96", t),
 41→  brightWhite: (t: string) => wrap("97", t),
 42→
 43→  // Backgrounds
 44→  bgCyan: (t: string) => wrap("46", t),
 45→  bgBlue: (t: string) => wrap("44", t),
 46→
 47→  // Combos
 48→  success: (t: string) => wrap("32", t), // green
 49→  error: (t: string) => wrap("31", t), // red
 50→  warn: (t: string) => wrap("33", t), // yellow
 51→  info: (t: string) => wrap("36", t), // cyan
 52→  label: (t: string) => wrap("1;36", t), // bold cyan
 53→};
 54→
 55→// True-color (24-bit) foreground
 56→function rgb(r: number, g: number, b: number, text: string): string {
 57→  if (noColor) return text;
 58→  return `\x1b[38;2;${r};${g};${b}m${text}${RESET}`;
 59→}
 60→
 61→// ── Symbols ──────────────────────────────────────────────────────────
 62→
 63→// Unicode symbols with ASCII fallbacks for limited terminals
 64→const isUnicode = process.platform !== "win32" || !!process.env.WT_SESSION;
 65→
 66→export const sym = {
 67→  tick: isUnicode ? "✓" : "√",
 68→  cross: isUnicode ? "✗" : "×",
 69→  dot: isUnicode ? "●" : "*",
 70→  dash: isUnicode ? "─" : "-",
 71→  arrow: isUnicode ? "→" : "->",
 72→  diamond: isUnicode ? "◆" : "*",
 73→  pointer: isUnicode ? "❯" : ">",
 74→  info: isUnicode ? "ℹ" : "i",
 75→  warning: isUnicode ? "⚠" : "!",
 76→  bullet: isUnicode ? "•" : "-",
 77→
 78→  // Box drawing
 79→  tl: isUnicode ? "╭" : "+",
 80→  tr: isUnicode ? "╮" : "+",
 81→  bl: isUnicode ? "╰" : "+",
 82→  br: isUnicode ? "╯" : "+",
 83→  h: isUnicode ? "─" : "-",
 84→  v: isUnicode ? "│" : "|",
 85→};
 86→
 87→// ── Logo / Banner ────────────────────────────────────────────────────
 88→
 89→// DEUS in block characters (ANSI Shadow style), per-letter for gradient coloring
 90→const LOGO_D = [
 91→  "██████╗ ",
 92→  "██╔══██╗",
 93→  "██║  ██║",
 94→  "██║  ██║",
 95→  "██████╔╝",
 96→  "╚═════╝ ",
 97→];
 98→const LOGO_E = [
 99→  "███████╗",
100→  "██╔════╝",
101→  "█████╗  ",
102→  "██╔══╝  ",
103→  "███████╗",
104→  "╚══════╝",
105→];
106→const LOGO_U = [
107→  "██╗   ██╗",
108→  "██║   ██║",
109→  "██║   ██║",
110→  "██║   ██║",
111→  "╚██████╔╝",
112→  " ╚═════╝ ",
113→];
114→const LOGO_S = [
115→  "███████╗",
116→  "██╔════╝",
117→  "███████╗",
118→  "╚════██║",
119→  "███████║",
120→  "╚══════╝",
121→];
122→
123→const LETTERS = [LOGO_D, LOGO_E, LOGO_U, LOGO_S];
124→
125→// Gradient for block chars (█): violet → indigo → blue → cyan
126→const LOGO_BLOCK: [number, number, number][] = [
127→  [167, 139, 250],
128→  [129, 140, 248],
129→  [96, 165, 250],
130→  [34, 211, 238],
131→];
132→
133→// Shadow for border chars (╔═╗║╚╝) in rows 0-4
134→const LOGO_INNER: [number, number, number][] = [
135→  [100, 83, 150],
136→  [77, 84, 149],
137→  [58, 99, 150],
138→  [20, 127, 143],
139→];
140→
141→// Extra-dim shadow for the bottom row (╚═╝)
142→const LOGO_FLOOR: [number, number, number][] = [
143→  [60, 50, 90],
144→  [46, 50, 89],
145→  [35, 59, 90],
146→  [12, 76, 86],
147→];
148→
149→const SHADOW_CHARS = new Set("╔═╗║╚╝╬╠╣╦╩╓╖╙╜╒╕╘╛┌┐└┘┬┴├┤┼─│");
150→
151→/** Color a logo row: block chars in main color, shadow chars in dim */
152→function colorLogo(
153→  text: string,
154→  block: [number, number, number],
155→  shadow: [number, number, number]
156→): string {
157→  let result = "";
158→  let buf = "";
159→  let cur: "b" | "s" | " " | null = null;
160→
161→  function flush() {
162→    if (!buf) return;
163→    if (cur === "b") result += rgb(block[0], block[1], block[2], buf);
164→    else if (cur === "s") result += rgb(shadow[0], shadow[1], shadow[2], buf);
165→    else result += buf;
166→    buf = "";
167→  }
168→
169→  for (const ch of text) {
170→    const t = ch === " " ? " " : SHADOW_CHARS.has(ch) ? "s" : "b";
171→    if (t !== cur) {
172→      flush();
173→      cur = t;
174→    }
175→    buf += ch;
176→  }
177→  flush();
178→  return result;
179→}
180→
181→// ASCII fallback for limited terminals
182→const LOGO_ASCII = [
183→  "  DDDD   EEEEE  U   U  SSSS ",
184→  "  D   D  E      U   U  S    ",
185→  "  D   D  EEE    U   U   SS  ",
186→  "  D   D  E      U   U     S ",
187→  "  DDDD   EEEEE  UUUUU  SSSS ",
188→];
189→
190→/** Render the logo rows for N letters (1-4) */
191→function renderLogoFrame(letterCount: number): string[] {
192→  const lines: string[] = [];
193→  for (let row = 0; row < 6; row++) {
194→    const shadow = row === 5 ? LOGO_FLOOR : LOGO_INNER;
195→    let line = "  ";
196→    for (let l = 0; l < letterCount; l++) {
197→      line += colorLogo(LETTERS[l][row], LOGO_BLOCK[l], shadow[l]);
198→    }
199→    lines.push(line);
200→  }
201→  return lines;
202→}
203→
204→/** Print static banner (instant) */
205→export function banner(version?: string): void {
206→  console.log("");
207→
208→  if (isUnicode && !noColor) {
209→    for (const line of renderLogoFrame(4)) {
210→      console.log(line);
211→    }
212→  } else {
213→    for (const line of LOGO_ASCII) {
214→      console.log(c.cyan(line));
215→    }
216→  }
217→
218→  console.log("");
219→  const tag = c.dim("  Agentic Engineering");
220→  const ver = version ? `  ${c.dim("v" + version)}` : "";
221→  console.log(tag + ver);
222→  console.log("");
223→}
