225→/**
226→ * Animated banner — letters reveal left-to-right.
227→ * Total animation: ~320ms (4 letters x 80ms).
228→ * Falls back to static banner in no-color or non-unicode terminals.
229→ */
230→export async function animatedBanner(version?: string): Promise<void> {
231→  if (!isUnicode || noColor) {
232→    banner(version);
233→    return;
234→  }
235→
236→  const out = process.stdout;
237→  const LOGO_ROWS = 6;
238→  const FRAME_DELAY = 80;
239→
240→  console.log(""); // blank line before logo
241→
242→  // Print initial empty lines (placeholder for logo)
243→  for (let i = 0; i < LOGO_ROWS; i++) {
244→    out.write("\n");
245→  }
246→
247→  // Animate: reveal one letter at a time
248→  for (let letterCount = 1; letterCount <= 4; letterCount++) {
249→    // Move cursor up to overwrite
250→    out.write(`${ESC}${LOGO_ROWS}A`);
251→
252→    const frame = renderLogoFrame(letterCount);
253→    for (const line of frame) {
254→      out.write(`${ESC}2K${line}\n`); // clear line + print
255→    }
256→
257→    if (letterCount < 4) {
