259→    }
260→  }
261→
262→  // Tagline + version (with fade-in delay)
263→  await sleep(100);
264→  console.log("");
265→  const tag = c.dim("  Agentic Engineering");
266→  const ver = version ? `  ${c.dim("v" + version)}` : "";
267→  console.log(tag + ver);
268→  console.log("");
269→}
270→
271→// ── Spinner ──────────────────────────────────────────────────────────
272→
273→const SPINNER_FRAMES = isUnicode
274→  ? ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"]
275→  : ["-", "\\", "|", "/"];
276→
277→const SPINNER_INTERVAL = 80;
278→
279→export interface Spinner {
280→  /** Update the spinner text while it's running */
281→  update(text: string): void;
282→  /** Stop with a success message */
283→  succeed(text?: string): void;
284→  /** Stop with a failure message */
285→  fail(text?: string): void;
286→  /** Stop with a warning message */
287→  warn(text?: string): void;
288→  /** Stop with an info message */
289→  info(text?: string): void;
290→  /** Stop and clear the line */
291→  stop(): void;
292→}
293→
294→export function spinner(text: string): Spinner {
295→  let frameIdx = 0;
296→  let currentText = text;
297→  let stopped = false;
298→
299→  const stream = process.stderr;
300→
301→  function render() {
302→    if (stopped) return;
303→    const frame = c.cyan(SPINNER_FRAMES[frameIdx % SPINNER_FRAMES.length]);
304→    stream.write(`\r${ESC}2K  ${frame} ${currentText}`);
305→    frameIdx++;
306→  }
307→
308→  const interval = setInterval(render, SPINNER_INTERVAL);
309→  render();
310→
311→  function stop(symbol: string, finalText: string) {
312→    if (stopped) return;
313→    stopped = true;
314→    clearInterval(interval);
315→    stream.write(`\r${ESC}2K  ${symbol} ${finalText}\n`);
316→  }
317→
318→  return {
319→    update(t: string) {
320→      currentText = t;
321→    },
322→    succeed(t?: string) {
323→      stop(c.green(sym.tick), t ?? currentText);
324→    },
325→    fail(t?: string) {
326→      stop(c.red(sym.cross), t ?? currentText);
327→    },
328→    warn(t?: string) {
329→      stop(c.yellow(sym.warning), t ?? currentText);
330→    },
331→    info(t?: string) {
332→      stop(c.blue(sym.info), t ?? currentText);
333→    },
334→    stop() {
335→      if (stopped) return;
336→      stopped = true;
337→      clearInterval(interval);
338→      stream.write(`\r${ESC}2K`);
339→    },
340→  };
341→}
342→
343→// ── Box ──────────────────────────────────────────────────────────────
344→
345→/** Draw a rounded box around content lines */
346→export function box(
347→  lines: string[],
348→  opts?: { padding?: number; borderColor?: (s: string) => string; width?: number }
349→): void {
350→  const { padding = 1, borderColor = c.dim, width } = opts ?? {};
351→  const pad = " ".repeat(padding);
352→
353→  // Calculate width from content (strip ANSI for measurement)
354→  const stripped = lines.map(stripAnsi);
355→  const contentWidth = width ?? Math.max(...stripped.map((l) => l.length));
356→  const innerWidth = contentWidth + padding * 2;
357→
358→  const top = borderColor(`  ${sym.tl}${sym.h.repeat(innerWidth)}${sym.tr}`);
359→  const bot = borderColor(`  ${sym.bl}${sym.h.repeat(innerWidth)}${sym.br}`);
360→  const empty = borderColor(`  ${sym.v}`) + " ".repeat(innerWidth) + borderColor(sym.v);
361→
362→  console.log(top);
363→  console.log(empty);
364→  for (let i = 0; i < lines.length; i++) {
365→    const visible = stripped[i].length;
366→    const rightPad = " ".repeat(Math.max(0, contentWidth - visible));
367→    console.log(
368→      borderColor(`  ${sym.v}`) + pad + lines[i] + rightPad + pad + borderColor(sym.v)
369→    );
370→  }
371→  console.log(empty);
372→  console.log(bot);
373→}
374→
375→// ── Section / Divider ────────────────────────────────────────────────
376→
377→/** Print a labeled divider line */
378→export function divider(label?: string, width = 44): void {
379→  if (label) {
380→    const lineLen = Math.max(0, width - label.length - 3);
381→    console.log(c.dim(`  ${sym.h.repeat(2)} ${label} ${sym.h.repeat(lineLen)}`));
382→  } else {
383→    console.log(c.dim(`  ${sym.h.repeat(width)}`));
384→  }
385→}
386→
387→// ── Key-Value Output ─────────────────────────────────────────────────
388→
389→/** Print a labeled value with consistent alignment */
390→export function kv(label: string, value: string, labelWidth = 12): void {
391→  const paddedLabel = label.padEnd(labelWidth);
392→  console.log(`  ${c.dim(paddedLabel)} ${value}`);
393→}
394→
395→// ── Messages ─────────────────────────────────────────────────────────
396→
397→export function success(text: string): void {
398→  console.log(`  ${c.green(sym.tick)} ${text}`);
399→}
400→
401→export function error(text: string): void {
402→  console.log(`  ${c.red(sym.cross)} ${text}`);
403→}
404→
405→export function warn(text: string): void {
406→  console.log(`  ${c.yellow(sym.warning)} ${text}`);
407→}
408→
409→export function info(text: string): void {
410→  console.log(`  ${c.blue(sym.info)} ${text}`);
411→}
412→
413→export function step(text: string): void {
414→  console.log(`  ${c.cyan(sym.diamond)} ${text}`);
415→}
416→
417→export function hint(text: string): void {
418→  console.log(c.dim(`  ${text}`));
419→}
420→
421→export function blank(): void {
422→  console.log("");
423→}
424→
425→// ── Gradient Text ────────────────────────────────────────────────────
426→
427→/** Apply a gradient across a text string (from → to RGB) */
428→export function gradientText(
429→  text: string,
430→  from: [number, number, number],
431→  to: [number, number, number]
432→): string {
433→  if (noColor) return text;
