  1→/**
  2→ * Build script for @deus/cli
  3→ *
  4→ * 1. Bundle the CLI TypeScript → dist/cli.js (esbuild)
  5→ * 2. Copy pre-built bundles into bundles/ for distribution:
  6→ *    - agent-server.bundled.cjs (from apps/agent-server/dist/)
  7→ *    - server.bundled.cjs (from apps/backend/dist/)
  8→ *    - web/ (from dist/web/ — built by `bun run build:web`)
  9→ *
 10→ * Prerequisites: run these from the monorepo root before building the CLI:
 11→ *   bun run build:agent-server
 12→ *   bun run build:backend
 13→ *   bun run build:web
 14→ */
 15→
 16→import { build } from "esbuild";
 17→import { cpSync, existsSync, mkdirSync, writeFileSync, readFileSync } from "fs";
 18→import { resolve, join, dirname } from "path";
 19→import { fileURLToPath } from "url";
 20→
 21→const __filename = fileURLToPath(import.meta.url);
 22→const cliDir = dirname(__filename);
 23→const monorepoRoot = resolve(cliDir, "../..");
 24→
 25→async function main() {
 26→  console.log("Building deus-machine CLI...\n");
 27→
 28→  // Step 1: Bundle CLI TypeScript
 29→  console.log("1. Bundling CLI...");
 30→  await build({
 31→    entryPoints: [join(cliDir, "src/cli.ts")],
 32→    bundle: true,
 33→    platform: "node",
 34→    target: "node20",
 35→    format: "esm",
 36→    outfile: join(cliDir, "dist/cli.js"),
 37→    external: [
 38→      // Native modules resolved at runtime
 39→      "better-sqlite3",
 40→      "node-pty",
 41→      "ws",
 42→    ],
 43→    packages: "external",
 44→    minify: false,
 45→    sourcemap: false,
 46→    logLevel: "info",
 47→  });
 48→
 49→  // Step 2: Create bin/ entry point
 50→  console.log("\n2. Creating bin/deus.js...");
 51→  mkdirSync(join(cliDir, "bin"), { recursive: true });
 52→  writeFileSync(
 53→    join(cliDir, "bin/deus.js"),
 54→    `#!/usr/bin/env node\nimport "../dist/cli.js";\n`,
 55→    { mode: 0o755 }
 56→  );
 57→
 58→  // Step 3: Copy bundles for distribution
 59→  console.log("\n3. Copying bundles...");
 60→  const bundlesDir = join(cliDir, "bundles");
 61→  mkdirSync(bundlesDir, { recursive: true });
 62→
 63→  const copies: { src: string; dest: string; name: string; required: boolean }[] = [
 64→    {
 65→      src: join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs"),
 66→      dest: join(bundlesDir, "agent-server.bundled.cjs"),
 67→      name: "agent-server bundle",
 68→      required: true,
 69→    },
 70→    {
 71→      src: join(monorepoRoot, "apps/backend/dist/server.bundled.cjs"),
 72→      dest: join(bundlesDir, "server.bundled.cjs"),
 73→      name: "backend bundle",
 74→      required: true,
 75→    },
 76→    {
 77→      src: join(monorepoRoot, "apps/web/dist/web"),
 78→      dest: join(bundlesDir, "web"),
 79→      name: "frontend build",
 80→      required: false,
 81→    },
 82→  ];
 83→
 84→  let hasErrors = false;
