222→  if (!fs.existsSync(settingsPath)) return {};
223→
224→  let raw: unknown;
225→  try {
226→    raw = JSON.parse(fs.readFileSync(settingsPath, "utf8"));
227→  } catch {
228→    console.error("Failed to parse settings.json as JSON");
229→    return {};
