264→
265→// ============================================================================
266→// Skills
267→// ============================================================================
268→
269→/**
270→ * Parse simple YAML frontmatter from a SKILL.md file.
271→ * Returns key-value pairs from the --- delimited block at the top.
272→ */
273→function parseFrontmatter(content: string): { frontmatter: Record<string, string>; body: string } {
274→  const match = content.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);
275→  if (!match) return { frontmatter: {}, body: content };
276→
277→  const frontmatter: Record<string, string> = {};
278→  match[1].split("\n").forEach((line) => {
279→    const colonIdx = line.indexOf(":");
280→    if (colonIdx > 0) {
281→      const key = line.slice(0, colonIdx).trim();
282→      const value = line
283→        .slice(colonIdx + 1)
284→        .trim()
285→        .replace(/^["']|["']$/g, "");
286→      frontmatter[key] = value;
287→    }
288→  });
289→
290→  return { frontmatter, body: match[2] };
291→}
292→
293→export function getSkills(projectPath?: string): SkillItem[] {
294→  const skillsDir = path.join(resolveClaudeDir(projectPath), "skills");
295→  if (!fs.existsSync(skillsDir)) return [];
296→
297→  const entries = fs.readdirSync(skillsDir, { withFileTypes: true });
298→  const skills: SkillItem[] = [];
299→
300→  entries.forEach((entry) => {
301→    if (!entry.isDirectory()) return;
302→    const skillMdPath = path.join(skillsDir, entry.name, "SKILL.md");
303→    if (!fs.existsSync(skillMdPath)) return;
304→
305→    try {
306→      const content = fs.readFileSync(skillMdPath, "utf8");
307→      const { frontmatter } = parseFrontmatter(content);
308→      // Use directory name as canonical identity — frontmatter.name is display-only
309→      skills.push({
310→        name: entry.name,
311→        description: frontmatter.description || frontmatter.name || "",
312→        content,
313→      });
314→    } catch {
315→      // Skip unreadable skill directories
316→      console.error(`Failed to read skill: ${entry.name}`);
317→    }
318→  });
319→
320→  return skills;
321→}
