230→  reset(sessionId: string): void {
231→    console.log(`Handling reset generator request for session: ${sessionId}`);
232→    const session = claudeSessions.get(sessionId);
233→    if (session) {
234→      console.log(`Terminating generator for session ${sessionId} on reset request`);
235→      terminateSession(sessionId);
236→    }
237→  }
