288→  async getContextUsage(request: ContextUsageParams) {
289→    const { id: sessionId, options } = request;
290→    const agentSessionId = options.agentSessionId;
291→
292→    console.log(
293→      `[getContextUsage] Getting context usage for session: ${sessionId}, agentSessionId: ${agentSessionId}`
294→    );
295→
296→    if (!agentSessionId) throw new Error("No agentSessionId provided");
297→    if (blockIfNotInitialized(sessionId)) throw new Error("Initialization failure");
298→
299→    const sdkOptions = {
300→      cwd: options.cwd,
301→      pathToClaudeCodeExecutable: getClaudeExecutablePath(),
302→      systemPrompt: DEFAULT_PROMPT,
303→      settingSources: DEFAULT_SETTING_SOURCES,
304→      resume: agentSessionId,
305→    };
306→
307→    const contextUsageQuery = claudeSDK({ prompt: "/context", options: sdkOptions });
308→
309→    try {
310→      for await (const message of contextUsageQuery) {
311→        if (message.type !== "user") continue;
312→        return {
313→          type: "context_usage",
314→          id: sessionId,
315→          agentType: "claude",
316→          contextUsageData: message,
317→        };
318→      }
319→    } finally {
320→      try {
321→        await contextUsageQuery.interrupt();
322→      } catch (error) {
323→        console.error(`[getContextUsage] Error during interrupt:`, error);
324→      }
325→    }
326→
327→    throw new Error("No user message found in context usage response");
328→  }
