 17→/**
 18→ * Configuration for discovering a CLI executable.
 19→ * Each agent provides one of these — the only thing that varies between agents.
 20→ */
 21→export interface DiscoveryConfig {
 22→  /** Agent type for error messages (e.g. "claude", "codex") */
 23→  agentType: AgentType;
 24→  /** Human-readable name for log messages (e.g. "Claude", "Codex") */
 25→  displayName: string;
 26→  /** Env var override (e.g. "CLAUDE_CLI_PATH", "CODEX_CLI_PATH") */
 27→  envVar: string;
 28→  /** Static candidate paths (known install locations) */
 29→  staticCandidates: string[];
 30→  /** Shell command name for dynamic discovery (e.g. "claude", "codex") */
 31→  shellCommand: string;
 32→  /** Version flag to verify the candidate (e.g. "-v", "--version") */
 33→  versionFlag: string;
 34→  /**
 35→   * Optional: additional candidates discovered programmatically
 36→   * (e.g. Codex's require.resolve for bundled npm binary).
 37→   * Returns additional paths to try, or empty array.
 38→   */
 39→  extraCandidates?: () => string[];
 40→}
