 42→/**
 43→ * Mutable state for a single agent's discovery result.
 44→ * Owned by each agent's discovery wrapper module.
 45→ */
 46→export interface DiscoveryState {
 47→  executablePath: string;
 48→  result: { success: boolean; path?: string; error?: string } | null;
 49→}
 50→
 51→// ============================================================================
 52→// Discovery Algorithm
 53→// ============================================================================
 54→
 55→/**
 56→ * Discovers and verifies a CLI executable using the given config.
 57→ * Mutates `state` with the result.
 58→ *
 59→ * Algorithm:
 60→ * 1. Gather candidates: env var → static paths → extra candidates → shell PATH
 61→ * 2. For each candidate: verify it exists, run `<candidate> <versionFlag>`
 62→ * 3. First success wins; all failures produce a descriptive error.
 63→ */
 64→export function discoverExecutable(
 65→  config: DiscoveryConfig,
 66→  state: DiscoveryState
 67→): { success: boolean; error?: string } {
 68→  console.log(`Setting up ${config.displayName} executable path...`);
 69→
 70→  // Build candidate list
 71→  const candidates: string[] = [];
 72→
 73→  // Env var override (highest priority)
 74→  const envOverride = process.env[config.envVar];
 75→  if (envOverride) candidates.push(envOverride);
 76→
 77→  // Static candidate paths
 78→  candidates.push(...config.staticCandidates);
 79→
 80→  // Extra programmatic candidates (e.g. require.resolve for bundled binary)
 81→  if (config.extraCandidates) {
 82→    try {
 83→      const extra = config.extraCandidates();
 84→      for (const p of extra) {
 85→        if (p && !candidates.includes(p)) candidates.push(p);
 86→      }
 87→    } catch {
 88→      // Extra candidate discovery failed — continue
 89→    }
 90→  }
 91→
 92→  // Dynamic discovery: find via user's login shell PATH.
 93→  // Node's child_process inherits a minimal env, so run through login shell
 94→  // to pick up ~/.local/bin, nvm paths, etc.
 95→  // Strip node_modules/.bin from PATH to avoid finding SDK's internal
 96→  // CLI wrapper (which crashes on version check in bundled/test contexts).
 97→  try {
 98→    const shell = process.env.SHELL || "/bin/zsh";
 99→    const cleanEnv = { ...process.env };
100→    if (cleanEnv.PATH) {
101→      cleanEnv.PATH = cleanEnv.PATH.split(":")
102→        .filter((p) => !p.includes("node_modules"))
103→        .join(":");
104→    }
105→    const resolved = execSync(`"${shell}" -l -c "command -v ${config.shellCommand}"`, {
106→      encoding: "utf-8",
107→      timeout: 5000,
108→      env: cleanEnv,
109→      stdio: ["ignore", "pipe", "pipe"],
110→    }).trim();
111→    if (resolved && !candidates.includes(resolved)) {
112→      candidates.push(resolved);
113→    }
114→  } catch {
115→    // Shell discovery failed — continue with static candidates
116→  }
117→
118→  // Verify each candidate
119→  const triedCandidates: string[] = [];
120→  for (const candidate of candidates) {
121→    if (!candidate) continue;
122→
123→    // Avoid shell noise when absolute/relative paths are missing
124→    const looksLikePath = candidate.includes(path.sep) || candidate.startsWith(".");
125→    if (looksLikePath && !fs.existsSync(candidate)) {
126→      triedCandidates.push(candidate);
127→      continue;
128→    }
129→
130→    try {
131→      const version = verifyCandidate(candidate, config.versionFlag);
132→      console.log(
133→        `${config.displayName} executable initialized with version: ${version} at ${candidate}`
134→      );
135→      state.executablePath = candidate;
136→      state.result = { success: true, path: candidate };
137→      return { success: true };
138→    } catch {
139→      triedCandidates.push(candidate);
140→    }
141→  }
142→
143→  const errorMessage = `Failed to find ${config.displayName} executable. Tried: ${triedCandidates.join(", ")}`;
144→  console.error(`${config.displayName} executable initialization failed: ${errorMessage}`);
145→  state.result = { success: false, error: errorMessage };
146→  return { success: false, error: errorMessage };
147→}
148→
149→function verifyCandidate(candidate: string, versionFlag: string): string {
150→  const opts = {
151→    encoding: "utf-8" as const,
152→    timeout: 5000,
153→    stdio: ["ignore", "pipe", "pipe"] as ["ignore", "pipe", "pipe"],
154→  };
155→
156→  // JS entrypoint installed via a global package manager
157→  if (candidate.endsWith(".js")) {
158→    return execFileSync("node", [candidate, versionFlag], opts).trim();
159→  }
160→
161→  // Native binary/symlink
162→  return execFileSync(candidate, [versionFlag], opts).trim();
163→}
164→
165→// ============================================================================
166→// Init Guard
167→// ============================================================================
168→
169→/**
170→ * Checks if initialization succeeded, and sends an error to the frontend if not.
171→ * Returns true if blocked (initialization failed), false if OK to proceed.
172→ */
173→export function blockIfNotInitialized(
174→  state: DiscoveryState,
175→  agentType: AgentType,
176→  sessionId: string
177→): boolean {
178→  if (!state.result?.success) {
179→    const errorMsg = `Cannot process request: ${state.result?.error || "Initialization failed"}`;
180→    try {
181→      EventBroadcaster.sendError({
182→        id: sessionId,
183→        type: "error",
184→        error: errorMsg,
185→        agentType,
186→        category: "internal",
187→      });
188→    } catch (error) {
189→      console.warn(`[CLI-DISCOVERY] Failed to emit init error to frontend:`, error);
190→    }
191→    // Emit canonical error event so the backend updates session status.
192→    // The backend set status='working' before forwarding turn/start to the agent-server.
193→    try {
194→      EventBroadcaster.emitSessionError(sessionId, agentType, errorMsg, "internal");
195→    } catch (error) {
196→      console.warn(`[CLI-DISCOVERY] Failed to emit session error:`, error);
197→    }
198→    console.log(`Blocked ${agentType} request due to initialization failure`);
199→    return true;
200→  }
201→  return false;
202→}
