  1→// agent-server/agents/environment/env-builder.ts
  2→// Shared environment construction for all agent handlers.
  3→// Builds the 6-layer environment: shell env → process.env → extra env →
  4→// deusEnv → providerEnvVars → ghToken.
  5→
  6→import { getShellEnvironment } from "./shell-env";
  7→
  8→/**
  9→ * Parses a multi-line "KEY=value" env string (supports export prefix, quoting).
 10→ * Used to parse user-provided environment variable overrides.
 11→ */
 12→export function parseEnvString(envString: string): Record<string, string> {
 13→  const result: Record<string, string> = {};
 14→  const lines = envString.split("\n");
 15→  let i = 0;
 16→
 17→  while (i < lines.length) {
 18→    let line = lines[i].trim();
 19→    if (!line || line.startsWith("#")) {
 20→      i++;
 21→      continue;
 22→    }
 23→    if (line.startsWith("export ")) {
 24→      line = line.substring(7).trim();
 25→    }
 26→
 27→    const equalIndex = line.indexOf("=");
 28→    if (equalIndex === -1) {
 29→      i++;
 30→      continue;
 31→    }
 32→
 33→    const key = line.substring(0, equalIndex).trim();
 34→    if (!key) {
 35→      i++;
 36→      continue;
 37→    }
 38→
 39→    let value = line.substring(equalIndex + 1).trim();
 40→
 41→    // Handle quoted values (may span multiple lines)
 42→    if ((value.startsWith('"') || value.startsWith("'")) && value.length > 1) {
 43→      const quote = value[0];
 44→      let endQuoteIndex = value.indexOf(quote, 1);
 45→      while (endQuoteIndex === -1 && i + 1 < lines.length) {
 46→        i++;
 47→        value += "\n" + lines[i];
 48→        endQuoteIndex = value.indexOf(quote, 1);
 49→      }
 50→      if (endQuoteIndex !== -1) {
 51→        value = value.substring(1, endQuoteIndex);
 52→      }
 53→    }
 54→
 55→    result[key] = value;
 56→    i++;
 57→  }
 58→  return result;
 59→}
 60→
 61→/**
 62→ * Builds the environment variable object for an agent session.
 63→ *
 64→ * Layer precedence (later layers override earlier):
 65→ * 1. Shell environment (login shell capture)
 66→ * 2. process.env (agent-server process environment)
 67→ * 3. extraEnv (agent-specific static env vars, e.g. CLAUDE_CODE_ENABLE_TASKS)
 68→ * 4. deusEnv (from frontend options)
 69→ * 5. providerEnvVars (user-configured env string, empty values delete keys)
 70→ * 6. ghToken (sets GH_TOKEN if provided)
 71→ */
 72→export function buildAgentEnvironment(options?: {
 73→  providerEnvVars?: string;
 74→  deusEnv?: Record<string, string>;
 75→  ghToken?: string;
 76→  extraEnv?: Record<string, string>;
 77→}): Record<string, string> {
 78→  const env: Record<string, string> = {};
 79→
 80→  // Layer 1: Shell environment
 81→  try {
 82→    Object.assign(env, getShellEnvironment());
 83→  } catch (error) {
 84→    console.error("Failed to load shell environment, continuing without it:", error);
 85→  }
 86→
 87→  // Layer 2: process.env
 88→  for (const [key, value] of Object.entries(process.env)) {
 89→    if (value !== undefined) env[key] = value;
 90→  }
 91→
 92→  // Layer 3: Extra static env vars
 93→  if (options?.extraEnv) {
 94→    for (const [key, value] of Object.entries(options.extraEnv)) {
 95→      env[key] = value;
 96→    }
 97→  }
 98→
 99→  // Layer 4: Deus env (from frontend)
100→  if (options?.deusEnv) {

100→  if (options?.deusEnv) {
101→    for (const [key, value] of Object.entries(options.deusEnv)) {
102→      env[key] = value;
103→    }
104→  }
105→
106→  // Layer 5: User-configured env vars (empty values delete keys)
107→  if (options?.providerEnvVars) {
108→    const parsed = parseEnvString(options.providerEnvVars);
109→    for (const [key, value] of Object.entries(parsed)) {
110→      if (value === "") delete env[key];
111→      else env[key] = value;
112→    }
113→  }
114→
115→  // Layer 6: GitHub token
116→  if (options?.ghToken) env["GH_TOKEN"] = options.ghToken;
117→
118→  return env;
119→}
