226→  const modelToUse = mapModelForProvider(options?.model, env);
227→  const workingDirectory = options?.cwd;
228→  const permissionMode = (options?.permissionMode ?? "default") as PermissionMode;
229→
230→  // Built as Partial<Options> and conditionally extended.
231→  // Cast to Options at return — the SDK validates at runtime.
232→  const sdkOptions: Partial<Options> = {
233→    maxTurns: options?.maxTurns || 1_000,
234→    model: modelToUse,
235→    maxThinkingTokens: options?.maxThinkingTokens,
236→    cwd: workingDirectory,
237→    pathToClaudeCodeExecutable: getClaudeExecutablePath(),
238→    systemPrompt: {
239→      type: "preset" as const,
240→      preset: "claude_code" as const,
241→      append: buildAppendSystemPrompt(workingDirectory),
242→    },
243→    settingSources: DEFAULT_SETTING_SOURCES,
244→    canUseTool: createCanUseTool(sessionId, workingDirectory),
245→    additionalDirectories: options?.additionalDirectories ?? [],
246→    env,
247→    disallowedTools: ["AskUserQuestion"],
248→    permissionMode,
249→    hooks: createHooks(sessionId),
250→  };
251→
252→  if (options?.chromeEnabled) {
253→    (sdkOptions as any).extraArgs = { chrome: null };
254→  }
255→
256→  if (options?.resumeSessionAt) {
257→    sdkOptions.resumeSessionAt = options.resumeSessionAt;
258→  }
259→
260→  if (options?.resume) {
261→    sdkOptions.resume = options.resume;
262→  }
263→
264→  if (!options?.strictDataPrivacy) {
265→    sdkOptions.mcpServers = {
266→      deus: createDeusMCPServer(sessionId),
267→      ...createNotebookMCPServer(workingDirectory),
268→    };
269→  }
270→
271→  return sdkOptions as Options;
272→}
