  1→import { Hono } from "hono";
  2→import Database from "better-sqlite3";
  3→import { existsSync, readdirSync } from "fs";
  4→import { homedir } from "os";
  5→import { join, basename } from "path";
  6→import type { RecentProject } from "@shared/types/onboarding";
  7→
  8→const app = new Hono();
  9→
 10→app.get("/onboarding/recent-projects", (c) => {
 11→  const home = homedir();
 12→  const projects: RecentProject[] = [];
 13→  const seenPaths = new Set<string>();
 14→
 15→  // Read from Cursor state.vscdb
 16→  const cursorDbPath = join(
 17→    home,
 18→    "Library/Application Support/Cursor/User/globalStorage/state.vscdb"
 19→  );
 20→  readVscdbProjects(cursorDbPath, "cursor", projects, seenPaths);
 21→
 22→  // Read from VSCode state.vscdb
 23→  const vscodeDbPath = join(
 24→    home,
 25→    "Library/Application Support/Code/User/globalStorage/state.vscdb"
 26→  );
 27→  readVscdbProjects(vscodeDbPath, "vscode", projects, seenPaths);
 28→
 29→  // Read from Claude projects directory
 30→  readClaudeProjects(join(home, ".claude/projects"), projects, seenPaths);
 31→
 32→  return c.json({ projects: projects.slice(0, 30) });
 33→});
 34→
 35→// Worktree directories created by AI coding tools — filter these from recent projects
 36→// so only root repos are shown, not individual worktree checkouts.
 37→const WORKTREE_SEGMENTS = [
 38→  "/.deus/", // Deus worktrees
 39→  "/.conductor/", // OpenDevs worktrees
 40→  "/.claude/worktrees/", // Claude Code worktrees
 41→  "/.cursor/worktrees/", // Cursor parallel agent worktrees
 42→  "/copilot-worktree/", // GitHub Copilot CLI worktrees
 43→];
 44→
 45→function isWorktreePath(fsPath: string): boolean {
 46→  return WORKTREE_SEGMENTS.some((seg) => fsPath.includes(seg));
 47→}
 48→
 49→function readVscdbProjects(
 50→  dbPath: string,
 51→  source: "cursor" | "vscode",
 52→  projects: RecentProject[],
 53→  seen: Set<string>
 54→) {
 55→  if (!existsSync(dbPath)) return;
 56→  let db: InstanceType<typeof Database> | undefined;
 57→  try {
 58→    db = new Database(dbPath, { readonly: true });
 59→    const row = db
 60→      .prepare("SELECT value FROM ItemTable WHERE key = 'history.recentlyOpenedPathsList'")
 61→      .get() as { value: string } | undefined;
 62→
 63→    if (!row?.value) return;
 64→    const data = JSON.parse(row.value);
 65→    const entries = data.entries || [];
 66→
 67→    for (const entry of entries) {
 68→      const uri = entry.folderUri;
 69→      if (!uri || !uri.startsWith("file://")) continue;
 70→      const fsPath = decodeURIComponent(uri.replace("file://", ""));
 71→      if (seen.has(fsPath) || isWorktreePath(fsPath) || !existsSync(fsPath)) continue;
 72→      seen.add(fsPath);
 73→      projects.push({ path: fsPath, name: basename(fsPath), source });
 74→    }
 75→  } catch {
 76→    // Silently skip if DB is locked or malformed
 77→  } finally {
 78→    db?.close();
 79→  }
 80→}
 81→
 82→function readClaudeProjects(dir: string, projects: RecentProject[], seen: Set<string>) {
 83→  if (!existsSync(dir)) return;
 84→  try {
 85→    const entries = readdirSync(dir, { withFileTypes: true });
 86→    for (const entry of entries) {
 87→      if (!entry.isDirectory()) continue;
 88→      // Claude encodes paths: leading dash + dashes as path separators
 89→      // e.g., "-Users-zvada-Developer-myproject" -> "/Users/zvada/Developer/myproject"
 90→      const decoded = entry.name.replace(/-/g, "/");
 91→      if (!decoded.startsWith("/")) continue;
 92→      if (seen.has(decoded) || isWorktreePath(decoded) || !existsSync(decoded)) continue;
 93→      seen.add(decoded);
 94→      projects.push({ path: decoded, name: basename(decoded), source: "claude" });
 95→    }
 96→  } catch {
 97→    // Silently skip
 98→  }
 99→}
100→
101→export default app;
