 1→// agent-server/agents/environment/shell-env.ts
 2→// Captures the user's login-shell environment so child processes (Claude SDK)
 3→// inherit PATH, NVM, pyenv, etc. without manual configuration.
 4→
 5→import { execFileSync } from "child_process";
 6→import { stripVTControlCharacters } from "util";
 7→
 8→let shellEnvironment: Record<string, string> | null = null;
 9→
10→const DELIMITER = "_SHELL_ENV_DELIMITER_";
11→
12→function parseEnv(output: string): Record<string, string> {
13→  const envSection = output.split(DELIMITER)[1];
14→  if (!envSection) {
15→    return {};
16→  }
17→
18→  const env: Record<string, string> = {};
19→  for (const line of stripVTControlCharacters(envSection).split("\n").filter(Boolean)) {
20→    const separatorIndex = line.indexOf("=");
21→    if (separatorIndex > 0) {
22→      const key = line.substring(0, separatorIndex);
23→      const value = line.substring(separatorIndex + 1);
24→      env[key] = value;
25→    }
26→  }
27→  return env;
28→}
29→
30→/**
31→ * Keys stripped from the shell environment to prevent auth interference.
32→ * These are provider-specific keys that the user may have set globally
33→ * but that should not leak into the Deus-managed Claude session.
34→ */
35→const STRIPPED_ENV_KEYS = [
36→  "ANTHROPIC_API_KEY",
37→  "OPENAI_API_KEY",
38→  "CLAUDE_CODE_USE_BEDROCK",
39→  "CLAUDE_CODE_USE_VERTEX",
40→];
41→
42→/**
43→ * Lazily captures and returns the user's interactive login-shell environment.
44→ * Results are cached after the first call.
45→ */
46→export function getShellEnvironment(): Record<string, string> {
47→  if (shellEnvironment !== null) {
48→    return shellEnvironment;
49→  }
50→
51→  const shell = process.env.SHELL || "/bin/zsh";
52→  const command = `echo -n "${DELIMITER}"; env; echo -n "${DELIMITER}"; exit`;
53→
54→  const output = execFileSync(shell, ["-ilc", command], {
55→    encoding: "utf8",
56→    timeout: 5_000,
57→    env: {
58→      // Prevent Oh My Zsh from blocking with auto-update prompts
59→      DISABLE_AUTO_UPDATE: "true",
60→    },
61→  });
62→
63→  const env = parseEnv(output);
64→
65→  for (const key of STRIPPED_ENV_KEYS) {
66→    if (key in env) {
67→      console.log(`Stripped ${key} from shell environment to prevent auth interference`);
68→      delete env[key];
69→    }
70→  }
71→
72→  console.log(`Loaded ${Object.keys(env).length} environment variables from shell`);
73→
74→  shellEnvironment = env;
75→  return env;
76→}
