  1→// backend/src/services/agent/service.ts
  2→// Composition root for agent-server communication.
  3→//
  4→// Creates the AgentClient, wires the event handler with injected dependencies,
  5→// and exposes typed methods for other services to call. No circular imports —
  6→// this module imports from its dependencies, none of them import back.
  7→//
  8→// Dependency graph (all arrows point down, no cycles):
  9→//
 10→//   service (this file)
 11→//       ├── client              (WebSocket transport)
 12→//       ├── event-handler       (factory: createAgentEventHandler)
 13→//       └── tool-relay          (frontend RPC relay)
 14→//
 15→// Initialized once at startup in server.ts via agentService.init().
 16→
 17→import { AgentClient } from "./client";
 18→import { createAgentEventHandler } from "./event-handler";
 19→import { relay } from "./tool-relay";
 20→import {
 21→  persistSessionNeedsPlanResponse,
 22→  persistSessionNeedsResponse,
 23→  persistSessionBackToWorking,
 24→} from "./persistence";
 25→import { invalidate } from "../query-engine";
 26→import type {
 27→  TurnStartRequest,
 28→  TurnStartResponse,
 29→  TurnRespondRequest,
 30→  SessionStopRequest,
 31→  ProviderAuthRequest,
 32→} from "@shared/agent-events";
 33→
 34→// ---- Singleton ----
 35→
 36→let client: AgentClient | null = null;
 37→
 38→/** Initialize the agent service. Call once at startup. */
 39→export function init(agentServerUrl: string): void {
 40→  if (client) {
 41→    console.warn("[AgentService] Already initialized, skipping");
 42→    return;
 43→  }
 44→
 45→  client = new AgentClient({
 46→    url: agentServerUrl,
 47→
 48→    // Wire the event handler with respondToAgent injected — breaks the
 49→    // circular dependency that previously existed between these modules.
 50→    onEvent: createAgentEventHandler({
 51→      respondToAgent: (params) => respondToAgent(params),
 52→    }),
 53→
 54→    onConnected: (agents) => {
 55→      console.log(`[AgentService] Connected, agents: [${agents.map((a) => a.type).join(", ")}]`);
 56→    },
 57→    onDisconnected: () => {
 58→      console.log("[AgentService] Disconnected from agent-server");
 59→    },
 60→
 61→    // Relay agent-server's frontend-facing RPC requests (browser, sim, diff, plan)
 62→    onFrontendRpc: async (requestId, sessionId, method, params) => {
 63→      const isUserFacing = method === "exitPlanMode" || method === "askUserQuestion";
 64→      const sessionResources = ["workspaces", "sessions", "session", "stats"] as const;
 65→
 66→      // User-facing methods: update session status so sidebar shows "needs input" instead of "working"
 67→      if (method === "exitPlanMode") {
 68→        const result = persistSessionNeedsPlanResponse(sessionId);
 69→        if (result.ok) invalidate([...sessionResources], { sessionIds: [sessionId] });
 70→      } else if (method === "askUserQuestion") {
 71→        const result = persistSessionNeedsResponse(sessionId);
 72→        if (result.ok) invalidate([...sessionResources], { sessionIds: [sessionId] });
 73→      }
 74→
 75→      try {
 76→        return await relay({
 77→          type: "tool.request",
 78→          requestId,
 79→          sessionId,
 80→          method,
 81→          params,
 82→          // User-facing methods wait indefinitely; auto-responding keep 2-min timeout
 83→          timeoutMs: isUserFacing ? 24 * 60 * 60 * 1000 : 120_000,
 84→        });
 85→      } finally {
 86→        if (isUserFacing) {
 87→          const result = persistSessionBackToWorking(sessionId);
 88→          if (result.ok) invalidate([...sessionResources], { sessionIds: [sessionId] });
 89→        }
 90→      }
 91→    },
 92→  });
 93→
 94→  client.connect();
 95→}
 96→
 97→/** Gracefully shut down the agent client. */
 98→export function shutdown(): void {
 99→  client?.disconnect();
100→  client = null;
101→}
102→
103→// ---- Public API (typed wrappers) ----
104→
105→/** Forward a turn/start request to the agent-server. */
106→export async function forwardTurn(params: TurnStartRequest): Promise<TurnStartResponse> {
107→  if (!client) throw new Error("Agent service not initialized");
108→  return client.sendTurnStart(params);
109→}
110→
111→/** Send a tool relay response back to the agent-server. */
112→export async function respondToAgent(params: TurnRespondRequest): Promise<void> {
113→  if (!client) throw new Error("Agent service not initialized");
114→  return client.sendTurnRespond(params);
115→}
116→
117→/** Stop a session on the agent-server. */
118→export async function stopSession(params: SessionStopRequest): Promise<void> {
119→  if (!client) throw new Error("Agent service not initialized");
120→  return client.sendSessionStop(params);
121→}
122→
123→/** Check if the agent service is connected. */
124→export function isConnected(): boolean {
125→  return client?.isConnected() ?? false;
126→}
127→
128→/** Check authentication status for an agent provider. */
129→export async function checkAuth(params: ProviderAuthRequest): Promise<unknown> {
130→  if (!client) throw new Error("Agent service not initialized");
131→  return client.sendProviderAuth(params);
132→}
133→
134→/** Returns the agents discovered during the initialize handshake. */
135→export function getAgents() {
136→  return client?.getAgents() ?? [];
137→}
138→

