 75→    hint(`Run ${c.cyan("bun run build:cli")} from the monorepo root first.`);
 76→    blank();
 77→    process.exit(1);
 78→  }
 79→
 80→  // Resolve Node binary (handles Electron ABI mismatch in dev)
 81→  const nodeCmd = resolveNodeBinary();
 82→
 83→  // Resolve database
 84→  const dbPath = resolveDataDir(dataDir);
 85→  kv("Database", c.dim(dbPath));
 86→  blank();
 87→
 88→  // Track child processes for cleanup
 89→  const children: ProcessInfo[] = [];
 90→  let status: ReturnType<typeof statusLine> | null = null;
 91→
 92→  function shutdown() {
 93→    if (status) status.stop();
 94→    blank();
 95→
 96→    const msg = gradientText("Thanks for using Deus!", [167, 139, 250], [34, 211, 238]);
 97→    console.log(`  ${msg}`);
 98→    blank();
 99→
100→    for (const child of children) {
101→      if (!child.process.killed) child.process.kill("SIGTERM");
102→    }
103→    process.exit(0);
104→  }
105→  process.on("SIGINT", shutdown);
106→  process.on("SIGTERM", shutdown);
107→
108→  // ── Step 1: Agent server ─────────────────────────────────────────
109→  const s1 = createSpinner("Starting agent server...");
110→  const agentServerUrl = await startProcess({
111→    name: "agent-server",
112→    command: nodeCmd,
113→    args: [paths.agentServer],
114→    env: { DATABASE_PATH: dbPath },
115→    waitFor: /LISTEN_URL=(.+)/,
116→    children,
117→  });
118→
119→  if (!agentServerUrl) {
120→    s1.fail("Agent server failed to start");
121→    blank();
122→    process.exit(1);
123→  }
124→  s1.succeed(`Agent server ${c.dim("ready")}`);
125→
126→  // ── Step 2: Backend ──────────────────────────────────────────────
127→  const s2 = createSpinner("Starting backend...");
128→  const backendPort = await startProcess({
129→    name: "backend",
130→    command: nodeCmd,
131→    args: [paths.backend],
132→    env: {
133→      AGENT_SERVER_URL: agentServerUrl,
134→      DATABASE_PATH: dbPath,
135→      PORT: "0",
136→    },
137→    waitFor: /\[BACKEND_PORT\](\d+)/,
138→    children,
139→  });
140→
141→  if (!backendPort) {
142→    s2.fail("Backend failed to start");
143→    blank();
144→    process.exit(1);
145→  }
146→  s2.succeed(`Backend ${c.dim("ready")}`);
147→
148→  // ── Step 3: Web server ───────────────────────────────────────────
149→  const hasFrontend = existsSync(paths.frontend) && existsSync(join(paths.frontend, "index.html"));
150→
151→  const s3 = createSpinner("Starting web server...");
152→  const webServer = createWebServer(parseInt(backendPort, 10), paths.frontend);
153→
154→  await new Promise<void>((resolve) => {
155→    webServer.listen(port, host, () => resolve());
156→  });
157→
158→  if (hasFrontend) {
159→    s3.succeed(`Web UI ${c.dim("ready")}`);
160→  } else {
161→    s3.warn(`Web UI ${c.dim("— frontend not built, API-only mode")}`);
162→  }
163→
164→  // ── Ready! ───────────────────────────────────────────────────────
165→  blank();
166→
167→  const url = `http://${host === "0.0.0.0" ? "localhost" : host}:${port}`;
168→  box(
169→    [
170→      gradientText("Deus is running", [167, 139, 250], [34, 211, 238]),
171→      "",
172→      c.bold(c.brightWhite(url)),
173→    ],
174→    { borderColor: c.cyan, width: 38 }
175→  );
176→
177→  blank();
178→  kv("Local", c.cyan(url), 10);
179→
180→  // Show network URL if binding to all interfaces or a specific host
181→  const lanIp = getLanIp();
182→  if (lanIp && (host === "0.0.0.0" || host === "localhost")) {
183→    kv("Network", c.dim(`http://${lanIp}:${port}`), 10);
184→  }
185→
186→  // ── Remote Access ────────────────────────────────────────────────
187→  blank();
188→  divider("Remote Access");
189→  blank();
190→  hint("To access from your phone or another computer:");
191→  blank();
192→  console.log(`    1. Open  ${c.cyan(c.underline("app.rundeus.com"))}`);
193→  console.log(`    2. Pair your device with this server`);
194→  blank();
195→  hint(`Or enable remote access in Settings ${sym.arrow} Remote Access`);
196→  blank();
197→  divider();
198→
199→  // ── API Key Check ────────────────────────────────────────────────
200→  const hasApiKey = !!(process.env.ANTHROPIC_API_KEY || process.env.OPENAI_API_KEY);
201→  if (!hasApiKey) {
202→    blank();
203→    warn("No API key detected in environment");
204→    blank();
205→    hint("AI agents need an API key to work. Set one of:");
206→    blank();
207→    console.log(`    ${c.cyan("export ANTHROPIC_API_KEY")}=${c.dim('"sk-ant-..."')}`);
208→    console.log(`    ${c.cyan("export OPENAI_API_KEY")}=${c.dim('"sk-..."')}`);
209→    blank();
210→    hint(`Or configure it in the app: Settings ${sym.arrow} API Keys`);
211→    blank();
212→    divider();
213→  }
214→
215→  // ── Status line ──────────────────────────────────────────────────
216→  blank();
217→  const startedAt = new Date();
218→  status = statusLine(() => {
