230→
231→// ── Bundle resolution ────────────────────────────────────────────────
232→
233→function resolveBundlePaths(): {
234→  agentServer: string;
235→  backend: string;
236→  frontend: string;
237→} | null {
238→  const cliRoot = resolve(__dirname, "..");
239→
240→  // Bundled mode (npm package)
241→  const bundledDir = join(cliRoot, "bundles");
242→  if (existsSync(join(bundledDir, "agent-server.bundled.cjs"))) {
243→    return {
244→      agentServer: join(bundledDir, "agent-server.bundled.cjs"),
245→      backend: join(bundledDir, "server.bundled.cjs"),
246→      frontend: join(bundledDir, "web"),
247→    };
248→  }
249→
250→  // Dev mode (monorepo)
251→  const monorepoRoot = resolve(cliRoot, "../..");
252→  const agentServer = join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs");
253→  const backend = join(monorepoRoot, "apps/backend/dist/server.bundled.cjs");
254→  const frontend = join(monorepoRoot, "apps/web/dist/web");
255→
256→  if (existsSync(agentServer) && existsSync(backend)) {
257→    return { agentServer, backend, frontend };
258→  }
259→
260→  return null;
261→}
262→
263→// ── Data directory ───────────────────────────────────────────────────
264→
265→function resolveDataDir(customDir?: string): string {
266→  if (customDir) {
267→    mkdirSync(customDir, { recursive: true });
268→    return join(customDir, "deus.db");
269→  }
270→
271→  const os = platform();
272→  let dir: string;
273→
274→  if (os === "darwin") {
275→    dir = join(homedir(), "Library/Application Support/com.deus.app");
276→  } else if (os === "win32") {
277→    dir = join(process.env.APPDATA || join(homedir(), "AppData/Roaming"), "com.deus.app");
278→  } else {
279→    dir = join(process.env.XDG_DATA_HOME || join(homedir(), ".local/share"), "deus");
280→  }
281→
282→  mkdirSync(dir, { recursive: true });
283→  return join(dir, "deus.db");
284→}
285→
286→// ── Node binary resolution ───────────────────────────────────────────
287→
288→function resolveNodeBinary(): string {
289→  if (process.env.ELECTRON_RUN_AS_NODE === "1") return process.execPath;
290→
291→  try {
292→    const electronPath = execSync(
293→      'node -e "try { console.log(require(\'electron\')) } catch { process.exit(1) }"',
294→      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
295→    ).trim();
296→
297→    if (electronPath && existsSync(electronPath)) {
298→      try {
299→        execSync(
300→          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
301→          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
302→        );
303→        return process.execPath;
304→      } catch {
305→        return electronPath;
306→      }
307→    }
308→  } catch {}
309→
310→  return process.execPath;
311→}
312→
313→// ── Process spawner ──────────────────────────────────────────────────
314→
315→async function startProcess(opts: {
316→  name: string;
317→  command: string;
318→  args: string[];
319→  env: Record<string, string>;
320→  waitFor: RegExp;
321→  children: ProcessInfo[];
322→  timeoutMs?: number;
323→}): Promise<string | null> {
324→  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
325→
326→  return new Promise((resolve) => {
327→    const extraEnv: Record<string, string> = {};
328→    if (command !== process.execPath && command.includes("Electron")) {
329→      extraEnv.ELECTRON_RUN_AS_NODE = "1";
330→    }
331→
332→    const child = spawn(command, args, {
333→      stdio: ["ignore", "pipe", "pipe"],
334→      env: { ...process.env, ...extraEnv, ...env },
335→    });
336→
337→    children.push({ process: child, name });
338→
339→    let buffer = "";
340→    let resolved = false;
341→
342→    const timeout = setTimeout(() => {
343→      if (!resolved) {
344→        resolved = true;
345→        resolve(null);
346→      }
347→    }, timeoutMs);
348→
349→    child.stdout?.on("data", (data: Buffer) => {
350→      buffer += data.toString();
351→      const match = buffer.match(waitFor);
352→      if (match && !resolved) {
353→        resolved = true;
354→        clearTimeout(timeout);
355→        resolve(match[1]);
356→      }
357→    });
358→
359→    child.stderr?.on("data", () => {
360→      // Suppress stderr in normal mode
361→    });
362→
363→    child.on("exit", (code, signal) => {
364→      if (!resolved) {
365→        resolved = true;
366→        clearTimeout(timeout);
367→        resolve(null);
368→      }
369→    });
370→  });
371→}
372→
373→// ── Web server (static + proxy) ──────────────────────────────────────
374→
375→function createWebServer(backendPort: number, frontendDir: string) {
376→  const hasFrontend = existsSync(frontendDir) && existsSync(join(frontendDir, "index.html"));
377→
378→  const server = createServer(async (req, res) => {
379→    const url = req.url || "/";
380→
381→    if (url.startsWith("/api/") || url.startsWith("/api")) {
382→      return proxyRequest(req, res, backendPort);
383→    }
384→
385→    if (url === "/__backend_port") {
386→      res.writeHead(200, {
387→        "Content-Type": "application/json",
388→        "Access-Control-Allow-Origin": "*",
389→      });
390→      res.end(JSON.stringify({ port: backendPort }));
391→      return;
392→    }
393→
394→    if (hasFrontend) {
395→      serveStaticFile(req, res, frontendDir);
396→    } else {
397→      res.writeHead(200, { "Content-Type": "text/html" });
398→      res.end(`<!DOCTYPE html><html><head><title>Deus IDE</title>
399→<style>body{font-family:system-ui;padding:3rem;background:#0a0a0a;color:#e5e5e5}
400→code{background:#1a1a1a;padding:2px 6px;border-radius:4px;font-size:14px}
401→a{color:#22d3ee}</style></head><body>
402→<h1>Deus IDE Server</h1>
403→<p>Backend API: <code>http://localhost:${backendPort}/api</code></p>
404→<p>WebSocket: <code>ws://localhost:${backendPort}/ws</code></p>
405→<p style="color:#a3a3a3">Frontend not built. Run <code>bun run build:web</code> to enable the UI.</p>
406→</body></html>`);
407→    }
408→  });
409→
410→  server.on("upgrade", (req, socket, head) => {
411→    const proxyReq = httpRequest({
412→      hostname: "localhost",
413→      port: backendPort,
414→      path: req.url,
415→      method: req.method,
416→      headers: req.headers,
417→    });
418→
419→    proxyReq.on("upgrade", (_proxyRes: any, proxySocket: any, proxyHead: any) => {
420→      socket.write(
421→        "HTTP/1.1 101 Switching Protocols\r\n" +
422→          Object.entries(_proxyRes.headers)
423→            .map(([k, v]: [string, any]) => `${k}: ${v}`)
424→            .join("\r\n") +
425→          "\r\n\r\n"
426→      );
427→      if (proxyHead.length > 0) socket.write(proxyHead);
428→      proxySocket.pipe(socket);
429→      socket.pipe(proxySocket);
430→    });
431→
432→    proxyReq.on("error", () => socket.end());
433→    proxyReq.end();
434→  });
435→
436→  return server;
437→}
438→
439→function proxyRequest(
440→  req: import("node:http").IncomingMessage,
441→  res: import("node:http").ServerResponse,
442→  backendPort: number
443→) {
444→  const proxyReq = httpRequest(
445→    {
446→      hostname: "localhost",
447→      port: backendPort,
448→      path: req.url,
449→      method: req.method,
450→      headers: { ...req.headers, host: `localhost:${backendPort}` },
451→    },
452→    (proxyRes) => {
453→      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
454→      proxyRes.pipe(res);
455→    }
456→  );
457→
458→  proxyReq.on("error", () => {
459→    res.writeHead(502, { "Content-Type": "application/json" });
460→    res.end(JSON.stringify({ error: "Backend unavailable" }));
461→  });
462→
463→  req.pipe(proxyReq);
464→}
465→
466→function serveStaticFile(
467→  req: import("node:http").IncomingMessage,
468→  res: import("node:http").ServerResponse,
469→  frontendDir: string
470→) {
471→  let pathname = (req.url || "/").split("?")[0];
472→  if (pathname === "/") pathname = "/index.html";
473→
474→  let filePath = join(frontendDir, pathname);
475→
476→  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
477→    filePath = join(frontendDir, "index.html");
478→  }
479→
480→  if (!existsSync(filePath)) {
481→    res.writeHead(404);
482→    res.end("Not found");
483→    return;
484→  }
485→
486→  const ext = extname(filePath);
487→  const contentType = MIME_TYPES[ext] || "application/octet-stream";
488→
489→  try {
490→    const content = readFileSync(filePath);
491→    res.writeHead(200, {
492→      "Content-Type": contentType,
493→      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
494→    });
495→    res.end(content);
496→  } catch {
497→    res.writeHead(500);
498→    res.end("Internal server error");
499→  }
500→}
501→
502→// ── Utilities ────────────────────────────────────────────────────────
503→
504→function getLanIp(): string | null {
505→  const nets = networkInterfaces();
506→  for (const ifaces of Object.values(nets)) {
507→    for (const iface of ifaces ?? []) {
508→      if (iface.family === "IPv4" && !iface.internal) {
509→        return iface.address;
510→      }
511→    }
512→  }
513→  return null;
514→}
515→
516→function openBrowser(url: string) {
517→  const os = platform();
518→  const cmd = os === "darwin" ? "open" : os === "win32" ? "start" : "xdg-open";
519→  spawn(cmd, [url], { detached: true, stdio: "ignore" }).unref();
520→}
521→
522→function formatUptime(ms: number): string {
523→  const s = Math.floor(ms / 1000);
524→  if (s < 60) return `${s}s`;
525→  const m = Math.floor(s / 60);
526→  if (m < 60) return `${m}m ${s % 60}s`;
527→  const h = Math.floor(m / 60);
528→  return `${h}h ${m % 60}m`;
529→}
530→

