    packages: "external",
    minify: false,
    sourcemap: false,
    logLevel: "info",
  });

  // Step 2: Create bin/ entry point
  console.log("\n2. Creating bin/deus.js...");
  mkdirSync(join(cliDir, "bin"), { recursive: true });
