   315→async function startProcess(opts: {
   316→  name: string;
   317→  command: string;
   318→  args: string[];
   319→  env: Record<string, string>;
   320→  waitFor: RegExp;
   321→  children: ProcessInfo[];
   322→  timeoutMs?: number;
   323→}): Promise<string | null> {
   324→  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
   325→
   326→  return new Promise((resolve) => {
   327→    const extraEnv: Record<string, string> = {};
   328→    if (command !== process.execPath && command.includes("Electron")) {
   329→      extraEnv.ELECTRON_RUN_AS_NODE = "1";
   330→    }
   331→
   332→    const child = spawn(command, args, {
   333→      stdio: ["ignore", "pipe", "pipe"],
   334→      env: { ...process.env, ...extraEnv, ...env },
   335→    });
   336→
   337→    children.push({ process: child, name });
   338→
   339→    let buffer = "";
   340→    let resolved = false;
   341→
   342→    const timeout = setTimeout(() => {
   343→      if (!resolved) {
   344→        resolved = true;
   345→        resolve(null);
   346→      }
   347→    }, timeoutMs);
   348→
   349→    child.stdout?.on("data", (data: Buffer) => {
   350→      buffer += data.toString();
   351→      const match = buffer.match(waitFor);
   352→      if (match && !resolved) {
   353→        resolved = true;
   354→        clearTimeout(timeout);
   355→        resolve(match[1]);
   356→      }
   357→    });
   358→
   359→    child.stderr?.on("data", () => {
   360→      // Suppress stderr in normal mode
   361→    });
   362→
   363→    child.on("exit", (code, signal) => {
   364→      if (!resolved) {
   365→        resolved = true;
   366→        clearTimeout(timeout);
   367→        resolve(null);
   368→      }
   369→    });
   370→  });
   371→}
