522→function formatUptime(ms: number): string {
523→  const s = Math.floor(ms / 1000);
524→  if (s < 60) return `${s}s`;
525→  const m = Math.floor(s / 60);
526→  if (m < 60) return `${m}m ${s % 60}s`;
527→  const h = Math.floor(m / 60);
528→  return `${h}h ${m % 60}m`;
529→}
