  1→/**
  2→ * Desktop installer — downloads and installs the Electron desktop app.
  3→ *
  4→ * Fetches the latest release from GitHub, downloads the appropriate installer
  5→ * for the current platform, and runs it.
  6→ */
  7→
  8→import { execSync, spawn } from "node:child_process";
  9→import { createWriteStream, existsSync, mkdirSync, unlinkSync } from "node:fs";
 10→import { join } from "node:path";
