 15→  spinner as createSpinner,
 16→  progressBar,
 17→  progressBarDone,
 18→  c,
 19→  blank,
 20→  success,
 21→  error,
 22→  warn,
 23→  hint,
 24→  kv,
 25→} from "./ui.js";
 26→
 27→const GITHUB_REPO = "zvadaadam/box-ide";
 28→
 29→const INSTALL_PATHS: Record<string, string[]> = {
 30→  darwin: ["/Applications/Deus.app", `${homedir()}/Applications/Deus.app`],
 31→  win32: [
