 71→/** Launch an already-installed desktop app. */
 72→export function launchDesktop(appPath: string): void {
 73→  const os = platform();
 74→  switch (os) {
 75→    case "darwin":
 76→      spawn("open", [appPath], { detached: true, stdio: "ignore" }).unref();
 77→      break;
 78→    case "win32":
 79→    case "linux":
 80→      spawn(appPath, [], { detached: true, stdio: "ignore" }).unref();
 81→      break;
