 84→
 85→export async function installDesktop(options: DesktopOptions): Promise<void> {
 86→  const { version } = options;
 87→  const os = platform();
 88→  const cpuArch = arch();
 89→
 90→  // Determine which asset to download
 91→  const assetPattern = getAssetPattern(os, cpuArch);
 92→  if (!assetPattern) {
 93→    error(`Unsupported platform: ${os} ${cpuArch}`);
 94→    blank();
 95→    hint("Supported: macOS (arm64/x64), Windows (x64), Linux (x64)");
 96→    hint(`Or run ${c.cyan("deus serve")} to use the web version instead.`);
 97→    blank();
 98→    process.exit(1);
 99→  }
100→
101→  kv("Platform", `${os} ${cpuArch}`, 10);
102→  kv("Package", c.dim(assetPattern.description), 10);
103→  blank();
104→
105→  // Fetch release info
106→  const s1 = createSpinner("Fetching latest release...");
107→  const release = await fetchRelease(version);
108→
109→  if (!release) {
110→    s1.fail("Could not find a release on GitHub");
111→    blank();
112→    hint(`Repo: ${c.dim(GITHUB_REPO)}`);
113→    hint("Make sure the repository has published releases.");
114→    hint(`Or run ${c.cyan("deus serve")} to use the web version.`);
115→    blank();
116→    process.exit(1);
117→  }
118→
119→  s1.succeed(`Found release ${c.cyan(release.tag_name)}`);
120→
121→  // Find matching asset
122→  const asset = release.assets.find((a) => assetPattern.matcher(a.name));
123→  if (!asset) {
124→    error(`No matching installer for ${os} ${cpuArch}`);
125→    blank();
126→    hint("Available downloads:");
127→    for (const a of release.assets) {
128→      hint(`  ${a.name}`);
129→    }
130→    blank();
131→    process.exit(1);
132→  }
133→
134→  // Download
135→  const downloadDir = join(tmpdir(), "deus-installer");
136→  mkdirSync(downloadDir, { recursive: true });
137→  const downloadPath = join(downloadDir, asset.name);
138→
139→  await downloadFile(asset.browser_download_url, downloadPath);
140→
141→  // Install
142→  const s3 = createSpinner("Installing...");
143→  const installed = await installForPlatform(os, downloadPath, s3);
144→
145→  // Cleanup temp file
146→  try {
147→    unlinkSync(downloadPath);
148→  } catch {}
149→
150→  if (installed) {
151→    blank();
152→    success("Deus is ready!");
153→    blank();
154→  }
155→}
156→
157→function getAssetPattern(
158→  os: string,
159→  cpuArch: string
160→): { matcher: (name: string) => boolean; description: string } | null {
161→  switch (os) {
162→    case "darwin": {
163→      const archSuffix = cpuArch === "arm64" ? "arm64" : "x64";
164→      return {
165→        matcher: (name) => name.endsWith(".dmg") && name.includes(archSuffix),
166→        description: `macOS DMG (${archSuffix})`,
167→      };
168→    }
169→    case "win32":
170→      return {
171→        matcher: (name) => name.endsWith(".exe") && !name.includes("blockmap"),
172→        description: "Windows installer (exe)",
173→      };
174→    case "linux":
175→      return {
176→        matcher: (name) => name.endsWith(".AppImage"),
177→        description: "Linux AppImage",
178→      };
179→    default:
180→      return null;
181→  }
182→}
183→
184→async function fetchRelease(version: string): Promise<GithubRelease | null> {
185→  const endpoint =
186→    version === "latest"
187→      ? `https://api.github.com/repos/${GITHUB_REPO}/releases/latest`
188→      : `https://api.github.com/repos/${GITHUB_REPO}/releases/tags/${version}`;
189→
190→  return new Promise((resolve) => {
191→    get(
192→      endpoint,
193→      { headers: { "User-Agent": "deus-cli", Accept: "application/vnd.github.v3+json" } },
194→      (res) => {
195→        if (res.statusCode === 302 || res.statusCode === 301) {
196→          const loc = res.headers.location;
197→          if (loc) {
198→            get(loc, { headers: { "User-Agent": "deus-cli" } }, (r) => {
199→              collectBody(r).then((b) => {
200→                try { resolve(JSON.parse(b)); } catch { resolve(null); }
201→              });
202→            }).on("error", () => resolve(null));
203→            return;
204→          }
205→        }
206→        if (res.statusCode !== 200) { resolve(null); return; }
207→        collectBody(res).then((b) => {
208→          try { resolve(JSON.parse(b)); } catch { resolve(null); }
209→        });
210→      }
211→    ).on("error", () => resolve(null));
212→  });
213→}
214→
215→function collectBody(res: IncomingMessage): Promise<string> {
216→  return new Promise((resolve) => {
217→    let body = "";
218→    res.on("data", (chunk: Buffer) => (body += chunk.toString()));
219→    res.on("end", () => resolve(body));
220→    res.on("error", () => resolve(""));
221→  });
222→}
223→
224→async function downloadFile(url: string, dest: string): Promise<void> {
225→  return new Promise((resolve, reject) => {
226→    const download = (downloadUrl: string) => {
227→      get(downloadUrl, { headers: { "User-Agent": "deus-cli" } }, (res) => {
228→        if (res.statusCode === 302 || res.statusCode === 301) {
229→          const loc = res.headers.location;
230→          if (loc) { download(loc); return; }
231→        }
232→
233→        if (res.statusCode !== 200) {
234→          reject(new Error(`Download failed with status ${res.statusCode}`));
235→          return;
236→        }
237→
238→        const totalSize = parseInt(res.headers["content-length"] || "0", 10);
239→        let downloaded = 0;
240→
241→        const file = createWriteStream(dest);
242→        res.on("data", (chunk: Buffer) => {
243→          downloaded += chunk.length;
244→          if (totalSize > 0) {
245→            progressBar(downloaded, totalSize, formatBytes(downloaded) + " / " + formatBytes(totalSize));
246→          }
247→        });
248→        res.pipe(file);
249→        file.on("finish", () => {
250→          file.close();
251→          progressBarDone(`Downloaded ${c.dim(formatBytes(totalSize))}`);
252→          resolve();
253→        });
254→        file.on("error", reject);
255→      }).on("error", reject);
256→    };
257→
258→    download(url);
259→  });
260→}
261→
262→function formatBytes(bytes: number): string {
263→  if (bytes < 1024) return `${bytes} B`;
264→  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
265→  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
266→}
