268→async function installForPlatform(
269→  os: string,
270→  filePath: string,
271→  s: ReturnType<typeof createSpinner>
272→): Promise<boolean> {
273→  switch (os) {
274→    case "darwin": {
275→      try {
276→        const mountOutput = execSync(`hdiutil attach "${filePath}" -nobrowse`, {
277→          encoding: "utf-8",
278→        });
279→
280→        const mountPoint = mountOutput
281→          .split("\n")
282→          .filter((line) => line.includes("/Volumes/"))
283→          .map((line) => line.trim().split("\t").pop()?.trim())
284→          .find(Boolean);
285→
286→        if (!mountPoint) {
287→          s.fail("Could not mount disk image");
288→          return false;
289→        }
290→
291→        const appName = "Deus.app";
292→        const appPath = `${mountPoint}/${appName}`;
293→        const destPath = `/Applications/${appName}`;
294→
295→        if (existsSync(appPath)) {
296→          execSync(`cp -R "${appPath}" "${destPath}"`, { stdio: "pipe" });
297→          s.succeed(`Installed to ${c.dim("/Applications/Deus.app")}`);
298→
299→          launchDesktop(destPath);
300→        } else {
301→          s.warn("DMG mounted — drag Deus to Applications to finish");
302→        }
303→
304→        execSync(`hdiutil detach "${mountPoint}" -quiet`, { stdio: "pipe" });
305→        return true;
306→      } catch {
307→        s.fail("Auto-install failed — opening DMG manually");
308→        execSync(`open "${filePath}"`);
309→        return false;
310→      }
311→    }
312→
313→    case "win32": {
314→      s.succeed("Launching installer...");
315→      spawn(filePath, [], { detached: true, stdio: "ignore" }).unref();
316→      hint("Follow the on-screen instructions to complete installation.");
317→      return true;
318→    }
319→
320→    case "linux": {
321→      execSync(`chmod +x "${filePath}"`);
322→      const installDir = join(homedir(), ".local", "bin");
323→      mkdirSync(installDir, { recursive: true });
324→      const destPath = join(installDir, "Deus.AppImage");
325→      execSync(`cp "${filePath}" "${destPath}"`);
326→      s.succeed(`Installed to ${c.dim(destPath)}`);
327→
328→      launchDesktop(destPath);
329→      return true;
330→    }
331→
332→    default:
333→      s.fail("Unsupported platform");
334→      return false;
335→  }
336→}
