  1→/**
  2→ * Terminal UI primitives for the Deus CLI.
  3→ *
  4→ * Zero dependencies — uses raw ANSI escape codes so everything
  5→ * bundles into a single file with esbuild. Inspired by Claude Code,
  6→ * Vercel CLI, and create-next-app.
  7→ */
  8→
  9→// ── ANSI Colors ──────────────────────────────────────────────────────
 10→
 11→const ESC = "\x1b[";
 12→const RESET = `${ESC}0m`;
 13→
 14→// Check NO_COLOR / FORCE_COLOR env vars (respect user preference)
 15→const noColor = !!process.env.NO_COLOR || process.argv.includes("--no-color");
 16→
 17→function wrap(code: string, text: string): string {
 18→  if (noColor) return text;
 19→  return `${ESC}${code}m${text}${RESET}`;
 20→}
 21→
 22→export const c = {
 23→  // Modifiers
 24→  bold: (t: string) => wrap("1", t),
 25→  dim: (t: string) => wrap("2", t),
 26→  italic: (t: string) => wrap("3", t),
 27→  underline: (t: string) => wrap("4", t),
 28→
 29→  // Colors
 30→  red: (t: string) => wrap("31", t),
 31→  green: (t: string) => wrap("32", t),
 32→  yellow: (t: string) => wrap("33", t),
 33→  blue: (t: string) => wrap("34", t),
 34→  magenta: (t: string) => wrap("35", t),
 35→  cyan: (t: string) => wrap("36", t),
 36→  white: (t: string) => wrap("37", t),
 37→  gray: (t: string) => wrap("90", t),
 38→
 39→  // Bright colors
 40→  brightCyan: (t: string) => wrap("96", t),
 41→  brightWhite: (t: string) => wrap("97", t),
 42→
 43→  // Backgrounds
 44→  bgCyan: (t: string) => wrap("46", t),
 45→  bgBlue: (t: string) => wrap("44", t),
 46→
 47→  // Combos
 48→  success: (t: string) => wrap("32", t), // green
 49→  error: (t: string) => wrap("31", t), // red
 50→  warn: (t: string) => wrap("33", t), // yellow
 51→  info: (t: string) => wrap("36", t), // cyan
 52→  label: (t: string) => wrap("1;36", t), // bold cyan
 53→};
 54→
 55→// True-color (24-bit) foreground
 56→function rgb(r: number, g: number, b: number, text: string): string {
 57→  if (noColor) return text;
 58→  return `\x1b[38;2;${r};${g};${b}m${text}${RESET}`;
 59→}
 60→
 61→// ── Symbols ──────────────────────────────────────────────────────────
 62→
 63→// Unicode symbols with ASCII fallbacks for limited terminals
 64→const isUnicode = process.platform !== "win32" || !!process.env.WT_SESSION;
 65→
 66→export const sym = {
 67→  tick: isUnicode ? "✓" : "√",
 68→  cross: isUnicode ? "✗" : "×",
 69→  dot: isUnicode ? "●" : "*",
 70→  dash: isUnicode ? "─" : "-",
 71→  arrow: isUnicode ? "→" : "->",
 72→  diamond: isUnicode ? "◆" : "*",
 73→  pointer: isUnicode ? "❯" : ">",
 74→  info: isUnicode ? "ℹ" : "i",
 75→  warning: isUnicode ? "⚠" : "!",
 76→  bullet: isUnicode ? "•" : "-",
 77→
 78→  // Box drawing
 79→  tl: isUnicode ? "╭" : "+",
 80→  tr: isUnicode ? "╮" : "+",
 81→  bl: isUnicode ? "╰" : "+",
 82→  br: isUnicode ? "╯" : "+",
 83→  h: isUnicode ? "─" : "-",
 84→  v: isUnicode ? "│" : "|",
 85→};
 86→
 87→// ── Logo / Banner ────────────────────────────────────────────────────
 88→
 89→// DEUS in block characters (ANSI Shadow style), per-letter for gradient coloring
 90→const LOGO_D = [
 91→  "██████╗ ",
 92→  "██╔══██╗",
 93→  "██║  ██║",
 94→  "██║  ██║",
 95→  "██████╔╝",
 96→  "╚═════╝ ",
 97→];
 98→const LOGO_E = [
 99→  "███████╗",
100→  "██╔════╝",
101→  "█████╗  ",
102→  "██╔══╝  ",
103→  "███████╗",
104→  "╚══════╝",
105→];
106→const LOGO_U = [
107→  "██╗   ██╗",
108→  "██║   ██║",
109→  "██║   ██║",
110→  "██║   ██║",
111→  "╚██████╔╝",
112→  " ╚═════╝ ",
113→];
114→const LOGO_S = [
115→  "███████╗",
116→  "██╔════╝",
117→  "███████╗",
118→  "╚════██║",
119→  "███████║",
120→  "╚══════╝",
121→];
122→
123→const LETTERS = [LOGO_D, LOGO_E, LOGO_U, LOGO_S];
124→
125→// Gradient for block chars (█): violet → indigo → blue → cyan
126→const LOGO_BLOCK: [number, number, number][] = [
127→  [167, 139, 250],
128→  [129, 140, 248],
129→  [96, 165, 250],
130→  [34, 211, 238],
131→];
132→
133→// Shadow for border chars (╔═╗║╚╝) in rows 0-4
134→const LOGO_INNER: [number, number, number][] = [
135→  [100, 83, 150],
136→  [77, 84, 149],
137→  [58, 99, 150],
138→  [20, 127, 143],
139→];
140→
141→// Extra-dim shadow for the bottom row (╚═╝)
142→const LOGO_FLOOR: [number, number, number][] = [
143→  [60, 50, 90],
144→  [46, 50, 89],
145→  [35, 59, 90],
146→  [12, 76, 86],
147→];
148→
149→const SHADOW_CHARS = new Set("╔═╗║╚╝╬╠╣╦╩╓╖╙╜╒╕╘╛┌┐└┘┬┴├┤┼─│");
150→
151→/** Color a logo row: block chars in main color, shadow chars in dim */
152→function colorLogo(
153→  text: string,
154→  block: [number, number, number],
155→  shadow: [number, number, number]
156→): string {
157→  let result = "";
158→  let buf = "";
159→  let cur: "b" | "s" | " " | null = null;
160→
161→  function flush() {
162→    if (!buf) return;
163→    if (cur === "b") result += rgb(block[0], block[1], block[2], buf);
164→    else if (cur === "s") result += rgb(shadow[0], shadow[1], shadow[2], buf);
165→    else result += buf;
166→    buf = "";
167→  }
168→
169→  for (const ch of text) {
170→    const t = ch === " " ? " " : SHADOW_CHARS.has(ch) ? "s" : "b";
171→    if (t !== cur) {
172→      flush();
173→      cur = t;
174→    }
175→    buf += ch;
176→  }
177→  flush();
178→  return result;
179→}
180→
181→// ASCII fallback for limited terminals
182→const LOGO_ASCII = [
183→  "  DDDD   EEEEE  U   U  SSSS ",
184→  "  D   D  E      U   U  S    ",
185→  "  D   D  EEE    U   U   SS  ",
186→  "  D   D  E      U   U     S ",
187→  "  DDDD   EEEEE  UUUUU  SSSS ",
188→];
189→
190→/** Render the logo rows for N letters (1-4) */
191→function renderLogoFrame(letterCount: number): string[] {
192→  const lines: string[] = [];
193→  for (let row = 0; row < 6; row++) {
194→    const shadow = row === 5 ? LOGO_FLOOR : LOGO_INNER;
195→    let line = "  ";
196→    for (let l = 0; l < letterCount; l++) {
197→      line += colorLogo(LETTERS[l][row], LOGO_BLOCK[l], shadow[l]);
198→    }
199→    lines.push(line);
200→  }
201→  return lines;
202→}
203→
204→/** Print static banner (instant) */
205→export function banner(version?: string): void {
206→  console.log("");
207→
208→  if (isUnicode && !noColor) {
209→    for (const line of renderLogoFrame(4)) {
210→      console.log(line);
211→    }
212→  } else {
213→    for (const line of LOGO_ASCII) {
214→      console.log(c.cyan(line));
215→    }
216→  }
217→
218→  console.log("");
219→  const tag = c.dim("  Agentic Engineering");
220→  const ver = version ? `  ${c.dim("v" + version)}` : "";
221→  console.log(tag + ver);
222→  console.log("");
223→}
224→
225→/**
226→ * Animated banner — letters reveal left-to-right.
227→ * Total animation: ~320ms (4 letters x 80ms).
228→ * Falls back to static banner in no-color or non-unicode terminals.
229→ */
230→export async function animatedBanner(version?: string): Promise<void> {
231→  if (!isUnicode || noColor) {
232→    banner(version);
233→    return;
234→  }
235→
236→  const out = process.stdout;
237→  const LOGO_ROWS = 6;
238→  const FRAME_DELAY = 80;
239→
240→  console.log(""); // blank line before logo
241→
242→  // Print initial empty lines (placeholder for logo)
243→  for (let i = 0; i < LOGO_ROWS; i++) {
244→    out.write("\n");
245→  }
246→
247→  // Animate: reveal one letter at a time
248→  for (let letterCount = 1; letterCount <= 4; letterCount++) {
249→    // Move cursor up to overwrite
250→    out.write(`${ESC}${LOGO_ROWS}A`);
251→
252→    const frame = renderLogoFrame(letterCount);
253→    for (const line of frame) {
254→      out.write(`${ESC}2K${line}\n`); // clear line + print
255→    }
256→
257→    if (letterCount < 4) {
258→      await sleep(FRAME_DELAY);
259→    }
260→  }
261→
262→  // Tagline + version (with fade-in delay)
263→  await sleep(100);
264→  console.log("");
265→  const tag = c.dim("  Agentic Engineering");
266→  const ver = version ? `  ${c.dim("v" + version)}` : "";
267→  console.log(tag + ver);
268→  console.log("");
269→}
270→
271→// ── Spinner ──────────────────────────────────────────────────────────
272→
273→const SPINNER_FRAMES = isUnicode
274→  ? ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"]
275→  : ["-", "\\", "|", "/"];
276→
277→const SPINNER_INTERVAL = 80;
278→
279→export interface Spinner {
280→  /** Update the spinner text while it's running */
281→  update(text: string): void;
282→  /** Stop with a success message */
283→  succeed(text?: string): void;
284→  /** Stop with a failure message */
285→  fail(text?: string): void;
286→  /** Stop with a warning message */
287→  warn(text?: string): void;
288→  /** Stop with an info message */
289→  info(text?: string): void;
290→  /** Stop and clear the line */
291→  stop(): void;
292→}
293→
294→export function spinner(text: string): Spinner {
295→  let frameIdx = 0;
296→  let currentText = text;
297→  let stopped = false;
298→
299→  const stream = process.stderr;
300→
301→  function render() {
302→    if (stopped) return;
303→    const frame = c.cyan(SPINNER_FRAMES[frameIdx % SPINNER_FRAMES.length]);
304→    stream.write(`\r${ESC}2K  ${frame} ${currentText}`);
305→    frameIdx++;
306→  }
307→
308→  const interval = setInterval(render, SPINNER_INTERVAL);
309→  render();
310→
311→  function stop(symbol: string, finalText: string) {
312→    if (stopped) return;
313→    stopped = true;
314→    clearInterval(interval);
315→    stream.write(`\r${ESC}2K  ${symbol} ${finalText}\n`);
316→  }
317→
318→  return {
319→    update(t: string) {
320→      currentText = t;
321→    },
322→    succeed(t?: string) {
323→      stop(c.green(sym.tick), t ?? currentText);
324→    },
325→    fail(t?: string) {
326→      stop(c.red(sym.cross), t ?? currentText);
327→    },
328→    warn(t?: string) {
329→      stop(c.yellow(sym.warning), t ?? currentText);
330→    },
331→    info(t?: string) {
332→      stop(c.blue(sym.info), t ?? currentText);
333→    },
334→    stop() {
335→      if (stopped) return;
336→      stopped = true;
337→      clearInterval(interval);
338→      stream.write(`\r${ESC}2K`);
339→    },
340→  };
341→}
342→
343→// ── Box ──────────────────────────────────────────────────────────────
344→
345→/** Draw a rounded box around content lines */
346→export function box(
347→  lines: string[],
348→  opts?: { padding?: number; borderColor?: (s: string) => string; width?: number }
349→): void {
350→  const { padding = 1, borderColor = c.dim, width } = opts ?? {};
351→  const pad = " ".repeat(padding);
352→
353→  // Calculate width from content (strip ANSI for measurement)
354→  const stripped = lines.map(stripAnsi);
355→  const contentWidth = width ?? Math.max(...stripped.map((l) => l.length));
356→  const innerWidth = contentWidth + padding * 2;
357→
358→  const top = borderColor(`  ${sym.tl}${sym.h.repeat(innerWidth)}${sym.tr}`);
359→  const bot = borderColor(`  ${sym.bl}${sym.h.repeat(innerWidth)}${sym.br}`);
360→  const empty = borderColor(`  ${sym.v}`) + " ".repeat(innerWidth) + borderColor(sym.v);
361→
362→  console.log(top);
363→  console.log(empty);
364→  for (let i = 0; i < lines.length; i++) {
365→    const visible = stripped[i].length;
366→    const rightPad = " ".repeat(Math.max(0, contentWidth - visible));
367→    console.log(
368→      borderColor(`  ${sym.v}`) + pad + lines[i] + rightPad + pad + borderColor(sym.v)
369→    );
370→  }
371→  console.log(empty);
372→  console.log(bot);
373→}
374→
375→// ── Section / Divider ────────────────────────────────────────────────
376→
377→/** Print a labeled divider line */
378→export function divider(label?: string, width = 44): void {
379→  if (label) {
380→    const lineLen = Math.max(0, width - label.length - 3);
381→    console.log(c.dim(`  ${sym.h.repeat(2)} ${label} ${sym.h.repeat(lineLen)}`));
382→  } else {
383→    console.log(c.dim(`  ${sym.h.repeat(width)}`));
384→  }
385→}
386→
387→// ── Key-Value Output ─────────────────────────────────────────────────
388→
389→/** Print a labeled value with consistent alignment */
390→export function kv(label: string, value: string, labelWidth = 12): void {
391→  const paddedLabel = label.padEnd(labelWidth);
392→  console.log(`  ${c.dim(paddedLabel)} ${value}`);
393→}
394→
395→// ── Messages ─────────────────────────────────────────────────────────
396→
397→export function success(text: string): void {
398→  console.log(`  ${c.green(sym.tick)} ${text}`);
399→}
400→
401→export function error(text: string): void {
402→  console.log(`  ${c.red(sym.cross)} ${text}`);
403→}
404→
405→export function warn(text: string): void {
406→  console.log(`  ${c.yellow(sym.warning)} ${text}`);
407→}
408→
409→export function info(text: string): void {
410→  console.log(`  ${c.blue(sym.info)} ${text}`);
411→}
412→
413→export function step(text: string): void {
414→  console.log(`  ${c.cyan(sym.diamond)} ${text}`);
415→}
416→
417→export function hint(text: string): void {
418→  console.log(c.dim(`  ${text}`));
419→}
420→
421→export function blank(): void {
422→  console.log("");
423→}
424→
425→// ── Gradient Text ────────────────────────────────────────────────────
426→
427→/** Apply a gradient across a text string (from → to RGB) */
428→export function gradientText(
429→  text: string,
430→  from: [number, number, number],
431→  to: [number, number, number]
432→): string {
433→  if (noColor) return text;
434→  let result = "";
435→  for (let i = 0; i < text.length; i++) {
436→    const t = text.length > 1 ? i / (text.length - 1) : 0;
437→    const r = Math.round(from[0] + (to[0] - from[0]) * t);
438→    const g = Math.round(from[1] + (to[1] - from[1]) * t);
439→    const b = Math.round(from[2] + (to[2] - from[2]) * t);
440→    result += rgb(r, g, b, text[i]);
441→  }
442→  return result;
443→}
444→
445→// ── Status Line ──────────────────────────────────────────────────────
446→
447→/**
448→ * A persistent status line at the bottom of the terminal.
449→ * Updates in place without scrolling. Shows the server is alive.
450→ */
451→export function statusLine(getText: () => string, intervalMs = 1000): { stop: () => void } {
452→  const stream = process.stderr;
453→  let stopped = false;
454→  let dotCount = 0;
455→  const dots = ["   ", ".  ", ".. ", "..."];
456→
457→  function render() {
458→    if (stopped) return;
459→    const dot = c.dim(dots[dotCount % dots.length]);
460→    stream.write(`\r${ESC}2K  ${c.dim(sym.dot)} ${getText()}${dot}`);
461→    dotCount++;
462→  }
463→
464→  const interval = setInterval(render, intervalMs);
465→  render();
466→
467→  return {
468→    stop() {
469→      if (stopped) return;
470→      stopped = true;
471→      clearInterval(interval);
472→      stream.write(`\r${ESC}2K`);
473→    },
474→  };
475→}
476→
477→// ── Progress Bar ─────────────────────────────────────────────────────
478→
479→const BAR_WIDTH = 30;
480→const BAR_FILLED = isUnicode ? "█" : "#";
481→const BAR_EMPTY = isUnicode ? "░" : ".";
482→
483→export function progressBar(current: number, total: number, label?: string): void {
484→  const pct = Math.min(1, current / total);
485→  const filled = Math.round(pct * BAR_WIDTH);
486→  const empty = BAR_WIDTH - filled;
487→  const bar = c.cyan(BAR_FILLED.repeat(filled)) + c.dim(BAR_EMPTY.repeat(empty));
488→  const pctStr = `${Math.round(pct * 100)}%`.padStart(4);
489→  const extra = label ? ` ${c.dim(label)}` : "";
490→  process.stderr.write(`\r${ESC}2K  ${bar} ${pctStr}${extra}`);
491→}
492→
493→export function progressBarDone(text: string): void {
494→  process.stderr.write(`\r${ESC}2K`);
495→  success(text);
496→}
497→
498→// ── Utilities ────────────────────────────────────────────────────────
499→
500→/** Strip ANSI escape codes for length calculation */
501→export function stripAnsi(str: string): string {
502→  // eslint-disable-next-line no-control-regex
503→  return str.replace(/\x1b\[[0-9;]*m/g, "");
504→}
505→
506→/** Sleep for ms */
507→export function sleep(ms: number): Promise<void> {
508→  return new Promise((r) => setTimeout(r, ms));
509→}
510→
511→/** Get terminal width (with safe fallback) */
512→export function termWidth(): number {
513→  return process.stdout.columns || 80;
514→}
