 1→// backend/src/routes/remote-auth.ts
 2→// Auth endpoints for remote access pairing and device management.
 3→// POST /remote-auth/pair — public, rate-limited, exchanges code for token
 4→// POST /remote-auth/generate-pair-code — localhost-only, creates a new code
 5→// GET /remote-auth/devices — localhost-only, lists paired devices
 6→// DELETE /remote-auth/devices/:id — localhost-only, revokes a device
 7→
 8→import { Hono } from "hono";
 9→import { createMiddleware } from "hono/factory";
10→import { parseBody, PairBody } from "../lib/schemas";
11→import {
12→  generatePairCode,
13→  validatePairCode,
14→  createDeviceToken,
15→  listDevices,
16→  revokeDevice,
17→  checkRateLimit,
18→  recordFailure,
19→  resetRateLimit,
20→} from "../services/remote-auth.service";
21→import { isLocalhost, getClientIp } from "../lib/network";
22→
23→const app = new Hono();
24→
25→/** Reject non-localhost requests with 403. Relay-bridged requests are trusted. */
26→const localhostOnly = createMiddleware(async (c, next) => {
27→  if (c.env?.relayBridged) {
28→    await next();
29→    return;
30→  }
31→  if (!isLocalhost(getClientIp(c))) {
32→    return c.json({ error: "This endpoint is only available from localhost" }, 403);
33→  }
34→  await next();
35→});
36→
37→// POST /remote-auth/pair — public, exchanges pairing code for device token
38→app.post("/remote-auth/pair", async (c) => {
39→  const clientIp = getClientIp(c);
40→
41→  // Rate limit check
42→  if (clientIp) {
43→    const lockout = checkRateLimit(clientIp);
44→    if (lockout > 0) {
45→      return c.json({ error: "Too many failed attempts. Try again later." }, 429);
46→    }
47→  }
48→
49→  const { code, deviceName } = parseBody(PairBody, await c.req.json());
50→
51→  if (!validatePairCode(code)) {
52→    if (clientIp) recordFailure(clientIp);
53→    return c.json({ error: "Invalid or expired connection code" }, 401);
54→  }
55→
56→  // Successful pairing — create device token
57→  if (clientIp) resetRateLimit(clientIp);
58→  const userAgent = c.req.header("user-agent") ?? null;
59→  const { token, device } = createDeviceToken(
60→    deviceName ?? "Unknown Device",
61→    clientIp ?? null,
62→    userAgent
63→  );
64→
65→  return c.json({
66→    token,
67→    device: {
68→      id: device.id,
69→      name: device.name,
70→      created_at: device.created_at,
71→    },
72→  });
73→});
74→
75→// POST /remote-auth/generate-pair-code — localhost-only
76→app.post("/remote-auth/generate-pair-code", localhostOnly, (c) => {
77→  const { code, expiresAt } = generatePairCode();
78→  const expiresInSeconds = Math.round((expiresAt - Date.now()) / 1000);
79→
80→  return c.json({ code, expires_in_seconds: expiresInSeconds });
81→});
82→
83→// GET /remote-auth/devices — localhost-only
84→app.get("/remote-auth/devices", localhostOnly, (c) => {
85→  return c.json({ devices: listDevices() });
86→});
87→
88→// DELETE /remote-auth/devices/:id — localhost-only
89→app.delete("/remote-auth/devices/:id", localhostOnly, (c) => {
90→  const id = c.req.param("id");
91→  const deleted = revokeDevice(id);
92→  if (!deleted) {
93→    return c.json({ error: "Device not found" }, 404);
94→  }
95→  return c.json({ success: true });
96→});
97→
98→export default app;
99→

  1→// backend/src/services/relay.service.ts
  2→// Manages the outbound WebSocket tunnel to the cloud relay.
  3→// Creates virtual WsConnections in ws.service for relay-forwarded clients.
  4→// Registers the query-engine protocol handler for q:* frames.
  5→
  6→import { execSync } from "child_process";
  7→import { hostname, userInfo, platform } from "os";
  8→import { WebSocket } from "ws";
  9→import { match } from "ts-pattern";
 10→import type { ServerFrame, RelayFrame } from "@shared/types/relay";
 11→import { getSetting, saveSetting } from "./settings.service";
 12→import {
 13→  getRelayCredentials,
 14→  generateRelayCredentials,
 15→  validateDeviceToken,
 16→  validatePairCode,
 17→  createDeviceToken,
 18→} from "./remote-auth.service";
 19→import { DEFAULT_RELAY_URL } from "../lib/network";
 20→import {
 21→  addConnection,
 22→  removeConnection,
 23→  getConnection,
 24→  setProtocolHandlers,
 25→  handleProtocolMessage,
 26→  type WsSendable,
 27→} from "./ws.service";
 28→import { handleFrame as handleQueryFrame, removeSubs as removeQuerySubs } from "./query-engine";
 29→
 30→// ---- Tunnel State ----
 31→
 32→let tunnelWs: WebSocket | null = null;
 33→let relayUrl: string | null = null;
 34→let serverId: string | null = null;
 35→let relayToken: string | null = null;
 36→let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 37→let reconnectAttempt = 0;
 38→
 39→// ---- Bidirectional Client Map ----
 40→// Maps relay clientId <-> ws.service connectionId. Both directions O(1).
 41→// The invariant: every key in clientToConn exists exactly once in connToClient.
 42→
 43→const clientToConn = new Map<string, string>();
 44→const connToClient = new Map<string, string>();
 45→
 46→function linkClient(clientId: string, connectionId: string): void {
 47→  clientToConn.set(clientId, connectionId);
 48→  connToClient.set(connectionId, clientId);
 49→}
 50→
 51→function unlinkClient(clientId: string): string | undefined {
 52→  const connectionId = clientToConn.get(clientId);
 53→  if (connectionId) connToClient.delete(connectionId);
 54→  clientToConn.delete(clientId);
 55→  return connectionId;
 56→}
 57→
 58→function unlinkAll(): void {
 59→  clientToConn.clear();
 60→  connToClient.clear();
 61→}
 62→
 63→const MAX_RECONNECT_DELAY = 30_000;
 64→const BASE_RECONNECT_DELAY = 1_000;
 65→
 66→// ---- Server Name Detection ----
 67→
 68→function getServerName(): string {
 69→  const custom = getSetting("server_name") as string | undefined;
 70→  if (custom) return custom;
 71→
 72→  if (platform() === "darwin") {
 73→    try {
 74→      const name = execSync("scutil --get ComputerName", {
 75→        encoding: "utf-8",
 76→        timeout: 2000,
 77→      }).trim();
 78→      if (name) return name;
 79→    } catch {
 80→      /* fall through */
 81→    }
 82→  }
 83→
 84→  const host = hostname().replace(/\.local$/, "");
 85→  if (host && host !== "localhost") return host;
 86→
 87→  try {
 88→    return `${userInfo().username}'s computer`;
 89→  } catch {
 90→    return "Deus Server";
 91→  }
 92→}
 93→
 94→// ---- Protocol Handler ----
 95→// Registered once at module load. Routes q:* frames to the query engine.
 96→
 97→setProtocolHandlers({
 98→  onQueryFrame: handleQueryFrame,
 99→});
100→
101→// ---- Public API ----
102→
103→export function ensureRelayConnected(): void {
104→  let url = getSetting("relay_url") as string | null;
105→  if (!url) {
106→    url = DEFAULT_RELAY_URL;
107→    saveSetting("relay_url", url);
108→  }
109→  let creds = getRelayCredentials();
110→  if (!creds) {
111→    creds = generateRelayCredentials();
112→  }
113→  // Already connected or connecting with same credentials — skip
114→  if (
115→    relayUrl === url &&
116→    serverId === creds.serverId &&
117→    relayToken === creds.relayToken &&
118→    tunnelWs &&
119→    (tunnelWs.readyState === WebSocket.OPEN || tunnelWs.readyState === WebSocket.CONNECTING)
120→  ) {
121→    return;
122→  }
123→
124→  connectToRelay(url, creds.serverId, creds.relayToken);
125→}
126→
127→export function connectToRelay(url: string, id: string, token: string): void {
128→  relayUrl = url;
129→  serverId = id;
130→  relayToken = token;
131→  reconnectAttempt = 0;
132→  openTunnel();
133→}
134→
135→export function disconnectFromRelay(): void {
136→  relayUrl = null;
137→  serverId = null;
138→  relayToken = null;
139→  if (reconnectTimer) {
140→    clearTimeout(reconnectTimer);
141→    reconnectTimer = null;
142→  }
143→  if (tunnelWs) {
144→    tunnelWs.close(1000, "Disconnecting");
145→    tunnelWs = null;
146→  }
147→  for (const [, connId] of clientToConn) {
148→    removeQuerySubs(connId);
149→    removeConnection(connId);
150→  }
151→  unlinkAll();
152→}
153→
154→export function getRelayStatus(): {
155→  connected: boolean;
156→  clients: number;
157→  serverId: string | null;
158→  relayUrl: string | null;
159→} {
160→  const effectiveUrl = relayUrl ?? (getSetting("relay_url") as string | undefined) ?? null;
161→  const creds = serverId ? null : getRelayCredentials();
162→  const effectiveServerId = serverId ?? creds?.serverId ?? null;
163→
164→  return {
165→    connected: tunnelWs?.readyState === WebSocket.OPEN,
166→    clients: clientToConn.size,
167→    serverId: effectiveServerId,
168→    relayUrl: effectiveUrl,
169→  };
170→}
171→
172→// ---- Tunnel Lifecycle ----
173→
174→function openTunnel(): void {
175→  if (!relayUrl || !serverId || !relayToken) return;
176→
177→  const wsUrl = `${relayUrl}/api/servers/${serverId}/tunnel?token=${encodeURIComponent(relayToken)}`;
178→  console.log(`[Relay] Connecting to ${relayUrl}/api/servers/${serverId}/tunnel...`);
179→
180→  try {
181→    tunnelWs = new WebSocket(wsUrl);
182→  } catch (err) {
183→    console.error("[Relay] Failed to create WebSocket:", err);
184→    scheduleReconnect();
185→    return;
186→  }
187→
188→  tunnelWs.on("open", () => {
189→    console.log("[Relay] Tunnel connected, registering...");
190→    reconnectAttempt = 0;
191→    sendToRelay({
192→      type: "register",
193→      serverId: serverId!,
194→      relayToken: relayToken!,
195→      serverName: getServerName(),
196→    });
197→  });
198→
199→  tunnelWs.on("message", (raw: Buffer | string) => {
200→    try {
201→      const frame = JSON.parse(typeof raw === "string" ? raw : raw.toString()) as RelayFrame;
202→      handleRelayFrame(frame);
203→    } catch {
204→      // Ignore malformed frames
205→    }
206→  });
207→
208→  tunnelWs.on("close", (code, reason) => {
209→    console.log(`[Relay] Tunnel closed: ${code} ${reason}`);
210→    tunnelWs = null;
211→    for (const [, connId] of clientToConn) {
212→      removeQuerySubs(connId);
213→      removeConnection(connId);
214→    }
215→    unlinkAll();
216→    if (relayUrl) scheduleReconnect();
217→  });
218→
219→  tunnelWs.on("error", (err) => {
220→    console.error("[Relay] Tunnel error:", err.message);
221→  });
222→}
223→
224→function handleRelayFrame(frame: RelayFrame): void {
225→  match(frame)
226→    .with({ type: "registered" }, () => {
227→      console.log("[Relay] Registered with relay successfully");
228→    })
229→    .with({ type: "client_connected" }, (f) => {
230→      const device = validateDeviceToken(f.deviceToken);
231→      if (device) {
232→        // Clean up existing connection (idempotent on tunnel reconnect)
233→        const existingConnId = clientToConn.get(f.clientId);
234→        if (existingConnId) {
235→          removeQuerySubs(existingConnId);
236→          removeConnection(existingConnId);
237→        }
238→
239→        // Virtual WsSendable routes data back through the relay tunnel
240→        const virtualWs: WsSendable = {
241→          send(data: string | ArrayBuffer) {
242→            const payload =
243→              typeof data === "string" ? data : new TextDecoder().decode(data as ArrayBuffer);
244→            sendToRelay({ type: "data", clientId: f.clientId, payload });
245→          },
246→          close() {
247→            // No-op — relay manages client disconnect
248→          },
249→        };
250→        const connId = addConnection(virtualWs, device.id, true);
251→        linkClient(f.clientId, connId);
252→        sendToRelay({ type: "auth_response", clientId: f.clientId, allowed: true });
253→        console.log(`[Relay] Client ${f.clientId} authenticated as device ${device.name}`);
254→      } else {
255→        sendToRelay({
256→          type: "auth_response",
257→          clientId: f.clientId,
258→          allowed: false,
259→          reason: "Invalid device token",
260→        });
261→        console.log(`[Relay] Client ${f.clientId} auth rejected`);
262→      }
263→    })
264→    .with({ type: "client_disconnected" }, (f) => {
265→      const connId = unlinkClient(f.clientId);
266→      if (connId) {
267→        removeQuerySubs(connId);
268→        removeConnection(connId);
269→        console.log(`[Relay] Client ${f.clientId} disconnected`);
270→      }
271→    })
272→    .with({ type: "data" }, (f) => {
273→      const connId = clientToConn.get(f.clientId);
274→      if (!connId) return;
275→      if (!getConnection(connId)) return;
276→
277→      try {
278→        const msg = JSON.parse(f.payload) as Record<string, unknown>;
279→        // Unified protocol handler — same as local WS clients
280→        handleProtocolMessage(connId, msg);
281→      } catch {
282→        // Ignore malformed inner messages
283→      }
284→    })
285→    .with({ type: "pair_request" }, (f) => {
286→      handlePairRequest(f.pairId, f.code, f.deviceName);
287→    })
288→    .with({ type: "ping" }, () => {
289→      sendToRelay({ type: "pong" });
290→    })
291→    .with({ type: "error" }, (f) => {
292→      console.error(`[Relay] Error from relay: ${f.message}`);
293→    })
294→    .exhaustive();
295→}
296→
297→// ---- Pairing ----
298→
299→function handlePairRequest(pairId: string, code: string, deviceName: string): void {
300→  if (!validatePairCode(code)) {
301→    sendToRelay({
302→      type: "pair_response",
303→      pairId,
304→      success: false,
305→      reason: "Invalid or expired pairing code",
306→    });
307→    console.log(`[Relay] Pair request ${pairId} rejected: invalid code`);
308→    return;
309→  }
310→
311→  const { token } = createDeviceToken(deviceName || "Web Portal", null, "relay-paired");
312→  sendToRelay({ type: "pair_response", pairId, success: true, deviceToken: token });
313→  console.log(`[Relay] Pair request ${pairId} succeeded, device "${deviceName}" paired`);
314→}
315→
316→// ---- Helpers ----
317→
318→function sendToRelay(frame: ServerFrame): void {
319→  if (tunnelWs?.readyState === WebSocket.OPEN) {
320→    try {
321→      tunnelWs.send(JSON.stringify(frame));
322→    } catch {
323→      // Will be handled by close/error handlers
324→    }
325→  }
326→}
327→
328→function scheduleReconnect(): void {
329→  if (reconnectTimer) return;
330→  const delay = Math.min(BASE_RECONNECT_DELAY * 2 ** reconnectAttempt, MAX_RECONNECT_DELAY);
331→  reconnectAttempt++;
332→  console.log(`[Relay] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})...`);
333→  reconnectTimer = setTimeout(() => {
334→    reconnectTimer = null;
335→    openTunnel();
336→  }, delay);
337→}
338→

 1→import fs from "fs";
 2→import path from "path";
 3→import { DB_PATH } from "../lib/database";
 4→import { PreferencesFile } from "../lib/schemas";
 5→
 6→// Co-locate with deus.db in the Electron app data directory.
 7→// Derived from DB_PATH so tests that set DATABASE_PATH get sandboxing for free.
 8→const PREFS_PATH = path.join(path.dirname(DB_PATH), "preferences.json");
 9→
10→function readPreferences(): Record<string, any> {
11→  if (!fs.existsSync(PREFS_PATH)) {
12→    return {};
13→  }
14→
15→  try {
16→    const raw = JSON.parse(fs.readFileSync(PREFS_PATH, "utf8"));
17→    const parsed = PreferencesFile.safeParse(raw);
18→    if (!parsed.success) {
19→      console.error("[settings] Invalid preferences.json, returning raw:", parsed.error.issues);
20→      return typeof raw === "object" && raw !== null && !Array.isArray(raw) ? raw : {};
21→    }
22→    return parsed.data;
23→  } catch (error) {
24→    console.error("[settings] Error reading preferences.json:", error);
25→    return {};
26→  }
27→}
28→
29→function writePreferences(settings: Record<string, any>): void {
30→  const dir = path.dirname(PREFS_PATH);
31→  if (!fs.existsSync(dir)) {
32→    fs.mkdirSync(dir, { recursive: true });
33→  }
34→
35→  // Atomic write: write to temp file, then rename
36→  const tmpPath = PREFS_PATH + ".tmp";
37→  fs.writeFileSync(tmpPath, JSON.stringify(settings, null, 2));
38→  fs.renameSync(tmpPath, PREFS_PATH);
39→}
40→
41→export function getAllSettings(): Record<string, any> {
42→  return readPreferences();
43→}
44→
45→/** Get a single setting value by key. Returns the parsed value or null. */
46→export function getSetting(key: string): any {
47→  const prefs = readPreferences();
48→  return key in prefs ? prefs[key] : null;
49→}
50→
51→export function saveSetting(key: string, value: any): void {
52→  const current = readPreferences();
53→  // Guard against readPreferences returning a non-object (e.g. if Zod fails and raw is an array/string)
54→  const obj =
55→    typeof current === "object" && current !== null && !Array.isArray(current) ? current : {};
56→  obj[key] = value;
57→  writePreferences(obj);
58→}
59→
60→export { PREFS_PATH };
61→

  1→import * as Sentry from "@sentry/node";
  2→import { serve } from "@hono/node-server";
  3→import { createApp } from "./app";
  4→import { initDatabase, closeDatabase, DB_PATH } from "./lib/database";
  5→import { closeAll as closeAllWsConnections } from "./services/ws.service";
  6→import { ensureRelayConnected, disconnectFromRelay } from "./services/relay.service";
  7→import { getSetting } from "./services/settings.service";
  8→import * as agentService from "./services/agent";
  9→import { destroyAllPtySessions } from "./services/pty.service";
 10→import { destroyAllWatchers } from "./services/fs-watcher.service";
 11→import { setApp } from "./services/route-delegate";
 12→import { invalidate } from "./services/query-engine";
 13→
 14→// Initialize Sentry before anything else.
 15→// DSN passed as env var from Electron main process (not hardcoded — open source repo).
 16→if (process.env.SENTRY_DSN) {
 17→  Sentry.init({
 18→    dsn: process.env.SENTRY_DSN,
 19→    environment: process.env.NODE_ENV === "production" ? "production" : "development",
 20→    sendDefaultPii: false,
 21→    initialScope: { tags: { process: "backend" } },
 22→  });
 23→}
 24→
 25→/**
 26→ * Deus Backend Server
 27→ *
 28→ * Handles workspace CRUD, sessions, repos, config, and stats.
 29→ * Agent runtime (Claude SDK) is managed by the agent-server.
 30→ */
 31→
 32→// Initialize database
 33→const db = initDatabase();
 34→
 35→// Backfill git_origin_url for repos added before we tracked origin URLs.
 36→// Runs once at startup (fire-and-forget) so WS subscribers get the data
 37→// on their first snapshot instead of waiting for GET /repos.
 38→async function backfillGitOriginUrls(): Promise<void> {
 39→  const { execFile } = await import("child_process");
 40→  const { promisify } = await import("util");
 41→  const execFileAsync = promisify(execFile);
 42→
 43→  try {
 44→    const nullUrlRepos = db
 45→      .prepare("SELECT id, root_path FROM repositories WHERE git_origin_url IS NULL")
 46→      .all() as { id: string; root_path: string }[];
 47→    if (nullUrlRepos.length === 0) return;
 48→
 49→    let updated = 0;
 50→    // Process in batches of 5 to cap concurrent git subprocesses
 51→    const BATCH_SIZE = 5;
 52→    for (let i = 0; i < nullUrlRepos.length; i += BATCH_SIZE) {
 53→      const batch = nullUrlRepos.slice(i, i + BATCH_SIZE);
 54→      const results = await Promise.allSettled(
 55→        batch.map(async (repo) => {
 56→          const { stdout } = await execFileAsync("git", ["remote", "get-url", "origin"], {
 57→            cwd: repo.root_path,
 58→            encoding: "utf-8",
 59→            timeout: 2000,
 60→          });
 61→          const url = stdout.trim();
 62→          if (url) {
 63→            db.prepare("UPDATE repositories SET git_origin_url = ? WHERE id = ?").run(url, repo.id);
 64→            return true;
 65→          }
 66→          return false;
 67→        })
 68→      );
 69→      updated += results.filter((r) => r.status === "fulfilled" && r.value).length;
 70→    }
 71→
 72→    // Push fresh data to WS subscribers so sidebar shows GitHub icons immediately
 73→    if (updated > 0) {
 74→      invalidate(["workspaces"]);
 75→    }
 76→  } catch {
 77→    // Backfill failed — not critical, icons will appear after next workspace creation
 78→  }
 79→}
 80→void backfillGitOriginUrls();
 81→
 82→// Create Hono app + WebSocket injector
 83→const { app, injectWebSocket } = createApp();
 84→
 85→// Register the Hono app for in-process route delegation (q:request/q:mutate → Hono routes)
 86→setApp(app);
 87→
 88→// Global variable to store actual port (used by health endpoint)
 89→let actualServerPort: number | null = null;
 90→
 91→export function getServerPort() {
 92→  return actualServerPort;
 93→}
 94→
 95→// Start server with dynamic port allocation
 96→const PORT = process.env.PORT ? parseInt(process.env.PORT) : 0;
 97→
 98→// Bind 0.0.0.0 to accept connections from all interfaces.
 99→// Remote access is gated by remoteGateMiddleware (rejects non-localhost when disabled).
100→const server = serve(
101→  {
102→    fetch: app.fetch,
103→    port: PORT,
104→    hostname: "0.0.0.0",
105→  },
106→  (info) => {
107→    actualServerPort = info.port;
108→
109→    // CRITICAL: Machine-readable port output for Electron main process and dev.sh
110→    console.log(`[BACKEND_PORT]${info.port}`);
111→
112→    console.log("\nDeus Backend Server");
113→    console.log(`API Server: http://0.0.0.0:${info.port}`);
114→    console.log(`Database: ${DB_PATH}`);
115→    console.log("Server ready!\n");
116→  }
117→);
118→
119→// Inject WebSocket support into the HTTP server
120→injectWebSocket(server);
121→
122→const remoteEnabled = getSetting("remote_access_enabled");
123→if (remoteEnabled === true) {
124→  ensureRelayConnected();
125→}
126→
127→// Connect to agent-server.
128→//
129→// Two bootstrap paths:
130→// 1. AGENT_SERVER_URL is set (dev.sh): agent-server already running, connect directly.
131→// 2. AGENT_SERVER_BUNDLE_PATH is set (Electron): spawn agent-server as child process,
132→//    parse LISTEN_URL from its stdout, then connect.
133→const agentServerUrl = process.env.AGENT_SERVER_URL;
134→const agentServerBundlePath = process.env.AGENT_SERVER_BUNDLE_PATH;
135→
136→if (agentServerUrl) {
137→  // Path 1: Direct connection (dev.sh spawned the agent-server externally)
138→  agentService.init(agentServerUrl);
139→} else if (agentServerBundlePath) {
140→  // Path 2: Spawn agent-server and connect (Electron desktop mode)
141→  void spawnAgentServerAndConnect(agentServerBundlePath);
142→}
143→
144→// Track agent-server child process for cleanup on shutdown
145→let agentServerChild: import("child_process").ChildProcess | null = null;
146→
147→function killAgentServer(): void {
148→  if (agentServerChild && !agentServerChild.killed) {
149→    agentServerChild.kill("SIGTERM");
150→    agentServerChild = null;
151→  }
152→}
153→
154→/** Spawn the agent-server bundle as a child process and connect to its WebSocket. */
155→async function spawnAgentServerAndConnect(bundlePath: string): Promise<void> {
156→  const { spawn } = await import("child_process");
157→  const fs = await import("fs");
158→
159→  if (!fs.existsSync(bundlePath)) {
160→    console.error(`[server] Agent-server bundle not found: ${bundlePath}`);
161→    return;
162→  }
163→
164→  agentServerChild = spawn(process.execPath, [bundlePath], {
165→    stdio: ["ignore", "pipe", "pipe"],
166→    env: {
167→      ...process.env,
168→      // Forward database path so agent-server can pass it to agents
169→      DATABASE_PATH: process.env.DATABASE_PATH,
170→      // Forward notebook server path
171→      NOTEBOOK_SERVER_BUNDLE_PATH: process.env.NOTEBOOK_SERVER_BUNDLE_PATH,
172→    },
173→  });
174→
175→  const agentServer = agentServerChild!;
176→  let stdoutBuffer = "";
177→
178→  agentServer.stdout?.on("data", (data: Buffer) => {
179→    stdoutBuffer += data.toString();
180→    const lines = stdoutBuffer.split("\n");
181→    stdoutBuffer = lines.pop() ?? "";
182→
183→    for (const line of lines) {
184→      const trimmed = line.trim();
185→      if (!trimmed) continue;
186→      console.log("[agent-server]", trimmed);
187→
188→      // Capture the LISTEN_URL and connect
189→      if (trimmed.startsWith("LISTEN_URL=")) {
190→        const url = trimmed.slice("LISTEN_URL=".length);
191→        console.log(`[server] Agent-server spawned and listening at ${url}`);
192→        agentService.init(url);
193→      }
194→    }
195→  });
196→
197→  agentServer.stderr?.on("data", (data: Buffer) => {
198→    for (const line of data.toString().split("\n")) {
199→      if (line.trim()) console.error("[agent-server:stderr]", line.trim());
200→    }
201→  });
202→
203→  agentServer.on("exit", (code, signal) => {
204→    console.log(`[agent-server] Exited with code=${code} signal=${signal}`);
205→    agentServerChild = null;
206→  });
207→}
208→
209→// Global error handlers
210→process.on("uncaughtException", (error, origin) => {
211→  console.error("[FATAL] Uncaught Exception:", origin, error);
212→  Sentry.captureException(error);
213→  Sentry.close(2000).finally(() => {
214→    destroyAllPtySessions();
215→    destroyAllWatchers();
216→    killAgentServer();
217→    try {
218→      closeDatabase();
219→    } catch {}
220→    process.exit(1);
221→  });
222→});
223→
224→process.on("unhandledRejection", (reason) => {
225→  // Sentry's built-in onUnhandledRejectionIntegration captures and normalizes
226→  // rejection reasons automatically. We only log here for local visibility.
227→  console.error("[FATAL] Unhandled Promise Rejection:", reason);
228→});
229→
230→// Graceful shutdown
231→function shutdown() {
232→  console.log("\nShutting down...");
233→  agentService.shutdown();
234→  destroyAllPtySessions();
235→  destroyAllWatchers();
236→  killAgentServer();
237→  disconnectFromRelay();
238→  closeAllWsConnections();
239→  closeDatabase();
240→  process.exit(0);
241→}
242→
243→process.on("SIGINT", shutdown);
244→process.on("SIGTERM", shutdown);
245→

