 1→// backend/src/middleware/remote-gate.ts
 2→// Rejects non-localhost requests when remote access is disabled.
 3→// Uses a 5s cache to avoid DB reads on every request.
 4→
 5→import { createMiddleware } from "hono/factory";
 6→import { getAllSettings } from "../services/settings.service";
 7→import { isLocalhost, getClientIp } from "../lib/network";
 8→
 9→let cachedEnabled = false;
10→let cacheExpiry = 0;
11→const CACHE_TTL_MS = 5_000;
12→
13→function isRemoteEnabled(): boolean {
14→  const now = Date.now();
15→  if (now < cacheExpiry) return cachedEnabled;
16→
17→  const settings = getAllSettings();
18→  cachedEnabled =
19→    settings.remote_access_enabled === true || settings.remote_access_enabled === "true";
20→  cacheExpiry = now + CACHE_TTL_MS;
21→  return cachedEnabled;
22→}
23→
24→/**
25→ * If remote_access_enabled is false, reject any non-localhost request with 403.
26→ * Localhost requests always pass through (desktop app is unaffected).
27→ * In-process relay bridge requests (via Hono env bindings) bypass the gate.
28→ */
29→export const remoteGateMiddleware = createMiddleware(async (c, next) => {
30→  // In-process requests from the HTTP-over-WS bridge pass relayBridged via
31→  // Hono env bindings. Structurally impossible to spoof from external clients.
32→  if (c.env?.relayBridged) {
33→    await next();
34→    return;
35→  }
36→
37→  const clientIp = getClientIp(c);
38→
39→  if (isLocalhost(clientIp)) {
40→    await next();
41→    return;
42→  }
43→
44→  if (!isRemoteEnabled()) {
45→    return c.json({ error: "Remote access is not enabled" }, 403);
46→  }
47→
48→  await next();
49→});
50→
51→/** Force-invalidate the settings cache (e.g., after toggling the setting). */
52→export function invalidateRemoteGateCache(): void {
53→  cacheExpiry = 0;
54→}
55→

 1→export const DEFAULT_RELAY_URL = "wss://relay.rundeus.com";
 2→
 3→export function isLocalhost(ip: string | undefined): boolean {
 4→  if (!ip) return false;
 5→  return ip === "127.0.0.1" || ip === "::1" || ip === "::ffff:127.0.0.1" || ip === "localhost";
 6→}
 7→
 8→export function getClientIp(c: any): string | undefined {
 9→  return (
10→    (c.env as any)?.incoming?.socket?.remoteAddress ||
11→    c.req.header("x-forwarded-for")?.split(",")[0]?.trim() ||
12→    c.req.header("x-real-ip")
13→  );
14→}
