} from "./ui.js";
import { readServerInfo } from "./config.js";

interface HealthResponse {
  status: string;
  [key: string]: unknown;
}

interface RelayStatusResponse {
  connected: boolean;
  clients: number;
  serverId: string | null;
  relayUrl: string | null;
}

interface DeviceInfo {
  id: string;
  name: string;
  created_at: string;
  last_seen_at?: string;
}

interface AgentAuthResponse {
  agents: {
    name: string;
    initialized: boolean;
    authenticated: boolean;
    account?: { email?: string };
  }[];
}

/** GET request helper */
function httpGet<T>(port: number, path: string): Promise<T | null> {
  return new Promise((resolve) => {
    const req = request(
      { hostname: "localhost", port, path, method: "GET", timeout: 3000 },
      (res) => {
        let body = "";
        res.on("data", (chunk: Buffer) => (body += chunk.toString()));
        res.on("end", () => {
          try {
            resolve(JSON.parse(body) as T);
          } catch {
            resolve(null);
          }
        });
      }
    );
    req.on("error", () => resolve(null));
    req.on("timeout", () => {
      req.destroy();
      resolve(null);
    });
    req.end();
  });
}

/** Show server status */
export async function showStatus(): Promise<void> {
  const serverInfo = readServerInfo();

  if (!serverInfo) {
    error("No running Deus server found.");
    blank();
